/* ════════════════════════════════════════════════
   PERSISTENCE  (local + cloud-ready hook)
   ════════════════════════════════════════════════ */
function saveLocal(){
  G.lastSeen=Date.now();
  try{localStorage.setItem(SAVE_KEY,JSON.stringify(G));}catch(e){console.warn('save failed',e);}
}
function loadLocal(){
  let raw=localStorage.getItem(SAVE_KEY);
  if(!raw){
    /* migrate from v1 if present */
    raw=localStorage.getItem(LEGACY_KEY);
    if(raw)try{
      const d=JSON.parse(raw);
      // run versioned migrations on the v1 save before merge
      const migrated = (typeof window.applyMigrations==='function') ? window.applyMigrations(d) : d;
      G={...G,...migrated};
      notify('Save migrated from v1','info');
    }catch(e){}
  }else{
    try{
      const d=JSON.parse(raw);
      // run versioned migrations BEFORE merge so old shapes are
      // upgraded against a clean object, not against current G defaults
      const migrated = (typeof window.applyMigrations==='function') ? window.applyMigrations(d) : d;
      G={...G,...migrated};
    }catch(e){console.warn(e);}
  }
  ensureRetentionState();
  ensureBountyState();
  migrateEquipmentSlots();
  ensureStarterCombatKit();
  G.entitlements=G.entitlements||{};
  G.ownedThemes=G.ownedThemes||['default'];
  G.ownedCosmetics=G.ownedCosmetics||[];
  G.settings=Object.assign({sfx:true,reduceFx:false,leftHand:false,scale:'auto'},G.settings||{});
  G.gems=G.gems||0;
  generateDailyTasks(false);
  G.playerMaxHp=levelFromXp(G.skills.hitpoints||0);
  G.playerHp=Math.min(G.playerHp||G.playerMaxHp,G.playerMaxHp);
  processOffline();
  // Resume the live combat tick if we still have an active monster
  // after the offline catch-up. processOfflineCombat may have nulled
  // G.activeMonster on death.
  if(G.activeMonster && !combatInterval){
    combatInterval = setInterval(combatTick, 2400);
  }
}
function processOffline(){
  const elapsed=(Date.now()-G.lastSeen)/3600000;
  if(elapsed<0.05) return;
  if(!G.activeSkill && !G.activeMonster && !G.activeArtisanRecipe) return;
  // Offline progression cap: 12h F2P, 16h with the Offline+ entitlement.
  // Resets every time the player logs in (lastSeen updates on save/load).
  const cap=G.entitlements?.offlinePlus?16:12;
  const hrs=Math.min(elapsed,cap);
  const beforeInv={...G.inventory},beforeXp={...G.skills},beforeGold=G.gold||0,beforeKills=G.stats?.kills||0;
  let combatSummary = null;

  // Combat takes priority — if a fight was in progress, simulate that.
  if(G.activeMonster){
    combatSummary = processOfflineCombat(hrs);
  } else if(G.activeSkill){
    // Offline gather runs at the same rate as active play — no dampening.
    const ticks=Math.floor((hrs*3600000)/(G.skillMs||5000));
    if(ticks>0){
      for(let i=0;i<ticks;i++)doSkillAction(true);
    }
  }

  const gainedItems=Object.keys(G.inventory).reduce((s,id)=>s+Math.max(0,(G.inventory[id]||0)-(beforeInv[id]||0)),0);
  const gainedXp=Object.keys(G.skills).reduce((s,sk)=>s+Math.max(0,(G.skills[sk]||0)-(beforeXp[sk]||0)),0);
  const gainedGold=(G.gold||0)-beforeGold;
  const gainedKills=(G.stats?.kills||0)-beforeKills;
  G.lastOfflineSummary={
    hrs:+hrs.toFixed(1), gainedItems, gainedXp,
    gainedGold, gainedKills,
    combat: combatSummary,
    at: Date.now(),
  };
  if(combatSummary){
    const note = combatSummary.died
      ? `⏰ Offline ${hrs.toFixed(1)}h — fought to the death after ${combatSummary.kills} kills, +${gainedXp} XP, +${gainedGold} gold`
      : `⏰ Offline ${hrs.toFixed(1)}h — ${combatSummary.kills} kills, +${gainedItems} items, +${gainedGold} gold`;
    notify(note, combatSummary.died ? 'kill' : 'info');
  } else {
    notify(`⏰ Offline ${hrs.toFixed(1)}h — +${gainedItems} items, +${gainedXp} XP`,'info');
  }
}

// ── Offline combat simulator ──────────────────────────────────
// Mirrors combatTick math without DOM updates. Runs N ticks at the
// engine's tick rate (2.4s default) until either the cap runs out or
// the player runs out of HP+food (in which case combat stops).
// Offline ticks run at the SAME rate as active play — no dampening.
// Returns a summary { kills, foodEaten, died, hrs }.
function processOfflineCombat(maxHrs){
  if(!G.activeMonster) return null;
  const tickMs = (typeof COMBAT_BALANCE === 'object' && COMBAT_BALANCE.tickMs) ? COMBAT_BALANCE.tickMs : 2400;
  const totalTicks = Math.max(0, Math.floor(maxHrs * 3600000 / tickMs));
  let kills = 0, foodEaten = 0, died = false, ticksRun = 0;

  for(let i = 0; i < totalTicks; i++){
    if(!G.activeMonster) break;
    const m = MONSTERS[G.activeMonster];
    if(!m){ G.activeMonster = null; break; }

    // Player attack
    const eq = getEquipmentStats();
    const playerRoll = getPlayerCombatRolls(m, eq);
    const pDmg = Math.random() < playerRoll.accuracy ? rand(1, playerRoll.maxHit) : 0;
    G.monsterHp = Math.max(0, G.monsterHp - pDmg);
    if(pDmg > 0){
      const style = (typeof window.getActiveCombatStyle === 'function') ? window.getActiveCombatStyle() : null;
      if(style && style.xp){
        Object.entries(style.xp).forEach(([sk, r]) => addXp(sk, pDmg * 4 * r));
      } else {
        addXp('attack', pDmg * 4);
        addXp('strength', pDmg * 4);
      }
      addXp('hitpoints', Math.floor(pDmg * 1.33));
    }

    // Kill: award gold + drops, respawn the same monster, continue
    if(G.monsterHp <= 0){
      const gp = rand(m.gp[0], m.gp[1]);
      G.gold = (G.gold||0) + gp;
      G.stats = G.stats || {};
      G.stats.kills = (G.stats.kills||0) + 1;
      G.combatKillsThisFoe = (G.combatKillsThisFoe||0) + 1;
      kills++;
      const dropMult = getWeaknessInfo(m).dropMult;
      (m.drops||[]).forEach(d => {
        const chance = d.ch >= 1 ? d.ch : Math.min(.95, d.ch * dropMult);
        if(Math.random() < chance){
          addItem(d.id, 1);
          if(d.ch <= 0.05){ G.stats.rareDrops = (G.stats.rareDrops||0) + 1; }
        }
      });
      // Bounty Hunter offline progress
      if(typeof handleBountyKill === 'function') handleBountyKill(G.activeMonster, m);
      // Respawn
      G.monsterHp = m.hp;
      G.monsterMaxHp = m.hp;
      ticksRun++;
      continue;
    }

    // Monster attack
    const mr = getMonsterCombatRolls(m, eq);
    const mDmg = Math.random() < mr.accuracy ? rand(1, mr.maxHit) : 0;
    G.playerHp = Math.max(0, G.playerHp - mDmg);

    // Auto-eat
    if(G.playerHp < G.playerMaxHp * (G.autoEatPct || 0.5) && G.foodSlot && (G.inventory[G.foodSlot]||0) > 0){
      const fd = ITEMS[G.foodSlot];
      if(fd && fd.heals){
        G.playerHp = Math.min(G.playerMaxHp, G.playerHp + fd.heals);
        removeItem(G.foodSlot, 1);
        foodEaten++;
        G.stats.buffsConsumed = (G.stats.buffsConsumed||0) + 1;
      }
    }

    // Death — heal up, stop combat, exit loop
    if(G.playerHp <= 0){
      G.playerHp = G.playerMaxHp;
      G.activeMonster = null;
      G.monsterHp = 0;
      if(G.bountyHunter && G.bountyHunter.active && G.bountyHunter.active.type === 'streak'){
        G.bountyHunter.active.progress = 0;
        G.bountyHunter.active.streak = 0;
      }
      died = true;
      ticksRun++;
      break;
    }
    ticksRun++;
  }
  return { kills, foodEaten, died, hrs: +maxHrs.toFixed(2), ticks: ticksRun };
}
window.processOfflineCombat = processOfflineCombat;

/* ════════════════════════════════════════════════
   NETCLIENT — backend abstraction
   - In dev: uses MockBackend (in-memory + localStorage)
   - Same call shape as a real REST/edge worker. Swap MockBackend
     with real fetch() implementation when the backend is live.
   ════════════════════════════════════════════════ */
const NetClient=(()=>{
  const ENDPOINT=null;  /* set to "https://api.hearthbound.example" later */
  const isOnline=()=>navigator.onLine && !!ENDPOINT;

  async function call(path,opts={}){
    if(!isOnline())return Mock.handle(path,opts);
    return fetch(ENDPOINT+path,{
      method:opts.method||'GET',
      headers:{'Content-Type':'application/json','X-Auth':G.account?.token||''},
      body:opts.body?JSON.stringify(opts.body):undefined,
    }).then(r=>r.json());
  }

  /* mock backend mirrors the shape of the real API */
  const Mock={
    _users:[
      {id:'u1',displayName:'DragonSlayer99',total:1842,combat:115,gold:2500000},
      {id:'u2',displayName:'IronMan2024',total:1756,combat:108,gold:1800000},
      {id:'u3',displayName:'FarmQueen',total:1690,combat:95,gold:2100000},
      {id:'u4',displayName:'CozyCrafter',total:1544,combat:78,gold:950000},
      {id:'u5',displayName:'GoblinHunter',total:1422,combat:102,gold:750000},
      {id:'u6',displayName:'TealKnight',total:1310,combat:88,gold:680000},
      {id:'u7',displayName:'PumpkinKing',total:1280,combat:74,gold:1200000},
      {id:'u8',displayName:'AshvaleAria',total:1198,combat:81,gold:520000},
    ],
    handle(path,opts){
      return new Promise(res=>setTimeout(()=>res(this._route(path,opts)),120));
    },
    _route(path,opts){
      if(path==='/auth/signin')return {ok:true,user:{id:'me',displayName:G.playerName,token:'mock-'+Math.random().toString(36).slice(2,8),provider:opts.body?.provider||'guest'}};
      if(path==='/save/sync')return {ok:true,syncedAt:Date.now()};
      if(path.startsWith('/leaderboard')){
        const mode=new URL('http://x'+path).searchParams.get('mode')||'total';
        const me={id:'me',displayName:G.playerName+' (You)',total:getTotalLevel(),combat:getCombatLevel(),gold:G.gold,you:true};
        const list=[...this._users,me].sort((a,b)=>(b[mode]||0)-(a[mode]||0)).slice(0,15)
          .map((u,i)=>({...u,rank:i+1}));
        return {ok:true,mode,list};
      }
      if(path==='/clan/list')return {ok:true,clans:[
        {id:'c1',name:'AshenForge',members:42,bonus:'+5% combat XP'},
        {id:'c2',name:'SilverHearth',members:36,bonus:'+5% gather speed'},
        {id:'c3',name:'GreenHollow',members:51,bonus:'+5% farm yield'},
      ]};
      if(path==='/iap/validate')return {ok:true,sku:opts.body.sku,receipt:'mock-'+Date.now()};
      return {ok:false,error:'unknown route '+path};
    },
  };

  return {
    online:isOnline,
    async signIn(provider){const r=await call('/auth/signin',{method:'POST',body:{provider}});if(r.ok){G.account=r.user;saveLocal();updateNetStatus();}return r;},
    signOut(){G.account=null;saveLocal();updateNetStatus();},
    async cloudSync(){const r=await call('/save/sync',{method:'POST',body:{state:G}});if(r.ok)G.cloudSyncedAt=r.syncedAt;return r;},
    async leaderboard(mode='total'){return call('/leaderboard?mode='+encodeURIComponent(mode));},
    async clans(){return call('/clan/list');},
    async iapValidate(sku,receipt){return call('/iap/validate',{method:'POST',body:{sku,receipt}});},
  };
})();

function updateNetStatus(){
  const el=document.getElementById('net-status');
  const pill=document.getElementById('status-pill');
  const online=NetClient.online()&&G.account;
  if(el){
    el.querySelector('.dot').classList.toggle('off',!online);
    el.querySelector('span:last-child').textContent=online?(G.account?.displayName||'Online'):'Offline';
  }
  if(pill){
    pill.classList.toggle('off',!online);
    pill.querySelector('span:last-child').textContent=online?'Online':'Offline play';
  }
}

/* ════════════════════════════════════════════════
   IAP — platform router
   On Steam (Electron wrapper): window.steam.purchase(sku)
   On iOS: window.webkit.messageHandlers.iap.postMessage({sku})
   On Android (Capacitor): window.cordova.plugins.inAppPurchase.buy(sku)
   On web: Stripe Checkout redirect or PaymentRequest API
   The store calls IAP.buy(sku) and lets the platform handle the rest.
   ════════════════════════════════════════════════ */
const IAP=(()=>{
  function detectPlatform(){
    if(window.steam)return 'steam';
    if(window.webkit?.messageHandlers?.iap)return 'ios';
    if(window.cordova?.plugins?.inAppPurchase)return 'android';
    return 'web';
  }
  async function buy(sku){
    const product=IAP_CATALOG.find(p=>p.sku===sku);
    if(!product){notify('Product not found','kill');return;}
    const platform=detectPlatform();
    /* show confirm */
    const confirmed=await confirmIAP(product,platform);
    if(!confirmed)return;

    /* In production each branch hands off to native billing.
       For dev / cowork preview we simulate a successful receipt. */
    let receipt;
    try{
      switch(platform){
        case 'steam':receipt=await window.steam.purchase(sku);break;
        case 'ios':window.webkit.messageHandlers.iap.postMessage({sku});return; /* iOS resolves via callback */
        case 'android':receipt=await new Promise(r=>window.cordova.plugins.inAppPurchase.buy(sku,r));break;
        default:receipt={mock:true,sku,at:Date.now()};
      }
    }catch(e){notify('Purchase cancelled','kill');return;}

    /* server-side receipt verify (mock in dev) */
    const v=await NetClient.iapValidate(sku,receipt);
    if(!v.ok){notify('Receipt validation failed','kill');return;}

    /* grant entitlements */
    grant(product);
    saveLocal();updateTopbar();renderShop();
    notify(`✅ Purchased ${product.title}`,'levelup');
  }
  function grant(p){
    if(p.gems)G.gems=(G.gems||0)+p.gems;
    if(p.gold)G.gold=(G.gold||0)+p.gold;
    if(p.ent)G.entitlements[p.ent]=true;
    if(p.unlocks)p.unlocks.forEach(id=>{if(!G.ownedThemes.includes(id))G.ownedThemes.push(id);});
    if(p.type==='pass'){
      G.seasonPass={sku:p.sku,startedAt:Date.now(),expiresAt:Date.now()+(p.duration||30)*86400000,tier:0};
    }
  }
  return {buy,detectPlatform,grant};
})();

function confirmIAP(p,platform){
  return new Promise(res=>{
    const m=document.getElementById('iap-modal');
    document.getElementById('iap-modal-body').innerHTML=`
      <div style="text-align:center;padding:8px 0 16px">
        <div style="font-size:54px">${p.icon}</div>
        <h3 style="font-family:var(--f-display);font-size:18px;color:var(--gold-2);margin:6px 0">${p.title}</h3>
        <div style="color:var(--ink-2);font-size:13px;margin-bottom:14px">${p.desc}</div>
        <div style="font-size:24px;font-weight:800;color:var(--ink)">${p.price}</div>
        <div class="status-pill" style="margin-top:10px"><span class="dot"></span><span>Platform: ${platform}</span></div>
      </div>
      <div class="row" style="gap:8px">
        <button class="btn btn-block" id="iap-cancel">Cancel</button>
        <button class="btn btn-block btn-gem" id="iap-confirm">Confirm</button>
      </div>
      <div style="font-size:10px;color:var(--ink-3);text-align:center;margin-top:10px">Receipts validated server-side. ${platform==='web'?'Web checkout uses Stripe.':platform==='ios'?'Apple In-App Purchase.':platform==='android'?'Google Play Billing.':platform==='steam'?'Steamworks Microtransactions.':'Mock billing.'}</div>`;
    m.classList.add('show');
    const cleanup=v=>{m.classList.remove('show');res(v);};
    document.getElementById('iap-cancel').onclick=()=>cleanup(false);
    document.getElementById('iap-confirm').onclick=()=>cleanup(true);
  });
}

/* ════════════════════════════════════════════════
   GAME LOGIC (combat, skills, farming, retention)
   Preserved from alpha, lightly cleaned.
   ════════════════════════════════════════════════ */
function migrateEquipmentSlots(){
  if(!G.equipment)G.equipment={};
  if(G.equipment.head&&!G.equipment.helmet)G.equipment.helmet=G.equipment.head;
  if(G.equipment.legs&&!G.equipment.pants)G.equipment.pants=G.equipment.legs;
  if(G.equipment.hands&&!G.equipment.gloves)G.equipment.gloves=G.equipment.hands;
  if(G.equipment.feet&&!G.equipment.boots)G.equipment.boots=G.equipment.feet;
  if(G.equipment.ring&&!G.equipment.ring1)G.equipment.ring1=G.equipment.ring;
  EQUIP_SLOTS.forEach(s=>{if(!(s in G.equipment))G.equipment[s]=null;});
  ['head','legs','hands','feet','ring'].forEach(s=>{delete G.equipment[s];});
}
function ensureStarterCombatKit(){
  const fresh=(G.stats?.kills||0)===0;
  if(fresh&&!G.equipment?.weapon&&!G.inventory?.bronze_sword)G.equipment.weapon='bronze_sword';
  if(fresh)G.inventory.shrimp=Math.max(G.inventory.shrimp||0,8);
}
function getPlayerCombatRolls(m,eq=getEquipmentStats()){
  /* Style-aware formulas. Routes accuracy/damage through the weapon's
     skill (sword/hammer→atk+str, magic→magic, ranged→ranged). */
  const weak=getWeaknessInfo(m,eq);
  const profile = (typeof window.getCombatStatProfile==='function')
    ? window.getCombatStatProfile()
    : {type:eq.weaponType||'sword', accuracySkill:'attack', damageSkill:'strength', accuracyBonusField:'atkB', strengthBonusField:'strB'};
  const style = (typeof window.getActiveCombatStyle==='function')
    ? window.getActiveCombatStyle()
    : {accuracyMod:1, damageMod:1, defenseMod:1, speedMod:1};
  /* Sum typed bonuses from equipment */
  let accBonus=0, strBonus=0;
  Object.values(G.equipment||{}).forEach(id=>{const it=ITEMS[id];if(!it)return; accBonus+=(it[profile.accuracyBonusField]||0); strBonus+=(it[profile.strengthBonusField]||0);});
  const accLvl = getLevel(profile.accuracySkill);
  const dmgLvl = getLevel(profile.damageSkill);
  const defScore = m?.def||0;
  /* ChatGPT spec: accuracy = 0.55 + ((lvl+bonus)-mob.def)*0.01 */
  let accuracy = 0.55 + (((accLvl+accBonus) - defScore) * 0.01);
  accuracy *= (style.accuracyMod || 1);
  accuracy *= weak.accuracyMult;
  accuracy = Math.max(0.15, Math.min(0.95, accuracy));
  /* ChatGPT spec: maxHit = floor(lvl*0.35 + strBonus*0.6 + 2) */
  let maxHit = Math.floor((dmgLvl * 0.35) + (strBonus * 0.6) + 2);
  maxHit = Math.max(1, Math.floor(maxHit - (defScore * 0.03)));
  maxHit = Math.max(1, Math.floor(maxHit * (style.damageMod || 1)));
  maxHit = Math.max(1, Math.floor(maxHit * (weak.damageMult || 1)));
  return {accuracy,maxHit,weak,profile,style};
}
function getMonsterCombatRolls(m,eq=getEquipmentStats()){
  const b=COMBAT_BALANCE;
  const playerDefense=getLevel('defense')+(eq.defB||0);
  const accuracy=clamp(b.monsterBaseAccuracy+(((m?.atk||1)-playerDefense)*b.monsterAccuracyPerPoint),b.monsterMinAccuracy,b.monsterMaxAccuracy);
  const maxHit=Math.max(1,Math.floor((m?.atk||1)*b.monsterAttackDamageScale));
  return {accuracy,maxHit};
}
function getEquipmentStats(){
  const s={atkB:0,strB:0,defB:0,critB:0,xpB:0,spdB:0,weaponType:'neutral'};
  if(!G.equipment)return s;
  Object.entries(G.equipment).forEach(([slot,id])=>{const it=ITEMS[id];if(!it)return;s.atkB+=it.atkB||0;s.strB+=it.strB||0;s.defB+=it.defB||0;s.critB+=it.critB||0;s.xpB+=it.xpB||0;s.spdB+=it.spdB||0;if(slot==='weapon'&&it.weaponType)s.weaponType=it.weaponType;});
  return s;
}
function getWeaknessInfo(m,eq=getEquipmentStats()){
  const weak=m?.weaponWeak||'neutral';
  const matched=weak!=='neutral'&&eq.weaponType===weak;
  return {weak,matched,damageMult:matched?WEAKNESS_BONUS.damage:1,accuracyMult:matched?WEAKNESS_BONUS.accuracy:1,dropMult:weak==='neutral'?NEUTRAL_DROP_BONUS:1};
}
function getPreferredSlot(def){
  if(!def)return null;
  if(def.slot==='ring'){if(!G.equipment.ring1)return 'ring1';if(!G.equipment.ring2)return 'ring2';return 'ring1';}
  if(def.slot==='head')return 'helmet';
  if(def.slot==='legs')return 'pants';
  if(def.slot==='hands')return 'gloves';
  if(def.slot==='feet')return 'boots';
  return def.slot||(def.type==='weapon'?'weapon':'body');
}
function getLevel(sk){return levelFromXp(G.skills[sk]||0);}
function getTotalLevel(){return Object.keys(G.skills).reduce((s,k)=>s+getLevel(k),0);}
function getCombatLevel(){
  const a=getLevel('attack'),st=getLevel('strength'),d=getLevel('defense'),h=getLevel('hitpoints'),p=getLevel('prayer');
  const r=getLevel('ranged'), mg=getLevel('magic');
  const base = (d+h+Math.floor(p/2))*.25;
  const melee = (a+st)*.325;
  const range = Math.floor(r*1.5)*.325;
  const mage  = Math.floor(mg*1.5)*.325;
  return Math.floor(base + Math.max(melee, range, mage));
}
function rand(min,max){return Math.floor(Math.random()*(max-min+1))+min;}

function getBonus(key){
  let t=0;
  for(const rId in G.rooms){const lv=G.rooms[rId];if(lv>0&&ROOMS[rId]){const ld=ROOMS[rId].levels[lv-1];if(ld&&ld.bk===key)t+=ld.bv;}}
  G.plotBuildings.forEach(b=>{if(b.id==='toolshed'&&key==='gatherSpeed')t+=0.05;if(b.id==='scarecrow'&&key==='farmYield')t+=0.1;if(b.id==='watchtower'&&key==='combatXP')t+=0.02;});
  /* season pass bonus */
  if(G.seasonPass && Date.now()<G.seasonPass.expiresAt && key==='allXP')t+=0.1;
  return t;
}
function addXp(sk,amt){
  const bonus=getBonus('allXP')+getEquipmentStats().xpB;
  const cb=['attack','strength','defense','hitpoints'].includes(sk)?getBonus('combatXP'):0;
  const gain=Math.floor(amt*(1+bonus+cb));
  const old=levelFromXp(G.skills[sk]||0);
  G.skills[sk]=(G.skills[sk]||0)+gain;
  const nw=levelFromXp(G.skills[sk]);
  if(nw>old){if(sk==='hitpoints')G.playerMaxHp=nw;notify(`🎉 ${SKILLS_DEF[sk]?.name||sk} ${nw}!`,'levelup');refreshAll();}
}
function addItem(id,qty=1,track=true){if(!ITEMS[id])return;G.inventory[id]=(G.inventory[id]||0)+qty;if(track)trackCollection(id,qty);}
function removeItem(id,qty=1){G.inventory[id]=(G.inventory[id]||0)-qty;if(G.inventory[id]<=0)delete G.inventory[id];}
function hasItem(id,qty=1){return(G.inventory[id]||0)>=qty;}


/* ─── Bounty Hunter ─── */
function ensureBountyState(){
  const base={marks:0,xp:0,completed:0,active:null,board:[],boardGeneratedAt:0,freeRerolls:1,rerollsToday:0,upgrades:{},warrants:{}};
  G.bountyHunter=Object.assign(base,G.bountyHunter||{});
  G.bountyHunter.upgrades=G.bountyHunter.upgrades||{};
  G.bountyHunter.warrants=G.bountyHunter.warrants||{};
  if(!Array.isArray(G.bountyHunter.board))G.bountyHunter.board=[];
  if(!G.bountyHunter.board.length)G.bountyHunter.board=generateBountyBoard();
}
function getBountyHunterLevel(){return levelFromXp(G.bountyHunter?.xp||0);}
function getUnlockedBountyTier(){
  const cl=getCombatLevel();
  if(cl>=70)return 6;if(cl>=55)return 5;if(cl>=40)return 4;if(cl>=25)return 3;if(cl>=12)return 2;return 1;
}
function getUnlockedBountyTypes(){
  const lv=getBountyHunterLevel();
  const t=['cull'];
  if(lv>=5)t.push('proof');
  if(lv>=10)t.push('weapon');
  if(lv>=15)t.push('streak');
  if(lv>=30)t.push('boss');
  if(lv>=40)t.push('chain');
  return t;
}
function getPlayerWeaponTypes(){
  const types=new Set(['sword']);
  Object.values(G.inventory||{});
  Object.keys(ITEMS).forEach(id=>{const it=ITEMS[id];if(it?.type==='weapon'&&it.weaponType&&(G.inventory[id]||Object.values(G.equipment||{}).includes(id)))types.add(it.weaponType);});
  return types;
}
function pickBountyMonster(tier,mode='normal',avoid=[]){
  let tiers=mode==='safe'?[tier,Math.max(1,tier-1)]:mode==='interesting'?[tier]:[tier,Math.max(1,tier-1),Math.max(1,tier-2)];
  const avoidSet=new Set(avoid);
  let pool=Object.entries(MONSTERS).filter(([id,m])=>tiers.includes(m.tier)&&!avoidSet.has(id)&&!m.boss);
  if(mode==='interesting'){
    pool.sort((a,b)=>((b[1].weaponWeak==='neutral')-(a[1].weaponWeak==='neutral'))||((b[1].tier||0)-(a[1].tier||0)));
    pool=pool.slice(0,Math.max(3,pool.length));
  }
  if(!pool.length)pool=Object.entries(MONSTERS).filter(([id,m])=>m.tier<=tier&&!m.boss&&!avoidSet.has(id));
  return pool[rand(0,pool.length-1)]?.[0]||'goblin';
}
function pickProofItem(monsterId){
  const m=MONSTERS[monsterId];
  if(!m?.drops?.length)return null;
  const candidates=m.drops.filter(d=>d.ch<1&&ITEMS[d.id]&&!ITEMS[d.id].type).sort((a,b)=>b.ch-a.ch);
  return candidates[0]?.id||m.drops.find(d=>d.ch<1)?.id||null;
}
function bountyCount(type,tier){
  if(type==='weapon')return Math.round(bountyCount('cull',tier)*0.85);
  const table=BOUNTY_KILL_COUNTS[type]||BOUNTY_KILL_COUNTS.cull;
  const r=table[tier]||table[1];return rand(r[0],r[1]);
}
function bountyRewards(tier,type,difficulty){
  const base=BOUNTY_BASE_REWARDS[tier]||BOUNTY_BASE_REWARDS[1],tm=BOUNTY_TYPE_MULT[type]||BOUNTY_TYPE_MULT.cull,dm=BOUNTY_DIFFICULTY_MULT[difficulty]||1;
  return {
    gold:Math.round((base.gold*tm.gold*dm)/10)*10,
    marks:Math.max(1,Math.round(base.marks*tm.marks*dm)),
    xp:Math.round(base.xp*tm.xp*dm)
  };
}
function makeBounty(type,monsterId,difficulty='normal'){
  const m=MONSTERS[monsterId],tier=m?.tier||1;
  const id=`${type}_${monsterId}_${Date.now()}_${Math.floor(Math.random()*9999)}`;
  const b={id,type,target:monsterId,difficulty,tier,progress:0,createdAt:Date.now(),rewards:bountyRewards(tier,type,difficulty)};
  if(type==='proof'){
    b.proofItem=pickProofItem(monsterId);
    if(!b.proofItem){b.type='cull';}
    b.required=bountyCount('proof',tier);
  }else if(type==='weapon'){
    b.required=bountyCount('weapon',tier);
    b.requiredWeaponType=m.weaponWeak==='neutral'?'neutral':m.weaponWeak;
  }else if(type==='streak'){
    b.required=bountyCount('streak',tier);b.streak=0; b.failOnDeath=true;
  }else{
    b.required=bountyCount('cull',tier);
  }
  return b;
}
function generateBountyBoard(){
  const tier=getUnlockedBountyTier();
  const types=getUnlockedBountyTypes();
  const used=[];
  const board=[];
  const m1=pickBountyMonster(tier,'safe',used);used.push(m1);board.push(makeBounty('cull',m1,'easy'));
  const secondType=types.includes('proof')?'proof':'cull';
  const m2=pickBountyMonster(tier,'normal',used);used.push(m2);board.push(makeBounty(secondType,m2,'normal'));
  let thirdType=types.includes('streak')?(Math.random()<0.5?'streak':(types.includes('weapon')?'weapon':'cull')):(types.includes('weapon')?'weapon':'cull');
  const ownedTypes=getPlayerWeaponTypes();
  const m3=pickBountyMonster(tier,'interesting',used);used.push(m3);
  if(thirdType==='weapon'){
    const weak=MONSTERS[m3]?.weaponWeak;
    if(weak!=='neutral'&&!ownedTypes.has(weak))thirdType='cull';
  }
  board.push(makeBounty(thirdType,m3,types.includes('streak')?'hard':'normal'));
  G.bountyHunter.boardGeneratedAt=Date.now();
  return board;
}
function bountyLabel(b){
  const m=MONSTERS[b.target];
  if(!m)return 'Unknown Bounty';
  if(b.type==='proof')return `Collect ${b.required} ${ITEMS[b.proofItem]?.n||b.proofItem}`;
  if(b.type==='weapon')return m.weaponWeak==='neutral'?`Defeat ${b.required} ${m.name}s with any weapon`:`Defeat ${b.required} ${m.name}s using ${WEAPON_TYPES[b.requiredWeaponType]}`;
  if(b.type==='streak')return `Defeat ${b.required} ${m.name}s without dying`;
  return `Defeat ${b.required} ${m.name}s`;
}
function bountyProgressText(b){
  if(!b)return '';
  if(b.type==='proof')return `${Math.min(G.inventory[b.proofItem]||0,b.required)} / ${b.required}`;
  return `${Math.min(b.progress||0,b.required)} / ${b.required}`;
}
function acceptBounty(index){
  ensureBountyState();
  if(G.bountyHunter.active){notify('Finish or abandon your active bounty first.','kill');return;}
  const b=G.bountyHunter.board[index];if(!b)return;
  G.bountyHunter.active=JSON.parse(JSON.stringify(b));
  G.bountyHunter.board.splice(index,1);
  notify(`Accepted bounty: ${MONSTERS[b.target]?.name}`,'info');
  renderCombat();saveLocal();
}
function abandonBounty(){
  if(!G.bountyHunter?.active)return;
  const b=G.bountyHunter.active;
  const lv=getBountyHunterLevel();
  if(lv>=10){const fee=Math.min(10,Math.floor((b.rewards?.marks||0)*.25));G.bountyHunter.marks=Math.max(0,(G.bountyHunter.marks||0)-fee);if(fee)notify(`Bounty abandoned (-${fee} Marks)`,'kill');}
  else notify('Bounty abandoned','info');
  G.bountyHunter.active=null;renderCombat();saveLocal();
}
function rerollBountyBoard(){
  ensureBountyState();
  if(G.bountyHunter.freeRerolls>0){G.bountyHunter.freeRerolls--;}
  else{const cost=5+(G.bountyHunter.rerollsToday||0)*5;if((G.bountyHunter.marks||0)<cost){notify(`Need ${cost} Bounty Marks to reroll.`,'kill');return;}G.bountyHunter.marks-=cost;G.bountyHunter.rerollsToday=(G.bountyHunter.rerollsToday||0)+1;}
  G.bountyHunter.board=generateBountyBoard();notify('Bounty board refreshed','info');renderCombat();saveLocal();
}
function handleBountyKill(monsterId,m){
  ensureBountyState();
  const b=G.bountyHunter.active;if(!b||b.target!==monsterId)return;
  if(b.type==='proof'){
    if((G.inventory[b.proofItem]||0)>=b.required)completeBounty();
    return;
  }
  if(b.type==='weapon'){
    const eq=getEquipmentStats();
    if(b.requiredWeaponType==='neutral'||eq.weaponType===b.requiredWeaponType)b.progress=(b.progress||0)+1;
  }else if(b.type==='streak'){
    b.progress=(b.progress||0)+1;b.streak=(b.streak||0)+1;
  }else{
    b.progress=(b.progress||0)+1;
  }
  if((b.progress||0)>=b.required)completeBounty();
}
function completeBounty(){
  const b=G.bountyHunter.active;if(!b)return;
  if(b.type==='proof'&&b.proofItem)removeItem(b.proofItem,b.required);
  const r=b.rewards||{gold:0,marks:0,xp:0};
  G.gold+=r.gold||0;G.bountyHunter.marks=(G.bountyHunter.marks||0)+(r.marks||0);G.bountyHunter.xp=(G.bountyHunter.xp||0)+(r.xp||0);G.bountyHunter.completed=(G.bountyHunter.completed||0)+1;
  const oldLevel=levelFromXp((G.bountyHunter.xp||0)-(r.xp||0)),newLevel=getBountyHunterLevel();
  const bonusRoll=Math.random()<0.10;
  if(bonusRoll){const bonus=Math.max(1,Math.round((r.marks||0)*0.5));G.bountyHunter.marks+=bonus;notify(`🎯 Bonus turn-in! +${bonus} Marks`,'levelup');}
  G.combatLog.push(`🎯 Bounty complete! +${r.marks} Marks, +${r.gold} gold`);
  notify(`Bounty complete: +${r.marks} Marks`,'levelup');
  if(newLevel>oldLevel)notify(`🎯 Bounty Hunter ${newLevel}!`,'levelup');
  G.bountyHunter.active=null;
  if(G.bountyHunter.autoBounty>=1&&G.bountyHunter.board.length){acceptBounty(0);}
  updateTopbar();renderCombat();saveLocal();
}
function renderBountyPanel(){
  ensureBountyState();
  const bh=G.bountyHunter,active=bh.active;
  let inner='';
  if(active){
    const m=MONSTERS[active.target];
    const current=active.type==='proof'?Math.min(G.inventory[active.proofItem]||0,active.required):(active.progress||0);
    const pct=Math.min(100,(current/active.required)*100);
    inner=`
      <div class="bounty-title">🎯 ${BOUNTY_TYPE_LABEL[active.type]} Bounty: ${m?.name||'Unknown'}</div>
      <div class="bounty-meta">${bountyLabel(active)} · Weakness: ${WEAPON_TYPES[m?.weaponWeak]||'—'}${m?.weaponWeak==='neutral'?' · +15% drops':''}</div>
      <div class="bounty-progress"><div class="row between tiny"><span>${bountyProgressText(active)}</span><span>${active.rewards.gold.toLocaleString()}g · ${active.rewards.marks} Marks · ${active.rewards.xp} BH XP</span></div><div class="bar gold"><i style="width:${pct}%"></i></div></div>
      <div class="row gap-sm"><button class="btn btn-sm" onclick="startCombat('${active.target}')">Fight Target</button><button class="btn btn-sm btn-danger" onclick="abandonBounty()">Abandon</button></div>`;
  }else{
    const rows=bh.board.map((b,i)=>{
      const m=MONSTERS[b.target];
      return `<div class="bounty-option"><div class="row between"><b>${m?.icon||'🎯'} ${m?.name||'Unknown'}</b><span class="bounty-chip">${BOUNTY_DIFFICULTY_LABEL[b.difficulty]} ${BOUNTY_TYPE_LABEL[b.type]}</span></div><div class="tiny muted">${bountyLabel(b)}</div><div class="tiny muted">Weak: ${WEAPON_TYPES[m?.weaponWeak]||'—'}${m?.weaponWeak==='neutral'?' · Neutral loot bonus':''}</div><div class="bounty-reward">${b.rewards.gold.toLocaleString()} gold · ${b.rewards.marks} Marks · ${b.rewards.xp} BH XP</div><button class="btn btn-sm btn-gold" onclick="acceptBounty(${i})">Accept</button></div>`;
    }).join('');
    inner=`<div class="bounty-board">${rows}</div><div class="row between" style="margin-top:8px"><span class="tiny muted">Free rerolls: ${bh.freeRerolls||0}</span><button class="btn btn-sm" onclick="rerollBountyBoard()">Reroll Board</button></div>`;
  }
  return `<div class="bounty-card"><div class="row between"><div><div class="bounty-title">Bounty Hunter</div><div class="bounty-meta">Level ${getBountyHunterLevel()} · ${bh.completed||0} completed</div></div><div class="t-stat gold" style="margin:0"><span class="ic">🎯</span><span>${(bh.marks||0).toLocaleString()}</span><span class="lab">Marks</span></div></div>${inner}</div>`;
}
/* ─── retention ─── */
function ensureRetentionState(){
  if(!G.daily)G.daily={lastReset:null,tasks:[]};
  if(!Array.isArray(G.daily.tasks))G.daily.tasks=[];
  if(!G.collection)G.collection={};
  if(!G.stats)G.stats={kills:0,gathered:0,harvested:0,rareDrops:0};
  if(!Array.isArray(G.quests)||!G.quests.length)G.quests=[
    {id:'first_blood',type:'kill_any',label:'Defeat 5 monsters',goal:5,progress:0,reward:{gold:150,item:'turnip_seed',qty:5},done:false},
    {id:'gatherer',type:'gather',label:'Gather 25 resources',goal:25,progress:0,reward:{gold:300},done:false},
    {id:'farmhand',type:'harvest',label:'Harvest 10 crops',goal:10,progress:0,reward:{gold:500,item:'wheat_seed',qty:5},done:false},
  ];
}
/* Daily task pool — pick 3 per day for variety. Each entry is a template
   factory that returns a fresh task object so we can adjust goals per
   level/character later if we want. Deterministic seed = date string.
   Only types with corresponding updateDaily() call sites are listed —
   adding a new type requires hooking the source counter too. */
const DAILY_TASK_POOL=[
  ()=>({id:'daily_kill',     type:'kill_any', label:'Kill 25 monsters',         goal:25, progress:0, reward:500, done:false}),
  ()=>({id:'daily_kill_big', type:'kill_any', label:'Kill 60 monsters',         goal:60, progress:0, reward:900, done:false}),
  ()=>({id:'daily_gather',   type:'gather',   label:'Gather 50 resources',      goal:50, progress:0, reward:400, done:false}),
  ()=>({id:'daily_gather_big',type:'gather',  label:'Gather 120 resources',     goal:120,progress:0, reward:800, done:false}),
  ()=>({id:'daily_harvest',  type:'harvest',  label:'Harvest 10 crops',         goal:10, progress:0, reward:350, done:false}),
  ()=>({id:'daily_harvest_big',type:'harvest',label:'Harvest 25 crops',         goal:25, progress:0, reward:700, done:false}),
  ()=>({id:'daily_cook',     type:'cooked',   label:'Cook 12 items',            goal:12, progress:0, reward:400, done:false}),
  ()=>({id:'daily_smith',    type:'smithed',  label:'Smith 8 items',            goal:8,  progress:0, reward:450, done:false}),
  ()=>({id:'daily_craft',    type:'crafted',  label:'Craft 8 items',            goal:8,  progress:0, reward:450, done:false}),
];
/* Simple FNV-1a hash on a string so we can derive a deterministic
   shuffle from the date — every player on the same day gets the same
   3 tasks, but each new day rotates them. */
function dailySeed(s){
  let h=0x811c9dc5;
  for(let i=0;i<s.length;i++){ h^=s.charCodeAt(i); h=(h*0x01000193)>>>0; }
  return h;
}
function generateDailyTasks(notice=true){
  ensureRetentionState();
  const today=new Date().toDateString();
  if(G.daily.lastReset===today&&G.daily.tasks.length)return;
  G.daily.lastReset=today;
  // Deterministic shuffle of pool by date seed
  let seed=dailySeed(today);
  const indexes=DAILY_TASK_POOL.map((_,i)=>i);
  for(let i=indexes.length-1;i>0;i--){
    seed=(seed*1664525+1013904223)>>>0;       // LCG step
    const j=seed%(i+1);
    [indexes[i],indexes[j]]=[indexes[j],indexes[i]];
  }
  G.daily.tasks=indexes.slice(0,3).map(i=>DAILY_TASK_POOL[i]());
  if(notice)notify('📅 New daily tasks!','info');
}
function updateDaily(type,amt=1){
  generateDailyTasks(false);
  G.daily.tasks.forEach(t=>{
    if(t.type===type&&!t.done){
      t.progress=Math.min(t.goal,(t.progress||0)+amt);
      if(t.progress>=t.goal){t.done=true;G.gold+=t.reward;notify(`✅ Daily: ${t.label} (+${t.reward}g)`,'loot');}
    }
  });
}
function updateQuest(type,amt=1,meta={}){
  ensureRetentionState();
  G.quests.forEach(q=>{
    if(q.done||q.type!==type)return;
    if(q.target&&meta.target!==q.target)return;
    q.progress=Math.min(q.goal,(q.progress||0)+amt);
    if(q.progress>=q.goal){
      q.done=true;
      const r=q.reward||{};
      if(r.gold)G.gold+=r.gold;
      if(r.item)addItem(r.item,r.qty||1,false);
      notify(`🎯 Quest: ${q.label}`,'loot');
    }
  });
}
function trackCollection(id,qty=1){if(id&&ITEMS[id])G.collection[id]=(G.collection[id]||0)+qty;}

/* ─── combat ─── */
let combatInterval=null;
function startCombat(mId){
  if(G.activeMonster===mId){stopCombat();return;}
  stopCombat();
  const m=MONSTERS[mId];
  G.activeMonster=mId;G.monsterHp=m.hp;G.monsterMaxHp=m.hp;G.combatKillsThisFoe=0;
  G.combatLog=[`⚔️ You attack the ${m.name}!`];
  combatInterval=setInterval(combatTick,2400);
  combatTick();
  renderCombat();renderMonsterList();
}
function stopCombat(){if(combatInterval){clearInterval(combatInterval);combatInterval=null;}G.activeMonster=null;renderCombat();renderMonsterList();}
function combatTick(){
  if(!G.activeMonster)return;
  const m=MONSTERS[G.activeMonster];
  const eq=getEquipmentStats();
  const playerRoll=getPlayerCombatRolls(m,eq);
  const hitCh=playerRoll.accuracy;
  const maxHit=playerRoll.maxHit;
  const pDmg=Math.random()<hitCh?rand(1,maxHit):0;
  G.monsterHp=Math.max(0,G.monsterHp-pDmg);
  const log=G.combatLog;
  log.push(pDmg>0?`⚔️ You hit ${m.name} for ${pDmg}`:`💨 You miss!`);
  if(pDmg>0){
    /* Route XP via active combat style (e.g. staff→Magic, bow→Ranged, sword 'aggressive'→Strength) */
    const _style = (typeof window.getActiveCombatStyle==='function') ? window.getActiveCombatStyle() : null;
    if(_style && _style.xp){
      Object.entries(_style.xp).forEach(([sk,r])=>addXp(sk,pDmg*4*r));
    } else {
      /* Fallback if styles haven't loaded yet */
      addXp('attack',pDmg*4);addXp('strength',pDmg*4);
    }
    addXp('hitpoints',Math.floor(pDmg*1.33));
  }
  if(G.monsterHp<=0){killMonster(m);return;}
  const monsterRoll=getMonsterCombatRolls(m,eq);
  const monHitCh=monsterRoll.accuracy;
  const mDmg=Math.random()<monHitCh?rand(1,monsterRoll.maxHit):0;
  G.playerHp=Math.max(0,G.playerHp-mDmg);
  log.push(mDmg>0?`🩸 ${m.name} hits you for ${mDmg}`:`🛡️ ${m.name} misses!`);
  /* Defense XP now comes from active combat style (e.g. sword 'defensive' or 'controlled'),
     not passively from being hit. Old passive grant removed per combat-style spec. */
  if(G.playerHp<G.playerMaxHp*G.autoEatPct&&G.foodSlot&&(G.inventory[G.foodSlot]||0)>0){
    const fd=ITEMS[G.foodSlot];
    if(fd?.heals){G.playerHp=Math.min(G.playerMaxHp,G.playerHp+fd.heals);removeItem(G.foodSlot,1);G.stats.buffsConsumed=(G.stats.buffsConsumed||0)+1;log.push(`🍖 Auto-ate ${fd.n} (+${fd.heals})`);}
  }
  if(G.playerHp<=0){
    if(G.bountyHunter?.active?.type==='streak'){G.bountyHunter.active.progress=0;G.bountyHunter.active.streak=0;log.push('🎯 Bounty streak broken. Progress reset.');}
    log.push('💀 You died! Respawning…');G.playerHp=G.playerMaxHp;stopCombat();notify('💀 You died!','kill');return;
  }
  while(log.length>30)log.shift();
  renderCombat();updateTopbar();
}
function killMonster(m){
  const gp=rand(m.gp[0],m.gp[1]);G.gold+=gp;G.stats.kills=(G.stats.kills||0)+1;
  // Per-foe kill counter — drives the activity bar's "this fight" number.
  // Reset by startCombat() when the player picks a different monster.
  G.combatKillsThisFoe=(G.combatKillsThisFoe||0)+1;
  const log=G.combatLog;if(gp>0)log.push(`💰 Looted ${gp} gold!`);
  const dropMult=getWeaknessInfo(m).dropMult;
  m.drops.forEach(d=>{
    const chance=d.ch>=1?d.ch:Math.min(.95,d.ch*dropMult);
    if(Math.random()<chance){
      addItem(d.id,1);
      const itemName=ITEMS[d.id]?.n||d.id;
      const rare=d.ch<=0.05;
      if(rare){G.stats.rareDrops=(G.stats.rareDrops||0)+1;log.push(`<span class="rare">✨ RARE: ${itemName}</span>`);notify(`✨ Rare: ${itemName}!`,'levelup');}
      else log.push(`📦 ${itemName}`);
    }
  });
  /* Kill XP routed by active style — staff kill awards Magic XP, bow kill awards Ranged, etc. */
  {
    const _style = (typeof window.getActiveCombatStyle==='function') ? window.getActiveCombatStyle() : null;
    if(_style && _style.xp){
      Object.entries(_style.xp).forEach(([sk,r])=>addXp(sk,m.xp*r));
    } else {
      addXp('attack',m.xp);
    }
  }
  updateDaily('kill_any',1);updateQuest('kill_any',1,{target:G.activeMonster});updateQuest('kill_monster',1,{target:G.activeMonster});
  handleBountyKill(G.activeMonster,m);
  notify(`☠️ Defeated ${m.name}`,'kill');
  G.monsterHp=m.hp;updateTopbar();
}

/* ─── skills ─── */
let skillInterval=null,skillProgressInterval=null;
function startSkill(type,targetId,ms){
  stopSkill();
  G.activeSkill=type;G.skillTargetId=targetId;G.skillMs=ms;G.skillProgress=0;
  const speed=getBonus('gatherSpeed');
  const actualMs=Math.max(500,Math.floor(ms*(1-speed)));
  skillInterval=setInterval(()=>doSkillAction(false),actualMs);
  skillProgressInterval=setInterval(()=>{G.skillProgress=Math.min(1,G.skillProgress+(100/actualMs));if(activeTab==='skills')renderSkillDetail(G.activeSkill);},100);
  renderSkillsList();renderSkillDetail(type);
}
function stopSkill(){
  if(skillInterval){clearInterval(skillInterval);skillInterval=null;}
  if(skillProgressInterval){clearInterval(skillProgressInterval);skillProgressInterval=null;}
  G.activeSkill=null;G.skillTargetId=null;G.skillProgress=0;
  renderSkillsList();
}
function doSkillAction(silent){
  const type=G.activeSkill,tid=G.skillTargetId;if(!type||!tid)return;
  G.skillProgress=0;
  let act=null;
  if(type==='woodcutting')act=TREES.find(t=>t.id===tid);
  if(type==='mining')act=ROCKS.find(r=>r.id===tid);
  if(type==='fishing')act=FISH_SPOTS.find(f=>f.id===tid);
  if(!act)return;
  if(getLevel(type)<act.req){stopSkill();return;}
  const qty=rand(act.qty[0],act.qty[1]);
  addItem(act.prod,qty);
  G.stats.gathered=(G.stats.gathered||0)+qty;
  updateDaily('gather',qty);updateQuest('gather',qty);
  addXp(type,act.xp);
  if(!silent){renderSkillDetail(type);updateTopbar();}
}

/* ─── farming ─── */
let farmInterval=null;
function startFarmCheck(){
  farmInterval=setInterval(()=>{
    let changed=false;
    G.farmPlots.forEach((p,i)=>{
      if(!p||p.state==='ready')return;
      const crop=CROPS[p.cropId];if(!crop)return;
      const elapsed=(Date.now()-p.plantedAt)/3600000;
      if(elapsed>=crop.hours&&p.watered){G.farmPlots[i]={...p,state:'ready'};changed=true;notify(`🌾 ${crop.name} ready!`,'loot');}
    });
    if(changed&&activeTab==='farming')renderFarm();
    if(changed&&activeTab==='profile')renderProfile();
  },5000);
}
function plantCrop(plotIdx,cropId){
  const crop=CROPS[cropId];if(!crop)return;
  const seedId=crop.seed;
  if(!hasItem(seedId)){notify('No seeds!','kill');return;}
  if(getLevel('farming')<crop.req){notify(`Farming Lv ${crop.req} required`,'kill');return;}
  removeItem(seedId,1);
  G.farmPlots[plotIdx]={cropId,plantedAt:Date.now(),watered:false,state:'growing'};
  G.stats.planted=(G.stats.planted||0)+1;
  addXp('farming',2);renderFarm();
}
function waterPlot(i){if(G.farmPlots[i]){G.farmPlots[i]={...G.farmPlots[i],watered:true};addXp('farming',1);renderFarm();}}
function harvestPlot(i){
  const p=G.farmPlots[i];if(!p||p.state!=='ready')return;
  const crop=CROPS[p.cropId];
  const yieldBonus=Math.floor(getBonus('farmYield'));
  const qty=rand(crop.yield[0],crop.yield[1])+yieldBonus;
  addItem(crop.prod,qty);
  G.stats.harvested=(G.stats.harvested||0)+qty;
  updateDaily('harvest',qty);updateQuest('harvest',qty);
  addXp('farming',crop.xp*qty);
  notify(`🌾 +${qty} ${crop.name}`,'loot');
  if(crop.regrows)G.farmPlots[i]={...p,plantedAt:Date.now(),state:'growing',watered:false};
  else G.farmPlots[i]=null;
  renderFarm();updateTopbar();
}

/* ─── notifications ─── */
function notify(text,type='info'){
  const el=document.getElementById('notifs');if(!el)return;
  const d=document.createElement('div');d.className='notif '+type;d.textContent=text;
  d.onclick=()=>d.remove();
  el.appendChild(d);
  setTimeout(()=>{try{d.remove();}catch(e){}},3500);
  while(el.children.length>5)el.children[0].remove();
}

/* ════════════════════════════════════════════════
   UI ROUTING
   ════════════════════════════════════════════════ */
let activeTab='profile';
function showTab(tab){
  if(tab==='more'){document.getElementById('more-modal').classList.add('show');return;}
  document.querySelectorAll('.panel').forEach(p=>p.classList.remove('active'));
  document.querySelectorAll('.nav-btn,.bn-btn').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));
  const panel=document.getElementById('panel-'+tab);if(!panel)return;
  panel.classList.add('active');
  activeTab=tab;
  document.getElementById('more-modal').classList.remove('show');
  if(tab==='profile')renderProfile();
  if(tab==='combat'){renderCombat();renderLoadout();renderMonsterList();}
  if(tab==='skills')renderSkillsList();
  if(tab==='inventory')renderInventory();
  if(tab==='farming')renderFarm();
  if(tab==='house')renderHouse();
  if(tab==='social')renderSocial();
  if(tab==='shop')renderShop();
}
function refreshAll(){
  updateTopbar();
  if(activeTab==='profile')renderProfile();
  if(activeTab==='combat'){renderCombat();renderLoadout();renderMonsterList();}
  if(activeTab==='skills'){renderSkillsList();if(G.activeSkill)renderSkillDetail(G.activeSkill);}
  if(activeTab==='inventory')renderInventory();
  if(activeTab==='farming')renderFarm();
  if(activeTab==='shop')renderShop();
}

function updateTopbar(){
  document.getElementById('top-gold').textContent=G.gold.toLocaleString();
  document.getElementById('top-gems').textContent=(G.gems||0).toLocaleString();
  document.getElementById('top-total').textContent=getTotalLevel();
  document.getElementById('top-combat').textContent=getCombatLevel();
  document.getElementById('player-name').textContent=G.playerName;
  const ct=document.getElementById('clan-tag');
  if(G.clanName){ct.classList.remove('hide');ct.textContent='['+G.clanName+']';}else ct.classList.add('hide');
}

/* ────────────────────────────────────────────────
   RENDER — Profile dashboard
   ──────────────────────────────────────────────── */
function renderProfile(){
  generateDailyTasks(false);
  /* user card */
  const cl=getCombatLevel(),tl=getTotalLevel();
  // b119: defensive null guards — these elements only exist when the
  // Profile panel template has rendered. onAuthStateChange can fire
  // before the DOM is built, which crashed renderProfile in a loop on
  // older builds (v=111) and broke the auth UI.
  const subEl = document.getElementById('dash-user-sub');
  const bodyEl = document.getElementById('dash-user-body');
  if (!subEl || !bodyEl) return; // Profile panel not in DOM yet — bail
  subEl.textContent = `Lv ${cl} · Total ${tl}`;
  bodyEl.innerHTML=`
    ${(()=>{
      // Auth-state resolution for the Profile dashboard:
      // 1) live Supabase session takes precedence (the actual cloud login)
      // 2) legacy guest G.account record
      // 3) offline / no auth at all
      const liveSess = (window.HearthriseAuth && window.HearthriseAuth.getSession && window.HearthriseAuth.getSession()) || null;
      const liveUser = liveSess && liveSess.user;
      const acctName = liveUser
        ? (liveUser.user_metadata?.display_name || (liveUser.email||'').split('@')[0] || 'Adventurer')
        : (G.account ? G.account.displayName : null);
      const isOnline = !!(liveUser || G.account);
      const subtitle = liveUser ? 'Online · cloud save active' : (G.account ? 'Online · '+G.account.displayName : 'Offline play · sign in to sync');
      return `<div class="activity-card">
      <div class="ac-icon">🧙</div>
      <div style="flex:1;min-width:0">
        <b>${escapeHtml(acctName || G.playerName)}</b>
        <span>${subtitle}</span>
      </div>
      ${isOnline?'':'<button class="btn btn-sm btn-primary" onclick="openSettings()">Sign in</button>'}
    </div>`;
    })()}
    <div class="kpi-row">
      <div class="kpi"><b>${cl}</b><span>Combat</span></div>
      <div class="kpi"><b>${tl}</b><span>Total Level</span></div>
      <div class="kpi"><b>${G.gold.toLocaleString()}</b><span>Gold</span></div>
      <div class="kpi"><b>${G.stats.kills||0}</b><span>Kills</span></div>
    </div>`;

  /* current activity */
  const activeName=G.activeMonster?MONSTERS[G.activeMonster]?.name:G.activeSkill?SKILLS_DEF[G.activeSkill]?.name:'Idle';
  document.getElementById('dash-active-sub').textContent=activeName;
  let activityHtml='';
  if(G.activeMonster){
    const m=MONSTERS[G.activeMonster];
    const php=Math.max(0,(G.playerHp/G.playerMaxHp)*100),mhp=Math.max(0,(G.monsterHp/G.monsterMaxHp)*100);
    activityHtml=`
      <div class="arena" style="margin-bottom:8px">
        <div class="fighter"><div class="portrait">🧍</div><div class="fname">You</div><div class="fhp">${G.playerHp}/${G.playerMaxHp}</div><div class="bar hp"><i style="width:${php}%"></i></div></div>
        <div class="vs">⚔️</div>
        <div class="fighter enemy"><div class="portrait">${m.icon}</div><div class="fname">${m.name}</div><div class="fhp">${G.monsterHp}/${G.monsterMaxHp}</div><div class="bar hp"><i style="width:${mhp}%"></i></div></div>
      </div>
      <button class="btn btn-block btn-danger" onclick="stopCombat()">Stop Combat</button>`;
  } else if(G.activeSkill){
    const sd=SKILLS_DEF[G.activeSkill];const lv=getLevel(G.activeSkill);const pct=xpPct(G.skills[G.activeSkill]||0)*100;
    activityHtml=`
      <div class="activity-card">
        <div class="ac-icon">${sd.icon}</div>
        <div style="flex:1"><b>Training ${sd.name}</b><span>Level ${lv}</span></div>
      </div>
      <div class="bar xp" style="margin:4px 0 8px"><i style="width:${pct.toFixed(1)}%"></i></div>
      <button class="btn btn-block btn-danger" onclick="stopSkill()">Stop</button>`;
  } else {
    activityHtml=`
      <div class="empty"><span class="em-icon">💤</span>No active task. Pick something to do.</div>
      <div class="kpi-row" style="margin-top:6px">
        <button class="btn tap" onclick="showTab('combat')">⚔️ Combat</button>
        <button class="btn tap" onclick="showTab('skills')">📊 Skills</button>
        <button class="btn tap" onclick="showTab('farming')">🌾 Farm</button>
        <button class="btn tap" onclick="showTab('shop')">💎 Store</button>
      </div>`;
  }
  if(G.lastOfflineSummary)activityHtml+=`<div class="muted tiny" style="margin-top:8px">⏰ Offline: ${G.lastOfflineSummary.hrs}h, +${G.lastOfflineSummary.gainedItems} items, +${G.lastOfflineSummary.gainedXp} XP</div>`;
  document.getElementById('dash-active-body').innerHTML=activityHtml;

  /* objectives */
  const all=[...(G.daily?.tasks||[]),...(G.quests||[])];
  const open=all.filter(q=>!q.done),done=all.filter(q=>q.done);
  document.getElementById('dash-obj-sub').textContent=`${done.length}/${all.length} done`;
  const passInfo=G.seasonPass?(()=>{
    const days=Math.max(0,Math.ceil((G.seasonPass.expiresAt-Date.now())/86400000));
    return `<div class="iap-card purple" style="margin-bottom:10px"><div class="row between"><div><h3>📜 Season ${G.seasonPass.tier?'Tier '+G.seasonPass.tier:'Pass'}</h3><div class="desc">${days}d remaining · +10% all XP</div></div><div class="iap-icon">📜</div></div></div>`;
  })():`<div style="background:var(--purple-bg);border:1px solid rgba(139,92,246,.3);border-radius:var(--r-sm);padding:10px;margin-bottom:10px"><div class="row between"><div><b>Season Pass</b><div class="muted tiny">30 daily tiers + cosmetics</div></div><button class="btn btn-sm btn-gem" onclick="IAP.buy('pass_season')">$9.99</button></div></div>`;
  document.getElementById('dash-objectives-body').innerHTML=passInfo+`
    <div class="objective-list">
      ${open.slice(0,6).map(q=>`<div class="obj"><span>⬜ ${q.label}</span><b>${Math.min(q.progress||0,q.goal)}/${q.goal}</b></div>`).join('')}
      ${done.slice(0,3).map(q=>`<div class="obj done"><span>✅ ${q.label}</span><b>Done</b></div>`).join('')}
    </div>`;

  /* skills board */
  document.getElementById('dash-skills-sub').textContent=`Total: ${tl}`;
  document.getElementById('dash-skills-body').innerHTML=`
    <div class="skill-board">
      ${Object.entries(SKILLS_DEF).map(([id,s])=>{
        const xp=G.skills[id]||0,lv=getLevel(id),pct=Math.floor(xpPct(xp)*100);
        return `<button class="skill-tile ${G.activeSkill===id?'active':''}" onclick="showTab('skills');openSkillDetail('${id}')"><span class="sicon">${s.icon}</span><span class="slv">Lv ${lv}</span><div class="bar xp"><i style="width:${pct}%"></i></div><span class="snm">${s.name}</span></button>`;
      }).join('')}
    </div>`;

  /* homestead */
  const plots=Array.from({length:8}).map((_,i)=>{
    const p=G.farmPlots[i];
    if(!p)return `<div class="farm-tile empty"><span>＋</span><small>Empty</small></div>`;
    const crop=CROPS[p.cropId];const elapsed=(Date.now()-p.plantedAt)/3600000;
    const pct=Math.min(100,Math.floor((elapsed/(crop.hours||1))*100));
    const lab=p.state==='ready'?'Ready':(p.watered?`${pct}%`:'Water');
    return `<div class="farm-tile ${p.state==='ready'?'ready':''}"><span>${crop.icon}</span><small>${lab}</small></div>`;
  }).join('');
  const roomLevels=Object.values(G.rooms).reduce((a,b)=>a+(b||0),0);
  document.getElementById('dash-homestead-body').innerHTML=`
    <div class="hmstead-grid">
      <div class="hmstead-col">
        <div class="row between" style="margin-bottom:8px"><b>🌾 Plots</b><button class="btn btn-sm" onclick="showTab('farming')">Open</button></div>
        <div class="farm-mini" style="grid-template-columns:repeat(8,1fr)">${plots}</div>
      </div>
      <div class="hmstead-col">
        <div class="row between" style="margin-bottom:8px"><b>🏠 House</b><button class="btn btn-sm" onclick="showTab('house')">Open</button></div>
        <div class="muted tiny" style="line-height:1.6">Theme: <b>${HOUSE_THEMES.find(t=>t.id===G.houseTheme)?.name||'Cozy Cottage'}</b><br>${roomLevels} room levels · ${G.plotBuildings.length} plot builds</div>
      </div>
    </div>`;
}

/* ────────────────────────────────────────────────
   RENDER — Combat
   ──────────────────────────────────────────────── */
let selectedTier=1;
function selectTier(t){selectedTier=t;document.querySelectorAll('#tier-chips .chip').forEach(c=>c.classList.toggle('active',+c.dataset.tier===t));document.getElementById('combat-picker-sub').textContent='Tier '+t;renderMonsterList();}
function renderMonsterList(){
  const el=document.getElementById('monster-list');if(!el)return;
  const list=Object.entries(MONSTERS).filter(([,m])=>m.tier===selectedTier);
  el.innerHTML=list.map(([id,m])=>{
    const cl=getCombatLevel();const req=(m.tier-1)*15;const unlocked=cl>=req;const fighting=G.activeMonster===id;
    return `<button class="monster-row ${fighting?'fighting':''}" ${unlocked?'':'disabled'} onclick="${unlocked?`startCombat('${id}')`:''}">
      <span class="mi">${m.icon}</span>
      <div style="flex:1;min-width:0">
        <span class="mn">${m.name}${m.boss?' <span class="tag">BOSS</span>':''}</span>
        <span class="ms">${m.family||'Monster'} · Weak: ${WEAPON_TYPES[m.weaponWeak]||'—'} · HP ${m.hp} · ATK ${m.atk}</span>
      </div>
      ${!unlocked?`<span class="muted tiny">🔒 CL ${req}</span>`:fighting?'<span style="color:var(--red);font-weight:700;font-size:11px">STOP</span>':''}
    </button>`;
  }).join('');
}
function renderCombat(){
  const el=document.getElementById('combat-area');if(!el)return;
  const stop=document.getElementById('combat-stop');
  if(!G.activeMonster){
    el.innerHTML=`${renderBountyPanel()}<div class="arena"><div class="fighter"><div class="portrait">🧍</div><div class="fname">You</div><div class="fhp">${G.playerHp}/${G.playerMaxHp}</div></div><div class="vs">⚔️</div><div class="fighter enemy"><div class="portrait">❓</div><div class="fname">Choose a foe</div><div class="fhp">—</div></div></div><div class="empty"><span class="em-icon">⚔️</span>Pick a monster from the list to begin.</div>`;
    stop.style.display='none';return;
  }
  const m=MONSTERS[G.activeMonster];
  const php=(G.playerHp/G.playerMaxHp)*100,mhp=(G.monsterHp/G.monsterMaxHp)*100;
  const eq=getEquipmentStats();
  const weak=getWeaknessInfo(m,eq);
  const playerRoll=getPlayerCombatRolls(m,eq);
  const monsterRoll=getMonsterCombatRolls(m,eq);
  const hitCh=playerRoll.accuracy;
  const maxHit=playerRoll.maxHit;
  const foods=Object.entries(G.inventory).filter(([id])=>ITEMS[id]?.heals);
  el.innerHTML=`
    ${renderBountyPanel()}
    <div class="arena">
      <div class="fighter"><div class="portrait">🧍</div><div class="fname">You</div><div class="fhp">${G.playerHp}/${G.playerMaxHp}</div><div class="bar hp"><i style="width:${php}%"></i></div></div>
      <div class="vs">⚔️</div>
      <div class="fighter enemy"><div class="portrait">${m.icon}</div><div class="fname">${m.name}${m.boss?' <span class="tag">BOSS</span>':''}</div><div class="fhp">${G.monsterHp}/${G.monsterMaxHp}</div><div class="bar hp"><i style="width:${mhp}%"></i></div></div>
    </div>
    <div class="calc">
      <div><b>${Math.round(hitCh*100)}%</b><span>Your hit chance</span></div>
      <div><b>${maxHit}</b><span>Your max hit</span></div>
      <div><b>${Math.round(monsterRoll.accuracy*100)}%</b><span>Enemy hit chance</span></div>
      <div><b>${monsterRoll.maxHit}</b><span>Enemy max hit</span></div>
      <div><b>${WEAPON_TYPES[eq.weaponType]}</b><span>Your type</span></div>
      <div><b>${WEAPON_TYPES[m.weaponWeak]}</b><span>${getWeaknessInfo(m,eq).matched?'+20% dmg / +15% acc':(m.weaponWeak==='neutral'?'+15% drops':'Weak to')}</span></div>
    </div>
    <div class="combat-log" id="clog">${[...G.combatLog].reverse().map(l=>`<div>${l}</div>`).join('')}</div>
    <div class="row between" style="margin-top:9px;gap:8px;flex-wrap:wrap">
      <label class="row tiny muted" style="gap:6px">Auto-eat:
        <select onchange="G.foodSlot=this.value||null;notify(this.value?'Food set':'Auto-eat off','info')" style="background:rgba(255,255,255,.04);border:1px solid var(--line-soft);border-radius:6px;padding:5px 8px;color:var(--ink)">
          <option value="">None</option>
          ${foods.map(([id])=>`<option value="${id}" ${G.foodSlot===id?'selected':''}>${ITEMS[id].icon} ${ITEMS[id].n} (x${G.inventory[id]})</option>`).join('')}
        </select>
      </label>
      <div class="row tiny muted">Drops: ${m.drops.map(d=>{const c=d.ch>=1?d.ch:Math.min(.95,d.ch*getWeaknessInfo(m,eq).dropMult);return `${ITEMS[d.id]?.icon||'?'} ${Math.round(c*100)}%`;}).join(' · ')}</div>
    </div>`;
  stop.style.display='inline-flex';
}
function renderLoadout(){
  const el=document.getElementById('loadout-panel');if(!el)return;
  migrateEquipmentSlots();
  const s=getEquipmentStats();
  el.innerHTML=`
    <div class="loadout-grid">
      ${EQUIP_SLOTS.slice(0,12).map(slot=>{
        const id=G.equipment[slot];const def=id?ITEMS[id]:null;const meta=EQUIP_SLOT_META[slot];
        return `<button class="loadout-slot ${def?'':'empty'}" onclick="${def?`unequip('${slot}')`:''}" title="${def?def.n+' (click to unequip)':meta.label}">${def?def.icon:meta.icon}<small>${def?def.n.split(' ')[0]:meta.label}</small></button>`;
      }).join('')}
    </div>
    <div class="stat-grid">
      <div class="stat"><b>+${s.atkB}</b><span>Atk</span></div>
      <div class="stat"><b>+${s.strB}</b><span>Str</span></div>
      <div class="stat"><b>+${s.defB}</b><span>Def</span></div>
      <div class="stat"><b>+${Math.round(s.critB*100)}%</b><span>Crit</span></div>
      <div class="stat"><b>+${Math.round(s.xpB*100)}%</b><span>XP</span></div>
      <div class="stat"><b>+${Math.round(s.spdB*100)}%</b><span>Spd</span></div>
      <div class="stat"><b>${WEAPON_TYPES[s.weaponType]}</b><span>Type</span></div>
    </div>
    <div class="muted tiny" style="margin-top:8px">Tap a slot to unequip. Manage gear from the Inventory tab.</div>`;
}
function unequip(slot){const id=G.equipment[slot];if(!id)return;G.equipment[slot]=null;G.inventory[id]=(G.inventory[id]||0)+1;notify(`Unequipped ${ITEMS[id].n}`,'info');renderLoadout();renderInventory();}
function equipItem(id){
  migrateEquipmentSlots();
  const def=ITEMS[id];if(!def||(!def.type&&!def.slot))return;
  const slot=getPreferredSlot(def);if(!slot||!EQUIP_SLOTS.includes(slot))return;
  const old=G.equipment[slot];if(old)G.inventory[old]=(G.inventory[old]||0)+1;
  G.equipment[slot]=id;removeItem(id,1);
  notify(`Equipped ${def.n}`,'info');
  renderInventory();renderLoadout();
}

/* ────────────────────────────────────────────────
   RENDER — Skills
   ──────────────────────────────────────────────── */
function renderSkillsList(){
  const el=document.getElementById('skills-list');if(!el)return;
  const cats={combat:'Combat',gather:'Gathering',artisan:'Artisan'};
  el.innerHTML=Object.entries(cats).map(([cat,label])=>`
    <div class="muted tiny" style="text-transform:uppercase;letter-spacing:.08em;margin:8px 0 5px;font-weight:700">${label}</div>
    <div class="skill-board">
      ${Object.entries(SKILLS_DEF).filter(([,s])=>s.cat===cat).map(([id,s])=>{
        const xp=G.skills[id]||0,lv=getLevel(id),pct=Math.floor(xpPct(xp)*100);
        return `<button class="skill-tile ${G.activeSkill===id?'active':''}" onclick="openSkillDetail('${id}')"><span class="sicon">${s.icon}</span><span class="slv">Lv ${lv}</span><div class="bar xp"><i style="width:${pct}%"></i></div><span class="snm">${s.name}</span></button>`;
      }).join('')}
    </div>`).join('');
}
let openSkill=null;
function openSkillDetail(id){openSkill=id;showTab('skills');setTimeout(()=>renderSkillDetail(id),0);}
function renderSkillDetail(id){
  if(!id)return;const s=SKILLS_DEF[id];if(!s)return;
  const xp=G.skills[id]||0,lv=getLevel(id),pct=xpPct(xp)*100,toNext=xpToNext(xp);
  document.getElementById('skill-detail-title').textContent=`${s.icon} ${s.name}`;
  let acts='',calc=null;
  if(id==='woodcutting'){acts=renderActivities(TREES,id);calc=TREES.find(a=>a.id===G.skillTargetId)||TREES.find(a=>getLevel(id)>=a.req)||TREES[0];}
  else if(id==='mining'){acts=renderActivities(ROCKS,id);calc=ROCKS.find(a=>a.id===G.skillTargetId)||ROCKS.find(a=>getLevel(id)>=a.req)||ROCKS[0];}
  else if(id==='fishing'){acts=renderActivities(FISH_SPOTS,id);calc=FISH_SPOTS.find(a=>a.id===G.skillTargetId)||FISH_SPOTS.find(a=>getLevel(id)>=a.req)||FISH_SPOTS[0];}
  else if(typeof window.renderArtisanActivities==='function' && (id==='cooking'||id==='smithing'||id==='crafting'||id==='prayer')){acts=window.renderArtisanActivities(id);}
  else acts=`<div class="empty"><span class="em-icon">⚔️</span>Train ${s.name} by fighting in the Combat tab.</div>`;
  let calcHtml='';
  if(calc){
    const speed=getBonus('gatherSpeed');const ms=Math.max(500,Math.floor(calc.ms*(1-speed)));
    const aph=3600000/ms,avgQ=(calc.qty[0]+calc.qty[1])/2;
    calcHtml=`<div class="calc" style="margin-top:10px"><div><b>${Math.floor(aph*calc.xp)}</b><span>XP/hr</span></div><div><b>${Math.floor(aph*avgQ)}</b><span>${ITEMS[calc.prod]?.n||calc.prod}/hr</span></div><div><b>${(ms/1000).toFixed(1)}s</b><span>per action</span></div></div>`;
  }
  document.getElementById('skill-detail').innerHTML=`
    <div class="row" style="gap:14px;margin-bottom:12px">
      <div style="font-size:54px">${s.icon}</div>
      <div style="flex:1">
        <div style="font-family:var(--f-display);font-size:22px;color:var(--gold-2)">Level ${lv}</div>
        <div class="muted tiny">${xp.toLocaleString()} XP${lv<99?` · ${toNext.toLocaleString()} to next`:' · MAX'}</div>
        <div class="bar xp" style="margin-top:6px"><i style="width:${pct.toFixed(1)}%"></i></div>
      </div>
    </div>
    ${G.activeSkill===id?`<div class="activity-card"><div class="ac-icon">⏳</div><div style="flex:1"><b>Training ${TREES.concat(ROCKS,FISH_SPOTS).find(a=>a.id===G.skillTargetId)?.name||''}</b><span>Auto progresses while open</span></div><button class="btn btn-sm btn-danger" onclick="stopSkill()">Stop</button></div>`:''}
    ${calcHtml}
    <div class="muted tiny" style="margin:12px 0 6px;text-transform:uppercase;letter-spacing:.08em;font-weight:700">Activities</div>
    ${acts}`;
}
function renderActivities(acts,skillId){
  const lv=getLevel(skillId);
  return acts.map(a=>{
    const unlocked=lv>=a.req;const active=G.activeSkill===skillId&&G.skillTargetId===a.id;
    return `<button class="monster-row ${active?'fighting':''}" ${unlocked?'':'disabled'} onclick="${active?'stopSkill()':`startSkill('${skillId}','${a.id}',${a.ms})`}">
      <span class="mi">${a.icon}</span>
      <div style="flex:1;min-width:0"><span class="mn">${a.name}</span><span class="ms">Lv ${a.req} · ${a.xp} XP · ${(a.ms/1000).toFixed(1)}s · ${ITEMS[a.prod]?.n||a.prod}</span></div>
      ${!unlocked?`<span class="muted tiny">🔒 Lv ${a.req}</span>`:active?'<span style="color:var(--green);font-weight:700;font-size:11px">●ACTIVE</span>':''}
    </button>`;
  }).join('');
}

/* ────────────────────────────────────────────────
   RENDER — Inventory
   ──────────────────────────────────────────────── */
let invTab='bag';
function renderInventory(){
  /* Modern layout (renderInvFancy) replaces panel-inventory's children; bail early. */
  if(document.querySelector('#panel-inventory .invc-bag-col')) return;
  if(!document.getElementById('equip-panel')) return;
  /* equipment side */
  migrateEquipmentSlots();
  document.getElementById('equip-panel').innerHTML=`
    <div class="loadout-grid">
      ${EQUIP_SLOTS.map(slot=>{const id=G.equipment[slot];const def=id?ITEMS[id]:null;const meta=EQUIP_SLOT_META[slot];return `<button class="loadout-slot ${def?'':'empty'}" onclick="${def?`unequip('${slot}')`:''}" title="${def?def.n:meta.label}">${def?def.icon:meta.icon}<small>${def?def.n.split(' ')[0]:meta.label}</small></button>`;}).join('')}
    </div>
    <div class="muted tiny" style="margin-top:10px">Tap an empty slot to see what fits, or tap an equipped item to unequip it.</div>`;

  /* bag/bank side */
  const el=document.getElementById('inv-panel');
  const bag=invTab==='bag'?G.inventory:G.bank;
  const items=Object.entries(bag).filter(([,q])=>q>0);
  if(!items.length){el.innerHTML=`<div class="empty"><span class="em-icon">🎒</span>${invTab==='bag'?'Your bag is empty.':'Your bank is empty.'}</div>`;return;}
  el.innerHTML=`<div class="item-grid">${items.map(([id,qty])=>{
    const d=ITEMS[id];if(!d)return'';
    const qShow=qty>=1000?(qty/1000).toFixed(1)+'k':qty;
    return `<button class="item-slot" title="${d.n} ×${qty} · ${d.v}gp" onclick="onItemTap('${id}')">${d.icon}<span class="qty">${qShow}</span><span class="nm">${d.n.split(' ')[0]}</span></button>`;
  }).join('')}</div>
  <div class="muted tiny" style="margin-top:10px">Tap to use: equip, eat, plant, or sell. Long press for menu.</div>`;
}
function onItemTap(id){
  const d=ITEMS[id];if(!d)return;
  if(d.type==='weapon'||d.type==='armor'||d.type==='jewelry'||d.type==='ammo'||d.type==='companion'){equipItem(id);return;}
  if(d.heals){G.foodSlot=id;notify(`Auto-eat: ${d.n}`,'info');return;}
  if(d.seed){showTab('farming');return;}
  /* default: prompt to sell */
  if(confirm(`Sell 1× ${d.n} for ${d.v}gp?`)){G.gold+=d.v;removeItem(id,1);notify(`Sold ${d.n}`,'loot');renderInventory();updateTopbar();}
}

/* ────────────────────────────────────────────────
   RENDER — Farming
   ──────────────────────────────────────────────── */
function renderFarm(){
  const el=document.getElementById('farm-panel');if(!el)return;
  const plotCount=Math.max(8,(G.farmPlots||[]).length);
  el.innerHTML=`<div class="farm-mini" style="grid-template-columns:repeat(4,1fr)">
    ${Array.from({length:plotCount}).map((_,i)=>{
      const p=G.farmPlots[i];
      if(!p)return `<div class="farm-tile empty" onclick="openSeedPicker(${i})"><span>＋</span><small>Empty</small></div>`;
      const crop=CROPS[p.cropId];
      const elapsed=(Date.now()-p.plantedAt)/3600000;
      const pct=Math.min(100,Math.floor((elapsed/(crop.hours||1))*100));
      const ready=p.state==='ready';
      const lab=ready?'Ready':(p.watered?`${pct}%`:'Tap to water');
      const action=ready?`harvestPlot(${i})`:`waterPlot(${i})`;
      return `<div class="farm-tile ${ready?'ready':''}" onclick="${action}"><span style="font-size:24px">${crop.icon}</span><small>${lab}</small></div>`;
    }).join('')}
  </div>`;

  const cg=document.getElementById('crops-guide');
  cg.innerHTML=Object.entries(CROPS).map(([id,c])=>{
    const lv=getLevel('farming');const unlocked=lv>=c.req;
    return `<div class="shop-row"><span class="si">${c.icon}</span><div class="info"><b>${c.name}</b><span>Lv ${c.req} · ${c.hours}h grow · ${c.yield[0]}-${c.yield[1]} yield</span></div>${unlocked?'<span class="tag">Unlocked</span>':`<span class="muted tiny">🔒</span>`}</div>`;
  }).join('');
}
let pendingPlot=null;
function openSeedPicker(i){
  pendingPlot=i;
  const seeds=Object.entries(CROPS).filter(([,c])=>(G.inventory[c.seed]||0)>0&&getLevel('farming')>=c.req);
  if(!seeds.length){notify('No usable seeds. Visit the shop.','kill');return;}
  const m=document.getElementById('settings-modal');
  document.getElementById('settings-body').innerHTML=`<h3 style="margin-bottom:10px">Pick a seed</h3>${seeds.map(([id,c])=>`<button class="shop-row" style="width:100%;cursor:pointer" onclick="plantCrop(${i},'${id}');document.getElementById('settings-modal').classList.remove('show')"><span class="si">${c.icon}</span><div class="info"><b>${c.name}</b><span>${c.hours}h · ${c.yield[0]}-${c.yield[1]} yield</span></div><span class="price">x${G.inventory[c.seed]||0}</span></button>`).join('')}`;
  m.classList.add('show');
}

/* ────────────────────────────────────────────────
   RENDER — House
   ──────────────────────────────────────────────── */
let houseTab='rooms';
function renderHouse(){
  const el=document.getElementById('house-panel');if(!el)return;
  // Helper: render a hand-painted building image if we have one for this id,
  // otherwise the legacy emoji glyph. b103 ships ~10 building images.
  const _bldImg = (id, fallbackIcon, mapName) => {
    const path = (window[mapName] || {})[id];
    if (path) return `<img src="${path}" alt="" loading="lazy" data-fb-glyph="${fallbackIcon}" style="width:42px;height:42px;object-fit:contain;display:block" />`;
    return `<span style="font-size:32px;line-height:42px">${fallbackIcon}</span>`;
  };
  if(houseTab==='rooms'){
    el.innerHTML=Object.entries(ROOMS).map(([id,r])=>{
      const lv=G.rooms[id]||0,max=r.levels.length;
      const next=r.levels[lv];
      const canAfford=next?Object.entries(next.cost).every(([k,v])=>k==='gold'?G.gold>=v:(G.inventory[k]||0)>=v):false;
      return `<div class="shop-row"><span class="si" style="width:56px;height:56px;display:flex;align-items:center;justify-content:center">${_bldImg(id, r.icon, '_roomIcon')}</span><div class="info"><b>${r.name} ${lv?'· Lv '+lv:''}</b><span>${next?next.bonus+' · '+Object.entries(next.cost).map(([k,v])=>`${v} ${k==='gold'?'🪙':(ITEMS[k]?.icon||'')}`).join(' '):'MAX'}</span></div>${next?`<button class="btn btn-sm ${canAfford?'btn-primary':''}" ${canAfford?'':'disabled'} onclick="upgradeRoom('${id}')">${lv?'Upgrade':'Build'}</button>`:'<span class="tag">MAX</span>'}</div>`;
    }).join('');
  } else if(houseTab==='plot'){
    el.innerHTML=Object.entries(PLOT_BUILDINGS).map(([id,b])=>{
      const have=G.plotBuildings.filter(x=>x.id===id).length;
      const at=have>=b.max;
      const can=Object.entries(b.cost).every(([k,v])=>k==='gold'?G.gold>=v:(G.inventory[k]||0)>=v);
      return `<div class="shop-row"><span class="si" style="width:56px;height:56px;display:flex;align-items:center;justify-content:center">${_bldImg(id, b.icon, '_plotBuildingIcon')}</span><div class="info"><b>${b.name} ${have?'('+have+'/'+b.max+')':''}</b><span>${b.desc} · ${Object.entries(b.cost).map(([k,v])=>`${v} ${k==='gold'?'🪙':(ITEMS[k]?.icon||'')}`).join(' ')}</span></div><button class="btn btn-sm ${at?'':'btn-primary'}" ${at||!can?'disabled':''} onclick="buildPlot('${id}')">${at?'Max':'Build'}</button></div>`;
    }).join('');
  } else {
    el.innerHTML=`<div class="iap-grid">${HOUSE_THEMES.map(t=>{
      const owned=G.ownedThemes.includes(t.id);
      const active=G.houseTheme===t.id;
      return `<div class="iap-card ${active?'gold':''}"><div class="iap-icon">${t.icon}</div><h3>${t.name}</h3><div class="desc">${t.price?(t.currency==='gem'?`${t.price} 💎`:`${t.price}🪙`):'Default'}</div>${owned?(active?'<button class="btn btn-block" disabled>Active</button>':`<button class="btn btn-block btn-primary" onclick="setTheme('${t.id}')">Apply</button>`):`<button class="btn btn-block btn-gem" onclick="buyTheme('${t.id}')">Buy</button>`}</div>`;
    }).join('')}</div>`;
  }

  /* bonuses panel */
  document.getElementById('house-bonus').innerHTML=`
    <div class="kpi-row" style="grid-template-columns:1fr">
      <div class="kpi"><b>+${Math.round(getBonus('allXP')*100)}%</b><span>All XP</span></div>
      <div class="kpi"><b>+${Math.round(getBonus('combatXP')*100)}%</b><span>Combat XP</span></div>
      <div class="kpi"><b>+${Math.floor(getBonus('farmYield'))}</b><span>Farm Yield</span></div>
      <div class="kpi"><b>+${Math.round(getBonus('gatherSpeed')*100)}%</b><span>Gather Speed</span></div>
    </div>`;
}
function setHouseTab(t){houseTab=t;document.querySelectorAll('[data-house]').forEach(c=>c.classList.toggle('active',c.dataset.house===t));renderHouse();}
function upgradeRoom(id){
  const r=ROOMS[id];const lv=G.rooms[id]||0;const nx=r.levels[lv];if(!nx)return;
  for(const [k,v] of Object.entries(nx.cost)){if(k==='gold'?G.gold<v:(G.inventory[k]||0)<v){notify('Not enough resources','kill');return;}}
  for(const [k,v] of Object.entries(nx.cost)){if(k==='gold')G.gold-=v;else removeItem(k,v);}
  G.rooms[id]=lv+1;G.stats.roomsBuilt=(G.stats.roomsBuilt||0)+1;notify(`${r.name} upgraded`,'levelup');refreshAll();
}
function buildPlot(id){
  const b=PLOT_BUILDINGS[id];const have=G.plotBuildings.filter(x=>x.id===id).length;if(have>=b.max)return;
  for(const [k,v] of Object.entries(b.cost)){if(k==='gold'?G.gold<v:(G.inventory[k]||0)<v){notify('Not enough resources','kill');return;}}
  for(const [k,v] of Object.entries(b.cost)){if(k==='gold')G.gold-=v;else removeItem(k,v);}
  G.plotBuildings.push({id,uid:Date.now()});
  notify(`Built ${b.name}`,'levelup');refreshAll();
}
function setTheme(id){if(!G.ownedThemes.includes(id))return;G.houseTheme=id;notify('Theme applied','info');renderHouse();}
function buyTheme(id){
  const t=HOUSE_THEMES.find(x=>x.id===id);if(!t)return;
  if(t.currency==='gem'){
    if((G.gems||0)<t.price){notify('Need more 💎. Open the Store.','kill');return;}
    G.gems-=t.price;G.ownedThemes.push(id);G.houseTheme=id;
    notify(`${t.name} unlocked`,'levelup');saveLocal();updateTopbar();renderHouse();
  } else {
    if(G.gold<t.price){notify('Not enough gold','kill');return;}
    G.gold-=t.price;G.ownedThemes.push(id);G.houseTheme=id;
    notify(`${t.name} unlocked`,'levelup');saveLocal();updateTopbar();renderHouse();
  }
}

/* ────────────────────────────────────────────────
   RENDER — Social (leaderboard, clan)
   ──────────────────────────────────────────────── */
let lbMode='total';
async function renderSocial(){
  const lbEl=document.getElementById('leaderboard');if(!lbEl)return;
  lbEl.innerHTML='<div class="empty"><span class="em-icon">⏳</span>Fetching ranks…</div>';
  const r=await NetClient.leaderboard(lbMode);
  if(r.ok){
    document.getElementById('lb-sub').textContent=NetClient.online()&&G.account?'Live':'Mock data';
    lbEl.innerHTML=r.list.map(u=>`<div class="lb-row ${u.you?'you':''}"><span class="lb-rank">${u.rank<=3?['🥇','🥈','🥉'][u.rank-1]:u.rank}</span><span class="lb-name">${u.displayName}</span><span class="lb-stat">Lv ${u.total}</span><span class="lb-stat">⚔️${u.combat}</span><span class="lb-stat gold">🪙${(u.gold||0).toLocaleString()}</span></div>`).join('');
  }
  /* clan + friends */
  const cl=document.getElementById('social-panel');
  if(G.clanName){
    cl.innerHTML=`<div class="activity-card"><div class="ac-icon">🛡️</div><div style="flex:1"><b>${G.clanName}</b><span>Member · +5% all XP</span></div><button class="btn btn-sm btn-danger" onclick="leaveClan()">Leave</button></div>
    <div class="muted tiny" style="margin:12px 0 6px;text-transform:uppercase;letter-spacing:.08em;font-weight:700">Roster</div>
    <div class="lb-row"><span>👑</span><span class="lb-name">GuildMaster</span><span class="lb-stat" style="color:var(--green)">Online</span></div>
    <div class="lb-row you"><span>⚔️</span><span class="lb-name">${escapeHtml(G.playerName)} (you)</span><span class="lb-stat" style="color:var(--green)">Online</span></div>`;
  } else {
    const cr=await NetClient.clans();
    cl.innerHTML=`<div class="muted tiny" style="margin-bottom:10px">Join a clan for shared bonuses + chat. (Leaderboards and clan ops use a mock backend until the live server is connected.)</div>
    ${cr.ok?cr.clans.map(c=>`<div class="shop-row"><span class="si">🛡️</span><div class="info"><b>${c.name}</b><span>${c.members} members · ${c.bonus}</span></div><button class="btn btn-sm btn-primary" onclick="joinClan('${c.name.replace(/'/g,'')}')">Join</button></div>`).join(''):''}
    <div style="margin-top:10px;display:flex;gap:6px"><input type="text" id="clan-input" placeholder="Or create your own clan" style="flex:1;background:rgba(255,255,255,.04);border:1px solid var(--line-soft);border-radius:8px;padding:8px 10px"><button class="btn btn-primary" onclick="joinClan(document.getElementById('clan-input').value)">Create</button></div>`;
  }
}
function setLbMode(m){lbMode=m;document.querySelectorAll('[data-lb]').forEach(c=>c.classList.toggle('active',c.dataset.lb===m));renderSocial();}
function joinClan(name){if(!name||name.length<3){notify('Need at least 3 chars','kill');return;}G.clanName=name;notify(`Joined ${name}!`,'info');renderSocial();updateTopbar();}
function leaveClan(){G.clanName=null;renderSocial();updateTopbar();}

/* ────────────────────────────────────────────────
   RENDER — Shop / IAP store
   ──────────────────────────────────────────────── */
let shopTab='seeds';
function renderShop(){
  /* IAP side (always visible) */
  document.getElementById('iap-panel').innerHTML=`
    <div class="iap-grid">
      ${IAP_CATALOG.map(p=>`
        <div class="iap-card ${p.style||''}">
          ${p.ribbon?`<div class="ribbon">${p.ribbon}</div>`:''}
          <div class="iap-icon">${p.icon}</div>
          <h3>${p.title}</h3>
          <div class="desc">${p.desc}</div>
          <div class="row between" style="margin-top:auto">
            <div class="iap-price">${p.price}<small>${p.gems?p.gems+' 💎':''}${p.gold?' · '+p.gold.toLocaleString()+' 🪙':''}</small></div>
            <button class="btn btn-gem btn-sm" onclick="IAP.buy('${p.sku}')">Buy</button>
          </div>
        </div>`).join('')}
    </div>
    <div class="muted tiny" style="margin-top:14px">Purchases route to the platform you're running on (Steamworks / App Store / Play Store / Stripe). Receipts are validated server-side before granting items. Detected: <b>${IAP.detectPlatform()}</b>.</div>`;

  /* in-game shop side */
  const el=document.getElementById('shop-panel');if(!el)return;
  if(shopTab==='seeds'){
    el.innerHTML=SEED_SHOP.map(s=>{const d=ITEMS[s.id];const can=G.gold>=s.cost;return `<div class="shop-row"><span class="si">${d.icon}</span><div class="info"><b>${d.n} ×${s.qty}</b><span>Have: ${G.inventory[s.id]||0}</span></div><span class="price">🪙 ${s.cost}</span><button class="btn btn-sm ${can?'btn-primary':''}" ${can?'':'disabled'} onclick="buyShopItem('${s.id}',${s.qty},${s.cost})">Buy</button></div>`;}).join('');
  } else if(shopTab==='equip'){
    el.innerHTML=EQUIP_SHOP.map(s=>{const d=ITEMS[s.id];const can=G.gold>=s.cost;const stats=[d.atkB?`+${d.atkB} ATK`:'',d.defB?`+${d.defB} DEF`:'',d.strB?`+${d.strB} STR`:''].filter(Boolean).join(' · ');return `<div class="shop-row"><span class="si">${d.icon}</span><div class="info"><b>${d.n}</b><span>${stats||d.n}</span></div><span class="price">🪙 ${s.cost.toLocaleString()}</span><button class="btn btn-sm ${can?'btn-primary':''}" ${can?'':'disabled'} onclick="buyShopItem('${s.id}',1,${s.cost})">Buy</button></div>`;}).join('');
  } else {
    /* cosmetics — gem-priced */
    const cosmetics=[
      {id:'name_gold',name:'Golden Name',icon:'✨',price:200,desc:'Gold-tinted player name in chat & leaderboards.'},
      {id:'avatar_dragon',name:'Dragon Avatar',icon:'🐲',price:500,desc:'Animated dragon profile portrait.'},
      {id:'pet_phoenix',name:'Phoenix Pet',icon:'🦅',price:1200,desc:'Idle phoenix companion (cosmetic).'},
      {id:'emote_pack',name:'Emote Pack',icon:'😎',price:300,desc:'12 chat emotes for clan chat.'},
    ];
    el.innerHTML=cosmetics.map(c=>{const owned=G.ownedCosmetics.includes(c.id);const can=(G.gems||0)>=c.price;return `<div class="shop-row"><span class="si">${c.icon}</span><div class="info"><b>${c.name}</b><span>${c.desc}</span></div><span class="price gem">💎 ${c.price}</span>${owned?'<button class="btn btn-sm" disabled>Owned</button>':`<button class="btn btn-sm ${can?'btn-gem':''}" ${can?'':'disabled'} onclick="buyCosmetic('${c.id}',${c.price})">Buy</button>`}</div>`;}).join('')+`<div class="muted tiny" style="margin-top:10px">Need 💎? <button class="btn btn-sm btn-gem" onclick="IAP.buy('gems_starter')">Get Gems</button></div>`;
  }
}
function setShopTab(t){shopTab=t;document.querySelectorAll('[data-shop]').forEach(c=>c.classList.toggle('active',c.dataset.shop===t));renderShop();}
function buyShopItem(id,qty,cost){if(G.gold<cost){notify('Not enough gold','kill');return;}G.gold-=cost;addItem(id,qty);notify(`Bought ${qty}× ${ITEMS[id]?.n}`,'loot');updateTopbar();renderShop();}
function buyCosmetic(id,price){if((G.gems||0)<price){notify('Need 💎. Tap "Get Gems".','kill');return;}G.gems-=price;G.ownedCosmetics.push(id);notify('Cosmetic unlocked!','levelup');saveLocal();updateTopbar();renderShop();}

/* ────────────────────────────────────────────────
   SETTINGS modal
   ──────────────────────────────────────────────── */
function openSettings(){
  const m=document.getElementById('settings-modal');
  document.getElementById('settings-body').innerHTML=`
    <div class="muted tiny" style="text-transform:uppercase;letter-spacing:.08em;margin-bottom:8px">Account</div>
    ${G.account?
      `<div class="activity-card"><div class="ac-icon">👤</div><div style="flex:1"><b>${escapeHtml(G.account.displayName)}</b><span>Provider: ${G.account.provider}</span></div><button class="btn btn-sm btn-danger" onclick="NetClient.signOut();openSettings()">Sign out</button></div>`:
      `<div class="kpi-row" style="margin-bottom:14px">
        <button class="btn tap" onclick="NetClient.signIn('steam').then(()=>openSettings())">Sign in (Steam)</button>
        <button class="btn tap" onclick="NetClient.signIn('apple').then(()=>openSettings())">Sign in (Apple)</button>
        <button class="btn tap" onclick="NetClient.signIn('google').then(()=>openSettings())">Sign in (Google)</button>
        <button class="btn tap" onclick="NetClient.signIn('guest').then(()=>openSettings())">Continue as guest</button>
      </div>`}

    <div class="muted tiny" style="text-transform:uppercase;letter-spacing:.08em;margin:14px 0 6px">Display name</div>
    <div class="row" style="gap:8px"><input type="text" value="${escapeHtml(G.playerName)}" id="set-name" style="flex:1;background:rgba(255,255,255,.04);border:1px solid var(--line-soft);border-radius:8px;padding:8px 10px"><button class="btn" onclick="G.playerName=document.getElementById('set-name').value||'Adventurer';updateTopbar();notify('Name updated','info')">Save</button></div>

    <div class="muted tiny" style="text-transform:uppercase;letter-spacing:.08em;margin:14px 0 6px">Game</div>
    <label class="row tap" style="gap:8px;padding:6px 0"><input type="checkbox" ${G.settings.sfx?'checked':''} onchange="G.settings.sfx=this.checked;saveLocal()"> Sound effects</label>
    <label class="row tap" style="gap:8px;padding:6px 0"><input type="checkbox" ${G.settings.reduceFx?'checked':''} onchange="G.settings.reduceFx=this.checked;saveLocal();document.documentElement.style.setProperty('--reduce-fx',this.checked?'1':'0')"> Reduce visual effects</label>
    <label class="row tap" style="gap:8px;padding:6px 0"><input type="checkbox" ${G.settings.leftHand?'checked':''} onchange="G.settings.leftHand=this.checked;saveLocal()"> Left-handed mode (mobile)</label>

    <div class="muted tiny" style="text-transform:uppercase;letter-spacing:.08em;margin:14px 0 6px">Save data</div>
    <div class="kpi-row">
      <button class="btn tap" onclick="saveLocal();notify('Saved','info')">💾 Save now</button>
      <button class="btn tap" onclick="cloudSync()">☁️ Cloud sync</button>
      <button class="btn tap" onclick="exportSave()">⬇️ Export</button>
      <button class="btn tap btn-danger" onclick="if(confirm('Erase save?')){localStorage.removeItem(SAVE_KEY);location.reload();}">🗑️ Reset</button>
    </div>
    <div class="muted tiny" style="margin-top:8px">Last cloud sync: ${G.cloudSyncedAt?new Date(G.cloudSyncedAt).toLocaleString():'never'}.</div>

    <div class="muted tiny" style="text-transform:uppercase;letter-spacing:.08em;margin:14px 0 6px">Shortcuts</div>
    <div class="muted tiny">1-8: tabs · S: save · Esc: close modals · Arrow keys: nav focus</div>`;
  m.classList.add('show');
}
async function cloudSync(){
  if(!G.account){notify('Sign in first','kill');return;}
  const r=await NetClient.cloudSync();
  notify(r.ok?'Cloud saved ☁️':'Cloud save failed','info');
  openSettings();
}
function exportSave(){
  const data=btoa(unescape(encodeURIComponent(JSON.stringify(G))));
  try{navigator.clipboard?.writeText(data);notify('Save exported to clipboard','info');}
  catch(e){prompt('Copy your save:',data);}
}

/* ────────────────────────────────────────────────
   helpers
   ──────────────────────────────────────────────── */
function escapeHtml(s){return String(s||'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));}

/* ════════════════════════════════════════════════
   INPUT / EVENTS
   ════════════════════════════════════════════════ */
function bindEvents(){
  /* nav */
  document.querySelectorAll('.nav-btn,.bn-btn').forEach(b=>b.addEventListener('click',()=>showTab(b.dataset.tab)));
  /* tier chips */
  document.querySelectorAll('#tier-chips .chip').forEach(c=>c.addEventListener('click',()=>selectTier(+c.dataset.tier)));
  /* inv tabs */
  document.querySelectorAll('[data-inv]').forEach(c=>c.addEventListener('click',()=>{invTab=c.dataset.inv;document.querySelectorAll('[data-inv]').forEach(x=>x.classList.toggle('active',x===c));renderInventory();}));
  /* house tabs */
  document.querySelectorAll('[data-house]').forEach(c=>c.addEventListener('click',()=>setHouseTab(c.dataset.house)));
  /* lb tabs */
  document.querySelectorAll('[data-lb]').forEach(c=>c.addEventListener('click',()=>setLbMode(c.dataset.lb)));
  /* shop tabs */
  document.querySelectorAll('[data-shop]').forEach(c=>c.addEventListener('click',()=>setShopTab(c.dataset.shop)));
  /* combat stop */
  document.getElementById('combat-stop').addEventListener('click',stopCombat);
  /* topbar buttons */
  document.getElementById('btn-save').addEventListener('click',()=>{saveLocal();notify('Saved 💾','info');});
  document.getElementById('btn-settings').addEventListener('click',openSettings);
  document.getElementById('btn-save-mobile')?.addEventListener('click',()=>{saveLocal();notify('Saved 💾','info');document.getElementById('more-modal').classList.remove('show');});
  document.getElementById('btn-settings-mobile')?.addEventListener('click',()=>{document.getElementById('more-modal').classList.remove('show');openSettings();});
  document.getElementById('combat-gear-btn').addEventListener('click',()=>showTab('inventory'));
  document.getElementById('top-gem-btn').addEventListener('click',()=>showTab('shop'));
  /* modals close */
  document.querySelectorAll('[data-close-modal]').forEach(b=>b.addEventListener('click',()=>document.getElementById(b.dataset.closeModal).classList.remove('show')));
  document.querySelectorAll('.modal').forEach(m=>m.addEventListener('click',e=>{if(e.target===m)m.classList.remove('show');}));
  /* keyboard shortcuts */
  document.addEventListener('keydown',e=>{
    if(e.key==='Escape'){document.querySelectorAll('.modal.show').forEach(m=>m.classList.remove('show'));return;}
    if(e.target.matches('input,textarea,select'))return;
    const map={'1':'profile','2':'combat','3':'skills','4':'inventory','5':'farming','6':'house','7':'social','8':'shop'};
    if(map[e.key]){showTab(map[e.key]);e.preventDefault();}
    if(e.key.toLowerCase()==='s'){saveLocal();notify('Saved 💾','info');}
  });
  /* online/offline events */
  window.addEventListener('online',updateNetStatus);
  window.addEventListener('offline',updateNetStatus);
  /* visibility — save on hide */
  document.addEventListener('visibilitychange',()=>{if(document.hidden)saveLocal();});
}

/* ════════════════════════════════════════════════
   PWA — manifest + service worker (single file)
   ════════════════════════════════════════════════ */
function installPwa(){
  /* inject manifest */
  const manifest={
    name:'Hearthrise — Idle Homestead',
    short_name:'Hearthrise',
    description:'Idle homestead RPG — fight, farm, craft, build a home.',
    start_url:'./',
    display:'fullscreen',
    orientation:'any',
    // b108: switched from old dark navy to cozy parchment palette so the
    // installed-PWA splash screen + status bar match the in-game UI.
    background_color:'#fff8e2',     // parchment cream
    theme_color:'#5c2d08',           // cocoa
    categories:['games','entertainment'],
    icons:[
      // Real Hearthrise crest instead of emoji square. Available on the
      // deploy at assets/brand/hearthrise-logo.svg.
      {src:'assets/brand/hearthrise-logo.svg', sizes:'any', type:'image/svg+xml', purpose:'any'},
      {src:'assets/brand/hearthrise-logo.svg', sizes:'192x192', type:'image/svg+xml'},
      {src:'assets/brand/hearthrise-logo.svg', sizes:'512x512', type:'image/svg+xml'},
    ],
  };
  const blob=new Blob([JSON.stringify(manifest)],{type:'application/manifest+json'});
  const url=URL.createObjectURL(blob);
  const link=document.createElement('link');link.rel='manifest';link.href=url;document.head.appendChild(link);

  /* register service worker (only if served over http/https)
   *
   * b111: rewrote the strategy. The old SW used a fixed cache name
   * (`hearthbound-v2`) and "cache-first" for everything, which meant
   * any file the SW had ever seen got served from cache forever —
   * pushing a new build did nothing for installed PWAs until the user
   * manually deleted + reinstalled the home shortcut.
   *
   * New strategy:
   *  • Cache name = `hearthrise-${BUILD}` derived from the cache-buster
   *    on this page's <script> tags. New build → new cache name → old
   *    caches purged on activate.
   *  • App shell (HTML/JS/CSS) = network-first. Try fetch; on success,
   *    update cache + serve. On failure, fall back to cache (offline).
   *  • Static assets (images/fonts) = cache-first. They're versioned
   *    by URL anyway, so cache hits are safe.
   *  • skipWaiting() + clients.claim() so the new SW takes control
   *    immediately without requiring a page close. */
  if('serviceWorker' in navigator && /^https?:/.test(location.protocol)){
    /* Extract the active build version from any of our versioned <script>
     * tags. e.g. legacy.js?v=111 → "111". Fallback "0" if not found. */
    const verMatch = (function(){
      const scripts = document.querySelectorAll('script[src*="?v="]');
      for (const s of scripts){
        const m = s.src.match(/\?v=(\d+)/);
        if (m) return m[1];
      }
      return '0';
    })();
    const swCode = `
      const BUILD = '${verMatch}';
      const CACHE = 'hearthrise-' + BUILD;
      const SHELL = ['./','./index.html'];

      function isShell(req){
        const u = new URL(req.url);
        if (u.origin !== self.location.origin) return false;
        const p = u.pathname;
        return p === '/' || p.endsWith('/') || p.endsWith('.html')
            || p.endsWith('.js') || p.endsWith('.css') || p.endsWith('.json');
      }
      function isStatic(req){
        const u = new URL(req.url);
        if (u.origin !== self.location.origin) return false;
        const p = u.pathname;
        return p.endsWith('.png') || p.endsWith('.jpg') || p.endsWith('.jpeg')
            || p.endsWith('.svg') || p.endsWith('.webp') || p.endsWith('.woff2')
            || p.endsWith('.woff') || p.endsWith('.ttf');
      }

      self.addEventListener('install', e => {
        // Pre-cache the app shell so cold-start works offline.
        e.waitUntil(
          caches.open(CACHE).then(c => c.addAll(SHELL).catch(()=>{}))
        );
        self.skipWaiting();
      });

      self.addEventListener('activate', e => {
        // Purge any old hearthrise-* caches from previous builds.
        e.waitUntil((async () => {
          const keys = await caches.keys();
          await Promise.all(keys.map(k => {
            if (k !== CACHE && (k.startsWith('hearthrise-') || k === 'hearthbound-v2')) {
              return caches.delete(k);
            }
          }));
          await self.clients.claim();
        })());
      });

      self.addEventListener('fetch', e => {
        const req = e.request;
        if (req.method !== 'GET') return;

        if (isShell(req)) {
          // Network-first for app shell — try fresh, fall back to cache offline.
          e.respondWith((async () => {
            try {
              const res = await fetch(req);
              try { (await caches.open(CACHE)).put(req, res.clone()); } catch {}
              return res;
            } catch {
              const cached = await caches.match(req);
              if (cached) return cached;
              return caches.match('./');
            }
          })());
          return;
        }

        if (isStatic(req)) {
          // Cache-first for images/fonts — versioned by URL, safe to cache.
          e.respondWith((async () => {
            const cached = await caches.match(req);
            if (cached) return cached;
            try {
              const res = await fetch(req);
              try { (await caches.open(CACHE)).put(req, res.clone()); } catch {}
              return res;
            } catch {
              return new Response('', { status: 504 });
            }
          })());
          return;
        }

        // Anything else (cross-origin Supabase, CDN imports): pass through.
      });
    `;
    const swBlob = new Blob([swCode], {type:'text/javascript'});
    const swUrl  = URL.createObjectURL(swBlob);
    navigator.serviceWorker.register(swUrl).catch(()=>{});
  }

  /* iOS / Android install prompt hint */
  let deferredPrompt=null;
  window.addEventListener('beforeinstallprompt',e=>{e.preventDefault();deferredPrompt=e;
    /* only nudge once per session */
    if(!sessionStorage.getItem('install-prompted')){
      sessionStorage.setItem('install-prompted','1');
      setTimeout(()=>{
        const ok=confirm('Install Hearthrise to your home screen for full-screen play?');
        if(ok&&deferredPrompt){deferredPrompt.prompt();}
      },5000);
    }
  });
}

