/* ════════════════════════════════════════════════════════
   INVENTORY REWORK + LOADOUT PRESETS — additive
   Wraps existing renderInventory + onItemTap. No combat edits.
   ════════════════════════════════════════════════════════ */

/* ───── State init ───── */
G.loadouts = G.loadouts || [
  {name:'Combat',  icon:'⚔️', equipment:{}, tools:{}, foodSlot:null, set:false},
  {name:'Mining',  icon:'⛏️', equipment:{}, tools:{}, foodSlot:null, set:false},
  {name:'Cooking', icon:'🍳', equipment:{}, tools:{}, foodSlot:null, set:false},
  {name:'Custom',  icon:'⭐', equipment:{}, tools:{}, foodSlot:null, set:false},
];
window._invFilter = 'all';
window._invSort = 'recent';
window._invSearch = '';
window._invSelectMode = false;
window._invSelected = new Set();
window._activeLoadout = -1;

/* ───── Helpers ───── */
function _itemCategory(it){
  if(!it) return 'mat';
  if(it.type === 'weapon') return 'gear';
  if(it.type === 'armor' || it.type === 'jewelry' || it.type === 'ammo' || it.type === 'companion') return 'gear';
  if(it.heals) return 'food';
  if(it.seed) return 'seed';
  if(it.buryXp) return 'bone';
  /* bars / ore / planks / logs by name suffix */
  const n = (it.n || '').toLowerCase();
  if(/bar$/.test(n)) return 'bar';
  if(/ore$/.test(n) || /coal$/.test(n)) return 'mat';
  if(/log$/.test(n) || /plank$/.test(n)) return 'plank';
  return 'mat';
}
function _itemTier(id){
  const tiers=['bronze','iron','steel','mithril','adamant','rune','dragon'];
  for(let i=0;i<tiers.length;i++){ if(String(id).startsWith(tiers[i]+'_')) return i+1; }
  return 0;
}
function _shortName(name){
  return String(name||'').split(' ')[0];
}
function _eqStatsTotals(){
  const s = {atk:0, str:0, def:0, hp:0};
  if(typeof getEquipmentStats === 'function'){
    const r = getEquipmentStats();
    s.atk = r.atkB || r.attackBonus || 0;
    s.str = r.strB || r.strengthBonus || 0;
    s.def = r.defB || r.defenseBonus || 0;
    s.hp  = r.hpB  || r.hitpointsBonus || 0;
  } else if(G.equipment){
    Object.values(G.equipment).forEach(id=>{
      const it = ITEMS[id]; if(!it) return;
      s.atk += it.atkB||0; s.str += it.strB||0; s.def += it.defB||0; s.hp += it.hpB||0;
    });
  }
  return s;
}

/* ───── Loadout actions ───── */
function saveLoadout(idx){
  const l = G.loadouts[idx]; if(!l) return;
  l.equipment = {...G.equipment};
  l.tools = {...(G.tools||{})};
  l.foodSlot = G.foodSlot || null;
  l.set = true;
  saveLocal();
  notify(`💾 Saved loadout: ${l.name}`, 'info');
  renderInvNew();
}
function applyLoadout(idx){
  const l = G.loadouts[idx]; if(!l || !l.set){ notify('Slot is empty — long-press to save current kit', 'kill'); return; }
  /* Equipment: items currently equipped that aren't in the preset go to bag */
  const newEq = {};
  Object.keys(G.equipment).forEach(slot=>{
    const cur = G.equipment[slot];
    const target = l.equipment[slot] || null;
    /* if current slot has an item, return it to bag */
    if(cur) addItem(cur, 1);
    /* if target item exists in bag, take from bag */
    if(target){
      if(hasItem(target, 1)){
        removeItem(target, 1);
        newEq[slot] = target;
      } else {
        newEq[slot] = null;
      }
    } else {
      newEq[slot] = null;
    }
  });
  G.equipment = newEq;
  /* Tools: held tools, not in inventory — just copy refs that exist in ITEMS */
  if(G.tools && l.tools){
    Object.keys(G.tools).forEach(slot=>{
      const target = l.tools[slot];
      if(target && ITEMS[target]) G.tools[slot] = target;
    });
  }
  /* Food slot */
  if(l.foodSlot && hasItem(l.foodSlot, 1)) G.foodSlot = l.foodSlot;
  else if(!l.foodSlot) G.foodSlot = null;
  window._activeLoadout = idx;
  saveLocal();
  notify(`✓ Applied loadout: ${l.name}`, 'levelup');
  refreshAll();
}
function renameLoadout(idx){
  const l = G.loadouts[idx]; if(!l) return;
  const nm = prompt(`Rename "${l.name}" to:`, l.name);
  if(nm && nm.trim()){ l.name = nm.trim().slice(0,18); saveLocal(); renderInvNew(); }
}
function clearLoadout(idx){
  const l = G.loadouts[idx]; if(!l) return;
  if(!confirm(`Clear loadout "${l.name}"?`)) return;
  l.equipment = {}; l.tools = {}; l.foodSlot = null; l.set = false;
  saveLocal(); renderInvNew();
}

/* ───── Filters / search / sort ───── */
const _CATEGORIES = [
  {id:'all',     label:'All',      test:()=>true},
  {id:'weapons', label:'Weapons',  test:it=>it && it.type==='weapon'},
  {id:'armor',   label:'Armor',    test:it=>it && (it.type==='armor' || it.type==='jewelry' || it.type==='ammo' || it.type==='companion')},
  {id:'food',    label:'Food',     test:it=>it && it.heals},
  {id:'seeds',   label:'Crops',    test:it=>it && (it.seed || it.crop)},
  {id:'bones',   label:'Bones',    test:it=>it && (it.buryXp || /bones?$/.test(it.n||''))},
  {id:'mat',     label:'Materials',test:it=>it && !it.type && !it.heals && !it.seed && !it.buryXp},
];
function _itemCategoryDisplay(it){
  if(!it) return 'mat';
  if(it.type === 'weapon') return 'weapon';
  if(it.type === 'armor' || it.type === 'jewelry' || it.type === 'ammo' || it.type === 'companion') return 'gear';
  if(it.heals) return 'food';
  if(it.seed) return 'seed';
  if(it.buryXp) return 'bone';
  if(/(_bar|_ore|_log|_plank)$/.test(it.id||'') || /Bar|Ore|Log|Plank/.test(it.n||'')) return 'mat';
  return 'mat';
}
function _filteredItems(srcDict){
  const cat = _CATEGORIES.find(c=>c.id === window._invFilter) || _CATEGORIES[0];
  const search = (window._invSearch||'').toLowerCase().trim();
  let arr = Object.entries(srcDict).filter(([id,q])=>{
    if(q <= 0) return false;
    const it = ITEMS[id]; if(!it) return false;
    if(!cat.test(it)) return false;
    if(search && !it.n.toLowerCase().includes(search)) return false;
    return true;
  });
  /* sort */
  switch(window._invSort){
    case 'name': arr.sort((a,b)=>(ITEMS[a[0]]?.n||'').localeCompare(ITEMS[b[0]]?.n||'')); break;
    case 'value':arr.sort((a,b)=>(ITEMS[b[0]]?.v||0)-(ITEMS[a[0]]?.v||0)); break;
    case 'qty':  arr.sort((a,b)=>b[1]-a[1]); break;
    /* 'recent' = insertion order, no sort */
  }
  return arr;
}

/* ───── Item detail flyout ───── */
function openInvDetail(id){
  const it = ITEMS[id]; if(!it) return;
  const qty = G.inventory[id] || G.bank[id] || 0;
  const cat = _itemCategory(it);
  const d = document.getElementById('inv-detail-overlay') || (function(){
    const el = document.createElement('div');
    el.id = 'inv-detail-overlay';
    el.className = 'inv-detail';
    el.addEventListener('click',e=>{ if(e.target===el) el.classList.remove('show'); });
    document.body.appendChild(el);
    return el;
  })();
  /* Stats grid for gear/tools, otherwise show value/qty */
  const stats = [];
  stats.push(`<div><b>${qty.toLocaleString()}</b><span>quantity</span></div>`);
  stats.push(`<div><b>🪙 ${(it.v||0).toLocaleString()}</b><span>value each</span></div>`);
  if(it.atkB) stats.push(`<div><b>+${it.atkB}</b><span>attack</span></div>`);
  if(it.strB) stats.push(`<div><b>+${it.strB}</b><span>strength</span></div>`);
  if(it.defB) stats.push(`<div><b>+${it.defB}</b><span>defense</span></div>`);
  if(it.heals) stats.push(`<div><b>+${it.heals}</b><span>heals</span></div>`);
  if(it.speed != null) stats.push(`<div><b>+${Math.round((it.speed||0)*100)}%</b><span>tool speed</span></div>`);
  if(it.smithSpeed != null) stats.push(`<div><b>+${Math.round((it.smithSpeed||0)*100)}%</b><span>smith speed</span></div>`);
  if(it.doubleCook != null) stats.push(`<div><b>+${Math.round((it.doubleCook||0)*100)}%</b><span>double-cook</span></div>`);
  if(it.noBurn != null) stats.push(`<div><b>+${Math.round((it.noBurn||0)*100)}%</b><span>no-burn</span></div>`);
  if(it.weaponType) stats.push(`<div><b>${it.weaponType}</b><span>weapon type</span></div>`);
  if(it.reqSkill && it.reqLv) stats.push(`<div><b>${SKILLS_DEF[it.reqSkill]?.name||it.reqSkill} ${it.reqLv}</b><span>required</span></div>`);

  /* Action buttons — detect by type/heals/seed/buryXp instead of kind */
  const acts = [];
  const isEquippable = it && (it.type==='weapon' || it.type==='armor' || it.type==='jewelry' || it.type==='ammo' || it.type==='companion' || it.kind==='gear' || it.kind==='tool');
  if(isEquippable){
    if(typeof equipItem === 'function')           acts.push(`<button class="btn btn-primary" onclick="equipItem('${id}');closeInvDetail();setTimeout(renderInvNew,0)">Equip</button>`);
    else if(typeof equipGear === 'function')      acts.push(`<button class="btn btn-primary" onclick="equipGear('${id}');closeInvDetail();setTimeout(renderInvNew,0)">Equip</button>`);
  }
  if(it.heals){
    acts.push(`<button class="btn btn-primary" onclick="G.foodSlot='${id}';notify('Auto-eat: ${it.n}','info');closeInvDetail()">Set Auto-eat</button>`);
    if(typeof eatItem === 'function') acts.push(`<button class="btn" onclick="eatItem('${id}');closeInvDetail()">Eat 1</button>`);
  }
  if(it.kind === 'upgrade' || it.upgradesTo){
    if(typeof openUpgradePicker === 'function') acts.push(`<button class="btn btn-primary" onclick="openUpgradePicker('${id}');closeInvDetail()">Apply Kit</button>`);
  }
  if(it.seed){
    acts.push(`<button class="btn" onclick="showTab('farming');closeInvDetail()">Open Farm</button>`);
  }
  if(it.buryXp){
    acts.push(`<button class="btn" onclick="if(typeof buryBones==='function'){buryBones('${id}');}else{G.skills.prayer=(G.skills.prayer||0)+${it.buryXp};removeItem('${id}',1);notify('Buried (+${it.buryXp} prayer XP)','info');}closeInvDetail();renderInvNew()">Bury</button>`);
  }
  if(qty > 0){
    acts.push(`<button class="btn" onclick="invSellOne('${id}');closeInvDetail()">Sell 1 (${(it.v||0)}🪙)</button>`);
    if(qty > 1) acts.push(`<button class="btn btn-danger" onclick="invSellAll('${id}')">Sell All ${qty} (${((it.v||0)*qty).toLocaleString()}🪙)</button>`);
    if(typeof bankItem === 'function') acts.push(`<button class="btn" onclick="bankItem('${id}',${qty});closeInvDetail()">→ Bank</button>`);
  }

  d.innerHTML = `<div class="inv-detail-card">
    <div class="inv-detail-close" onclick="closeInvDetail()">✕</div>
    <div class="inv-detail-head">
      <div class="inv-detail-icon">${it.icon||'❓'}</div>
      <div>
        <div class="inv-detail-name">${it.n}</div>
        <div class="inv-detail-meta">${cat}${it.slot?' · '+it.slot:''}${it.weaponType?' · '+it.weaponType:''}${_itemTier(id)?' · T'+_itemTier(id):''}</div>
      </div>
    </div>
    <div class="inv-detail-stats">${stats.join('')}</div>
    <div class="inv-detail-actions">${acts.join('')}</div>
  </div>`;
  d.classList.add('show');
}
function closeInvDetail(){
  document.getElementById('inv-detail-overlay')?.classList.remove('show');
}

/* Sell helpers — wrap existing logic if available, else simple */
function invSellOne(id){
  const it = ITEMS[id]; if(!it) return;
  if((G.inventory[id]||0) <= 0){ notify('Nothing to sell','kill'); return; }
  G.gold = (G.gold||0) + (it.v||0);
  removeItem(id, 1);
  notify(`Sold 1× ${it.n} (+${it.v||0}🪙)`,'loot');
  updateTopbar(); renderInvNew();
}
function invSellAll(id){
  const it = ITEMS[id]; if(!it) return;
  const qty = G.inventory[id]||0;
  if(qty <= 0){ notify('Nothing to sell','kill'); return; }
  G.gold = (G.gold||0) + (it.v||0)*qty;
  delete G.inventory[id];
  notify(`Sold ${qty}× ${it.n} (+${((it.v||0)*qty).toLocaleString()}🪙)`,'loot');
  updateTopbar(); renderInvNew(); closeInvDetail();
}
function invSellSelected(){
  if(!window._invSelected.size){ notify('Nothing selected','kill'); return; }
  let total = 0, count = 0;
  for(const id of window._invSelected){
    const it = ITEMS[id]; if(!it) continue;
    const qty = G.inventory[id]||0; if(qty<=0) continue;
    total += (it.v||0)*qty; count += qty;
    delete G.inventory[id];
  }
  G.gold = (G.gold||0) + total;
  window._invSelected.clear();
  notify(`Sold ${count} items for ${total.toLocaleString()}🪙`,'loot');
  window._invSelectMode = false;
  updateTopbar(); renderInvNew();
}

/* ───── Render: equipment paper-doll + loadouts + bag w/ filters ───── */
function renderInvNew(){
  const eqEl = document.getElementById('equip-panel');
  const bagEl = document.getElementById('inv-panel');
  if(!eqEl || !bagEl) return;
  if(typeof migrateEquipmentSlots === 'function') migrateEquipmentSlots();

  const stats = _eqStatsTotals();
  const slotIcon = slot => (typeof EQUIP_SLOT_META !== 'undefined' && EQUIP_SLOT_META[slot]) ? EQUIP_SLOT_META[slot].icon : '▫️';
  const slotLabel = slot => (typeof EQUIP_SLOT_META !== 'undefined' && EQUIP_SLOT_META[slot]) ? EQUIP_SLOT_META[slot].label : slot;
  const slotBtn = (slot)=>{
    const id = G.equipment ? G.equipment[slot] : null;
    const it = id ? ITEMS[id] : null;
    const tier = it ? _itemTier(id) : 0;
    const svg = window._slotSVG && window._slotSVG[slot];
    if(!it){
      return `<button class="inv-slot empty" data-slot="${slot}" title="${slotLabel(slot)}"><span class="slot-svg">${svg||''}</span></button>`;
    }
    return `<button class="inv-slot" data-slot="${slot}" onclick="unequipSlotInv('${slot}')" title="${it.n} (tap to unequip)">${it.icon}${tier?`<span class="tier">T${tier}</span>`:''}${(it&&it.hands===2)?'<span class="twoH">2H</span>':''}</button>`;
  };

  /* Loadout pill bar */
  const loadoutsHtml = G.loadouts.map((l,i)=>{
    const isActive = window._activeLoadout === i;
    const summary = l.set
      ? `${Object.values(l.equipment||{}).filter(Boolean).length}+${Object.values(l.tools||{}).filter(Boolean).length} items`
      : 'empty';
    return `<button class="inv-loadout ${isActive?'active':''}" oncontextmenu="event.preventDefault();saveLoadout(${i});return false" onclick="${l.set?`applyLoadout(${i})`:`saveLoadout(${i})`}" title="${l.set?'Tap to apply · long-press / right-click to overwrite':'Tap to save current kit'}">
      <span class="ld-icon">${l.icon}</span>
      <span class="ld-name">${l.name}</span>
      <span class="ld-empty">${summary}</span>
      <span class="ld-actions">
        <span class="ld-act" onclick="event.stopPropagation();renameLoadout(${i})" title="Rename">✏️</span>
        ${l.set?`<span class="ld-act" onclick="event.stopPropagation();clearLoadout(${i})" title="Clear">✕</span>`:''}
      </span>
    </button>`;
  }).join('');

  /* Paper-doll: centered body avatar, slots arc around it via grid-template-areas */
  const SLOT_ORDER = ['helmet','earrings','necklace','cape','weapon','body','ammo','ring1','ring2','gloves','belt','boots','pants','companion'];
  const doll = `<div class="inv-doll">${SLOT_ORDER.map(s=>slotBtn(s)).join('')}</div>`;

  /* Held tools rail */
  let toolsRail = '';
  if(typeof TOOL_SLOTS !== 'undefined' && Array.isArray(TOOL_SLOTS) && G.tools){
    toolsRail = `<div class="inv-eq-title" style="margin:6px 0 4px">Tools</div>
      <div class="inv-tool-rail">${TOOL_SLOTS.map(t=>{
        const id = G.tools[t.slot];
        const it = id ? ITEMS[id] : null;
        const tier = it ? (it.tier || _itemTier(id)) : 0;
        return `<button class="inv-slot ${it?'':'empty'}" title="${it?it.n:t.label}">${it?it.icon:t.icon}<small>${it?_shortName(it.n):t.label}</small>${tier?`<span class="tier">T${tier}</span>`:''}</button>`;
      }).join('')}</div>`;
  }

  eqEl.innerHTML = `
    <div class="inv-eq-head">
      <div class="inv-eq-title">Loadout</div>
      <div class="inv-eq-stats"><span><b>+${stats.atk}</b> atk</span><span><b>+${stats.str}</b> str</span><span><b>+${stats.def}</b> def</span></div>
    </div>
    <div class="inv-loadouts">${loadoutsHtml}</div>
    ${doll}
    ${toolsRail}
    `;

  /* Bag side */
  const src = (typeof invTab !== 'undefined' && invTab === 'bank') ? G.bank : G.inventory;
  const items = _filteredItems(src);
  const totalCount = items.reduce((s,[id,q])=>s+q, 0);
  const totalValue = items.reduce((s,[id,q])=>s+(ITEMS[id]?.v||0)*q, 0);

  const filtersHtml = _CATEGORIES.map(c=>{
    const isAct = window._invFilter === c.id;
    return `<button class="inv-filter ${isAct?'active':''}" onclick="invSetFilter('${c.id}')">${c.label}</button>`;
  }).join('');

  const toolbarHtml = `
    <div class="inv-toolbar">
      <div class="inv-search">
        <span style="font-size:14px">🔍</span>
        <input type="text" placeholder="Search…" value="${(window._invSearch||'').replace(/"/g,'&quot;')}" oninput="invSetSearch(this.value)">
      </div>
      <select class="inv-sort" onchange="invSetSort(this.value)">
        <option value="recent" ${window._invSort==='recent'?'selected':''}>Recent</option>
        <option value="name" ${window._invSort==='name'?'selected':''}>Name</option>
        <option value="value" ${window._invSort==='value'?'selected':''}>Value</option>
        <option value="qty" ${window._invSort==='qty'?'selected':''}>Quantity</option>
      </select>
      <button class="inv-select-toggle ${window._invSelectMode?'active':''}" onclick="invToggleSelectMode()">${window._invSelectMode?'✓ Selecting':'Select'}</button>
    </div>
    <div class="inv-filters">${filtersHtml}</div>`;

  let gridHtml;
  if(!items.length){
    gridHtml = `<div class="inv-empty"><span class="em-icon">${(window._invSearch||window._invFilter!=='all')?'🔍':'🎒'}</span>${(window._invSearch||window._invFilter!=='all')?'Nothing matches your filters.':'Your bag is empty.'}</div>`;
  } else {
    gridHtml = `<div class="inv-grid ${window._invSelectMode?'inv-mode-select':''}">${items.map(([id,qty])=>{
      const it = ITEMS[id]; if(!it) return '';
      const cat = _itemCategory(it);
      const sel = window._invSelected.has(id);
      const tier = _itemTier(id);
      const qShow = qty>=10000?(qty/1000).toFixed(1)+'k':qty>=1000?(qty/1000).toFixed(1)+'k':qty;
      return `<button class="inv-item ${sel?'selected':''}" data-cat="${cat}" onclick="invItemTap('${id}')" title="${it.n} ×${qty} · ${it.v||0}🪙 each">
        <span class="selbox"></span>
        <span style="font-size:24px;line-height:1">${it.icon}</span>
        <span class="qty">${qShow}</span>
        <span class="nm">${_shortName(it.n)}</span>
        ${tier?`<span class="tier">T${tier}</span>`:''}
      </button>`;
    }).join('')}</div>`;
  }

  let batchBar = '';
  if(window._invSelectMode){
    let selValue = 0, selCount = 0;
    for(const id of window._invSelected){
      const q = G.inventory[id]||0;
      selValue += (ITEMS[id]?.v||0)*q;
      selCount += q;
    }
    batchBar = `<div class="inv-batch-bar">
      <div class="bb-info"><b>${window._invSelected.size}</b> stacks · <b>${selCount.toLocaleString()}</b> items · worth <b>${selValue.toLocaleString()}🪙</b></div>
      <div class="bb-actions">
        <button class="btn" onclick="window._invSelected.clear();renderInvNew()">Clear</button>
        <button class="btn btn-danger" onclick="invSellSelected()">Sell Selected</button>
      </div>
    </div>`;
  }

  const summaryHtml = items.length ? `<div class="muted tiny" style="margin-top:8px;display:flex;justify-content:space-between"><span>${items.length} stack${items.length!==1?'s':''} · ${totalCount.toLocaleString()} items</span><span>worth ${totalValue.toLocaleString()}🪙</span></div>` : '';

  bagEl.innerHTML = toolbarHtml + gridHtml + summaryHtml + batchBar;
}

function invSetFilter(id){ window._invFilter=id; renderInvNew(); }
function invSetSearch(v){ window._invSearch=v||''; renderInvNew(); }
function invSetSort(v){ window._invSort=v||'recent'; renderInvNew(); }
function invToggleSelectMode(){
  window._invSelectMode = !window._invSelectMode;
  if(!window._invSelectMode) window._invSelected.clear();
  renderInvNew();
}
function invItemTap(id){
  if(window._invSelectMode){
    if(window._invSelected.has(id)) window._invSelected.delete(id);
    else window._invSelected.add(id);
    renderInvNew();
    return;
  }
  openInvDetail(id);
}
/* Unequip helper that doesn't conflict with existing names */
function unequipSlotInv(slot){
  if(typeof unequip === 'function'){ unequip(slot); }
  else if(typeof unequipGear === 'function'){ unequipGear(slot); }
  else {
    const id = G.equipment[slot]; if(!id) return;
    G.equipment[slot] = null; addItem(id, 1);
    notify(`Unequipped ${ITEMS[id]?.n||id}`,'info');
  }
  setTimeout(renderInvNew, 0);
}

/* ───── Wire it in: replace renderInventory + onItemTap with the new one ───── */
const _origRenderInventory = window.renderInventory;
window.renderInventory = function(){
  /* Ensure original DOM containers exist; if so we render into them */
  if(document.getElementById('equip-panel') && document.getElementById('inv-panel')){
    renderInvNew();
  } else if(typeof _origRenderInventory === 'function'){
    _origRenderInventory();
  }
};

const _origOnItemTap = window.onItemTap;
window.onItemTap = function(id){
  /* If item detail flyout is preferred, use it. Falls back to original. */
  if(ITEMS[id]) openInvDetail(id);
  else if(typeof _origOnItemTap === 'function') _origOnItemTap(id);
};

/* Re-render on tab switch; also attach when bag/bank chip clicked */
const _origShowTabInv = window.showTab;
window.showTab = function(tab){
  if(typeof _origShowTabInv === 'function') _origShowTabInv(tab);
  if(tab === 'inventory') setTimeout(renderInvNew, 0);
};

/* Bag/Bank chip clicks: re-render via the new path */
document.addEventListener('click', e=>{
  const t = e.target.closest && e.target.closest('[data-inv]');
  if(t){
    const v = t.dataset.inv;
    if(typeof window.invTab !== 'undefined') window.invTab = v;
    document.querySelectorAll('[data-inv]').forEach(x=>x.classList.toggle('active', x.dataset.inv===v));
    setTimeout(renderInvNew, 0);
  }
});

/* Initial paint refresh */
setTimeout(()=>{ if(typeof activeTab !== 'undefined' && activeTab === 'inventory') renderInvNew(); }, 50);
console.log('Inventory rework + loadout presets: loaded');

