"use strict";
/* ════════════════════════════════════════════════════════════
   COMBAT LIFE — animations + damage numbers
   Hooks:
     - combatTick (snapshot HP before, compare after, paint deltas)
     - renderCombat (mark .arena.active when fighting)
   ════════════════════════════════════════════════════════════ */

(function combatLife(){
  let lastPlayerHp = null, lastMonsterHp = null;

  function spawnDamage(side, value, opts){
    /* side: "player" or "monster" portraits */
    const fighter = document.querySelectorAll('.fighter');
    const target = side === 'player' ? fighter[0] : fighter[1];
    if(!target) return;
    const num = document.createElement('div');
    num.className = 'dmg-num' + (opts && opts.crit?' crit':'') + (opts && opts.miss?' miss':'') + (side==='player'?' player-hit':'');
    num.textContent = (opts && opts.miss) ? 'miss' : (value > 0 ? '−' + value : '0');
    target.appendChild(num);
    /* shake the receiving fighter */
    if(!opts || !opts.miss){
      target.classList.add('hit');
      setTimeout(()=>target.classList.remove('hit'), 360);
      const bar = target.querySelector('.bar');
      if(bar){ bar.classList.add('hp-pulse'); setTimeout(()=>bar.classList.remove('hp-pulse'), 520); }
    }
    setTimeout(()=>num.remove(), 1100);
  }

  /* Wrap combatTick to detect HP deltas */
  const _origCombatTick = window.combatTick;
  if(typeof _origCombatTick !== 'function') return;
  window.combatTick = function(){
    const beforeP = G.playerHp, beforeM = G.monsterHp;
    _origCombatTick.apply(this, arguments);
    const afterP = G.playerHp, afterM = G.monsterHp;
    /* monster took damage = player hit */
    if(beforeM != null && afterM < beforeM){
      const dmg = beforeM - afterM;
      spawnDamage('monster', dmg, { crit: dmg >= 8 });
    } else if(beforeM != null && afterM === beforeM && G.activeMonster){
      /* miss feedback only if player tried to attack — read last log line */
      const last = G.combatLog && G.combatLog[G.combatLog.length-1] || '';
      if(/miss/i.test(last) && /You/i.test(last)){
        spawnDamage('monster', 0, { miss: true });
      }
    }
    if(beforeP != null && afterP < beforeP){
      const dmg = beforeP - afterP;
      spawnDamage('player', dmg, {});
    }
    /* mark arena as active so the breathe animation runs */
    document.querySelectorAll('.arena').forEach(a=>{
      if(G.activeMonster) a.classList.add('active');
      else a.classList.remove('active');
    });
  };

  /* Also mark/unmark on renderCombat (covers stop-combat clean state) */
  const _prevRenderCombat = window.renderCombat;
  if(typeof _prevRenderCombat === 'function'){
    window.renderCombat = function(){
      _prevRenderCombat.apply(this, arguments);
      setTimeout(()=>{
        document.querySelectorAll('.arena').forEach(a=>{
          if(G.activeMonster) a.classList.add('active');
          else a.classList.remove('active');
        });
      }, 0);
    };
  }
})();

