"use strict";
/* ════════════════════════════════════════════════════════════
   PERSISTENT ACTIVITY BAR
   Slot below topbar. Shows current action + progress + stop.
   Reads from G.activeMonster / G.activeSkill / G.activeAction.
   Updates every 100ms via tick. No engine changes.
   ════════════════════════════════════════════════════════════ */

(function injectActivityBar(){
  if(document.getElementById('activity-bar')) return;
  const main = document.querySelector('.main'); if(!main) return;
  const topbar = main.querySelector('.topbar'); if(!topbar) return;
  const bar = document.createElement('div');
  bar.id = 'activity-bar';
  bar.className = 'activity-bar v2 idle';
  // Compact pill: icon + activity name + meta (Lv X · 12,345 xp/hr) + Stop.
  // No progress bar here — that lives inside the relevant activity panel.
  bar.innerHTML = `
    <div class="ab-icon" id="ab-icon">💤</div>
    <div class="ab-info">
      <div class="ab-name" id="ab-name">Idle — pick an activity</div>
    </div>
    <div class="ab-meta" id="ab-meta"></div>
    <button class="ab-stop" id="ab-stop">Stop</button>`;
  /* insert right after topbar */
  topbar.insertAdjacentElement('afterend', bar);
  bar.querySelector('#ab-stop').addEventListener('click', stopCurrentActivity);
})();

function stopCurrentActivity(){
  if(G.activeMonster && typeof stopCombat === 'function'){ stopCombat(); return; }
  if(G.activeSkill && typeof stopSkill === 'function'){ stopSkill(); return; }
  if(G.activeAction && typeof stopAction === 'function'){ stopAction(); return; }
}

/* Compute progress fraction. We try several common paths since this game
   has multiple action loops (combat tick + gather skill tick). */
function _activityProgress(){
  if(G.activeMonster){
    /* Monster combat: tick is fixed (~2.4s). We can fake fluid progress
       by interpolating between combatLog entries — but cleaner: read
       G._combatTickStart if set, else just animate via timer. */
    const tickMs = (typeof COMBAT_BALANCE === 'object' && COMBAT_BALANCE.tickMs) || 2400;
    const last = G._combatTickStart || (G._combatTickStart = Date.now());
    const elapsed = Date.now() - last;
    return Math.min(1, elapsed / tickMs);
  }
  if(G.activeSkill && typeof G.skillProgress === 'number'){
    return Math.min(1, G.skillProgress || 0);
  }
  if(G.activeAction && typeof G.actionProgress === 'number'){
    return Math.min(1, G.actionProgress || 0);
  }
  return 0;
}

function _activityXpHr(){
  /* Estimate XP/hr for current skill action */
  if(G.activeSkill && G.skillTargetId){
    let t = null;
    if(G.activeSkill === 'woodcutting' && typeof TREES !== 'undefined') t = TREES.find(a=>a.id===G.skillTargetId);
    else if(G.activeSkill === 'mining' && typeof ROCKS !== 'undefined') t = ROCKS.find(a=>a.id===G.skillTargetId);
    else if(G.activeSkill === 'fishing' && typeof FISH_SPOTS !== 'undefined') t = FISH_SPOTS.find(a=>a.id===G.skillTargetId);
    if(t){
      const speed = (typeof getBonus==='function') ? (getBonus('gatherSpeed')||0) : 0;
      const ms = Math.max(500, Math.floor((t.ms||3000) * (1 - speed)));
      const aph = 3600000 / ms;
      return Math.floor(aph * (t.xp||0));
    }
  }
  return null;
}

function refreshActivityBar(){
  const bar = document.getElementById('activity-bar'); if(!bar) return;
  const iconEl = document.getElementById('ab-icon');
  const nameEl = document.getElementById('ab-name');
  const metaEl = document.getElementById('ab-meta');
  const stopBtn = document.getElementById('ab-stop');

  /* Combat */
  if(G.activeMonster){
    const m = MONSTERS[G.activeMonster];
    bar.classList.remove('idle'); bar.classList.add('combat');
    if(iconEl) iconEl.textContent = m?.icon || '⚔️';
    if(nameEl) nameEl.textContent = `Fighting ${m?.name||'?'}`;
    if(metaEl){
      // Show kill count for the current foe (resets when the player picks a
      // new monster) + total session kills. The arena vs panel already shows
      // player HP, so the activity bar carries the more interesting numbers.
      const kills = (G.combatKillsThisFoe||0);
      const totalKills = (G.stats?.kills||0);
      metaEl.innerHTML = ''
        + '<span class="ab-kills">⚔️ <b>'+kills.toLocaleString()+'</b> this fight</span>'
        + '<span class="ab-tkills">Lifetime <b>'+totalKills.toLocaleString()+'</b></span>';
    }
    if(stopBtn) stopBtn.style.display = '';
    refreshPanelProgress();
    return;
  }
  /* Skill training */
  if(G.activeSkill){
    const s = SKILLS_DEF[G.activeSkill];
    bar.classList.remove('idle','combat');
    if(iconEl) iconEl.textContent = s?.icon || '⚙️';
    let actName = G.skillTargetId ? G.skillTargetId.replace(/_/g,' ') : '';
    if(nameEl) nameEl.textContent = `${s?.name||G.activeSkill}${actName?' — '+actName:''}`;
    const xph = _activityXpHr();
    if(metaEl){
      const lv = (typeof getLevel==='function') ? getLevel(G.activeSkill) : 0;
      metaEl.innerHTML = `<span class="ab-lv">Lv <b>${lv}</b></span>${xph?`<span class="ab-xph"><b>${xph.toLocaleString()}</b> xp/hr</span>`:''}`;
    }
    if(stopBtn) stopBtn.style.display = '';
    refreshPanelProgress();
    return;
  }
  /* Generic action loop (smelt/saw/forge/cook in some branches) */
  if(G.activeAction){
    const a = G.activeAction;
    const map = {smelt:'🔥',saw:'🪚',forge:'🔨',cook:'🍳',craft:'🧵',enchant:'✨',pray:'🙏'};
    const labelMap = {smelt:'Smelting',saw:'Sawing',forge:'Forging',cook:'Cooking',craft:'Crafting',enchant:'Enchanting',pray:'Bury'};
    bar.classList.remove('idle','combat');
    if(iconEl) iconEl.textContent = map[a.kind] || '⚙️';
    if(nameEl) nameEl.textContent = `${labelMap[a.kind]||a.kind} — ${(a.targetId||'').replace(/_/g,' ')}`;
    if(metaEl) metaEl.innerHTML = '';
    if(stopBtn) stopBtn.style.display = '';
    refreshPanelProgress();
    return;
  }
  /* Artisan (cooking/smithing/crafting recipes) — Phase A.1 onwards uses
     this path instead of legacy activeAction. */
  if(G.activeArtisanRecipe){
    const map = {cooking:'🍳', smithing:'🔨', crafting:'🧵', prayer:'🙏'};
    const skill = G.activeArtisanSkill || 'cooking';
    bar.classList.remove('idle','combat');
    if(iconEl) iconEl.textContent = map[skill] || '⚙️';
    if(nameEl){
      const recipeName = G.activeArtisanRecipe.replace(/^[a-z]+_/,'').replace(/_/g,' ');
      nameEl.textContent = `${skill[0].toUpperCase()}${skill.slice(1)} — ${recipeName}`;
    }
    if(metaEl){
      const lv = (typeof getLevel==='function') ? getLevel(skill) : 0;
      metaEl.innerHTML = `<span class="ab-lv">Lv <b>${lv}</b></span>`;
    }
    if(stopBtn) stopBtn.style.display = '';
    refreshPanelProgress();
    return;
  }
  /* Idle */
  bar.classList.add('idle'); bar.classList.remove('combat');
  if(iconEl) iconEl.textContent = '💤';
  if(nameEl) nameEl.textContent = 'Idle — pick an activity';
  if(metaEl) metaEl.innerHTML = '';
  if(stopBtn) stopBtn.style.display = 'none';

  // Drive the per-tab progress bar (only visible when the active tab
  // matches the kind of activity in progress).
  refreshPanelProgress();
}

// ── Per-tab progress bar ─────────────────────────────────────────
// A separate <div class="panel-progress"> is appended to each panel
// that hosts an activity. It auto-shows/hides + tracks progress.
function ensurePanelProgress(panelId){
  const panel = document.getElementById(panelId);
  if(!panel) return null;
  let pp = panel.querySelector(':scope > .panel-progress');
  if(!pp){
    pp = document.createElement('div');
    pp.className = 'panel-progress';
    pp.innerHTML = `
      <div class="pp-row">
        <span class="pp-label" data-pp="label">—</span>
        <span class="pp-meta" data-pp="meta"></span>
      </div>
      <div class="pp-bar"><i data-pp="fill" style="width:0%"></i></div>`;
    // Insert at the very top of the panel so it sits above other cards.
    panel.insertBefore(pp, panel.firstChild);
  }
  return pp;
}

function refreshPanelProgress(){
  // Possible activity panels: combat, skills (per-skill), artisan-skills.
  const activeTab = document.querySelector('.panel.active')?.id || '';
  const updateOne = function(panelId, label, meta, pct, kind){
    const pp = ensurePanelProgress(panelId); if(!pp) return;
    const visible = activeTab === panelId;
    pp.style.display = visible ? '' : 'none';
    if(!visible) return;
    pp.dataset.kind = kind || '';
    const lbl = pp.querySelector('[data-pp=label]');
    const mta = pp.querySelector('[data-pp=meta]');
    const fill = pp.querySelector('[data-pp=fill]');
    if(lbl) lbl.textContent = label;
    if(mta) mta.textContent = meta || '';
    if(fill) fill.style.width = (Math.max(0,Math.min(1,pct))*100).toFixed(1)+'%';
  };

  // Hide all first; the matching one will be shown.
  document.querySelectorAll('.panel-progress').forEach(p => { p.style.display = 'none'; });

  if(G.activeMonster){
    // Combat has its own arena-vs panel + activity bar HP — suppress the
    // small panel-progress strip on the combat tab to avoid redundancy.
    return;
  }
  if(G.activeSkill){
    const s = SKILLS_DEF[G.activeSkill] || {};
    const target = G.skillTargetId ? G.skillTargetId.replace(/_/g,' ') : '';
    const xph = _activityXpHr();
    updateOne('panel-skills',
      `${s.name || G.activeSkill}${target?' — '+target:''}`,
      xph ? `${xph.toLocaleString()} xp/hr` : '',
      _activityProgress(),
      'skill');
    return;
  }
  if(G.activeArtisanRecipe){
    const skill = G.activeArtisanSkill || 'cooking';
    const recipeName = G.activeArtisanRecipe.replace(/^[a-z]+_/,'').replace(/_/g,' ');
    updateOne('panel-skills',
      `${skill[0].toUpperCase()}${skill.slice(1)} — ${recipeName}`,
      '',
      Math.min(1, G.skillProgress || G.actionProgress || 0),
      'artisan');
    return;
  }
}

/* Reset combat tick timer when a tick fires so the progress animation matches reality */
const _origCombatTickAB = window.combatTick;
if(typeof _origCombatTickAB === 'function'){
  window.combatTick = function(){
    G._combatTickStart = Date.now();
    return _origCombatTickAB.apply(this, arguments);
  };
}
const _origStopCombatAB = window.stopCombat;
if(typeof _origStopCombatAB === 'function'){
  window.stopCombat = function(){ const r = _origStopCombatAB.apply(this, arguments); refreshActivityBar(); return r; };
}
const _origStartCombatAB = window.startCombat;
if(typeof _origStartCombatAB === 'function'){
  window.startCombat = function(){ G._combatTickStart = Date.now(); const r = _origStartCombatAB.apply(this, arguments); refreshActivityBar(); return r; };
}

/* Drive the bar at 10fps */
setInterval(refreshActivityBar, 100);

console.log('Activity bar: loaded');

// ── Combat-mode arena VS visualization ─────────────────────────
// Toggles body.in-combat and injects a centered "PLAYER vs FOE" portrait
// + HP bars panel into #panel-combat .combat-arena when a fight is active.
(function setupArenaVs(){
  function ensureArenaVs(){
    var arena = document.querySelector('#panel-combat .combat-arena');
    if(!arena) return null;
    var vs = arena.querySelector(':scope > .arena-vs');
    if(!vs){
      vs = document.createElement('div');
      vs.className = 'arena-vs';
      vs.innerHTML = `
        <div class="arena-side player">
          <div class="arena-portrait" id="arena-player-portrait">🧙</div>
          <div class="arena-name" id="arena-player-name">You</div>
          <div class="arena-hp-bar"><i id="arena-player-hp" style="width:100%"></i></div>
          <div class="arena-hp-text" id="arena-player-hp-text">10 / 10</div>
        </div>
        <div class="arena-vs-divider">VS</div>
        <div class="arena-side foe">
          <div class="arena-portrait" id="arena-foe-portrait">👾</div>
          <div class="arena-name" id="arena-foe-name">—</div>
          <div class="arena-hp-bar"><i id="arena-foe-hp" style="width:100%"></i></div>
          <div class="arena-hp-text" id="arena-foe-hp-text">— / —</div>
        </div>`;
      // Insert before the card-body so it sits at the top of the arena.
      var head = arena.querySelector('.card-head');
      if(head && head.nextSibling){ arena.insertBefore(vs, head.nextSibling); }
      else { arena.appendChild(vs); }
    }
    return vs;
  }

  function refreshArenaVs(){
    var inCombat = !!(window.G && window.G.activeMonster);
    document.body.classList.toggle('in-combat', inCombat);
    var existing = document.querySelector('#panel-combat .combat-arena > .arena-vs');
    if(!inCombat){
      // Hide the arena-vs panel when not fighting so stale player/foe
      // portraits don't linger.
      if(existing) existing.style.display = 'none';
      return;
    }
    ensureArenaVs();
    if(existing) existing.style.display = '';
    var m = window.MONSTERS && window.MONSTERS[window.G.activeMonster];
    var foeIcon = (window._monsterIcon && window._monsterIcon[window.G.activeMonster])
      ? '<img src="'+window._monsterIcon[window.G.activeMonster]+'" alt="">'
      : (m?.icon || '👾');
    var pf = document.getElementById('arena-foe-portrait');
    var pn = document.getElementById('arena-foe-name');
    var phb = document.getElementById('arena-foe-hp');
    var pht = document.getElementById('arena-foe-hp-text');
    if(pf) pf.innerHTML = foeIcon;
    if(pn) pn.textContent = m?.name || window.G.activeMonster;
    var foePct = window.G.monsterMaxHp ? Math.max(0, (window.G.monsterHp/window.G.monsterMaxHp)*100) : 0;
    if(phb) phb.style.width = foePct.toFixed(1)+'%';
    if(pht) pht.textContent = (window.G.monsterHp||0)+' / '+(window.G.monsterMaxHp||0);

    var pp = document.getElementById('arena-player-portrait');
    var pnp = document.getElementById('arena-player-name');
    var php = document.getElementById('arena-player-hp');
    var phpt = document.getElementById('arena-player-hp-text');
    if(pnp) pnp.textContent = window.G.playerName || 'You';
    var pPct = window.G.playerMaxHp ? Math.max(0, (window.G.playerHp/window.G.playerMaxHp)*100) : 0;
    if(php) php.style.width = pPct.toFixed(1)+'%';
    if(phpt) phpt.textContent = (window.G.playerHp||0)+' / '+(window.G.playerMaxHp||0);
  }

  // Tick alongside the activity bar
  setInterval(refreshArenaVs, 200);
  console.log('Arena VS: loaded');

  // Hook combatTick to also pop damage numbers on the new arena-vs portraits
  // (the original .fighter elements live inside .arena which we hid).
  var _lastP = null, _lastM = null;
  function popDmg(target, value, opts){
    if(!target) return;
    var num = document.createElement('div');
    num.className = 'dmg-num-vs' + (opts && opts.crit ? ' crit' : '') + (opts && opts.miss ? ' miss' : '');
    num.textContent = (opts && opts.miss) ? 'miss' : (value > 0 ? '-' + value : '0');
    target.appendChild(num);
    if(!opts || !opts.miss){
      target.classList.add('hit-shake');
      setTimeout(function(){ target.classList.remove('hit-shake'); }, 320);
    }
    setTimeout(function(){ num.remove(); }, 1100);
  }
  var _origTick = window.combatTick;
  if(typeof _origTick === 'function'){
    window.combatTick = function(){
      var beforeP = window.G && window.G.playerHp;
      var beforeM = window.G && window.G.monsterHp;
      var r = _origTick.apply(this, arguments);
      var afterP = window.G && window.G.playerHp;
      var afterM = window.G && window.G.monsterHp;
      var foeP = document.querySelector('#panel-combat .arena-vs .arena-side.foe .arena-portrait');
      var youP = document.querySelector('#panel-combat .arena-vs .arena-side.player .arena-portrait');
      if(beforeM != null && afterM < beforeM){
        popDmg(foeP, beforeM - afterM, { crit: (beforeM - afterM) >= 8 });
      } else if(beforeM != null && afterM === beforeM && window.G && window.G.activeMonster){
        var last = window.G.combatLog && window.G.combatLog[window.G.combatLog.length-1] || '';
        if(/miss/i.test(last) && /You/i.test(last)){
          popDmg(foeP, 0, { miss: true });
        }
      }
      if(beforeP != null && afterP < beforeP){
        popDmg(youP, beforeP - afterP, {});
      }
      _lastP = afterP; _lastM = afterM;
      return r;
    };
  }
})();

// ═════════════════════════════════════════════════════════════
// Combat preview modal — clicking a monster opens this panel with
// estimated DPS, drop table, your stats + Fight button. No more
// auto-starting combat. Inspired by Idle Clans-style combat preview.
// ═════════════════════════════════════════════════════════════
(function setupCombatPreview(){
  function ensureModal(){
    if(document.getElementById('mob-preview')) return;
    var ov = document.createElement('div');
    ov.id = 'mob-preview';
    ov.className = 'mob-preview-overlay';
    ov.innerHTML = '<div class="mp-modal" id="mp-modal"></div>';
    ov.addEventListener('click', function(e){ if(e.target === ov) closePreview(); });
    document.body.appendChild(ov);
  }
  function closePreview(){
    var ov = document.getElementById('mob-preview');
    if(ov) ov.classList.remove('open');
  }
  window.closeMobPreview = closePreview;

  function fmtNum(n){ return Math.round(n).toLocaleString(); }

  // Estimate damage range + hit chance + DPS using same math the engine
  // uses (best-effort — fallback to coarse approximation if engine helpers
  // aren't exposed).
  function estimateCombat(m){
    var atkLv = (typeof getLevel === 'function') ? getLevel('attack') : 1;
    var strLv = (typeof getLevel === 'function') ? getLevel('strength') : 1;
    var defLv = (typeof getLevel === 'function') ? getLevel('defense') : 1;
    var hpLv  = (typeof getLevel === 'function') ? getLevel('hitpoints') : 1;
    var eq = (typeof getEquipmentStats === 'function') ? getEquipmentStats() : {atk:0, str:0, def:0};
    var weakness = m.weaponWeak || null;
    var weaponType = (typeof window.getEquippedWeaponType === 'function') ? window.getEquippedWeaponType() : 'sword';
    var weaknessBonus = (weakness && weaponType === weakness) ? 1.20 : 1.0;
    var maxHit = Math.max(1, Math.floor((strLv + (eq.str||0)) * 0.18 * weaknessBonus + 1));
    var minHit = Math.max(1, Math.floor(maxHit * 0.3));
    var hitChance = Math.min(0.95, Math.max(0.20, ((atkLv + (eq.atk||0)) - (m.def||0)) / Math.max(1, (atkLv + (eq.atk||0)) + (m.def||0)) + 0.55));
    var avgDmg = ((minHit + maxHit) / 2) * hitChance;
    var tickMs = (typeof window.COMBAT_BALANCE === 'object' && window.COMBAT_BALANCE.tickMs) ? window.COMBAT_BALANCE.tickMs : 2400;
    var dps = avgDmg * (1000 / tickMs);
    var killTimeS = m.hp / dps;
    var killsHr = 3600 / killTimeS;
    var xpHr = killsHr * (m.xp || 0);
    var goldHr = killsHr * (((m.gp && m.gp[0])||0) + ((m.gp && m.gp[1])||0))/2;
    return {
      minHit: minHit, maxHit: maxHit,
      hitChance: hitChance,
      dps: dps, killTimeS: killTimeS,
      killsHr: killsHr, xpHr: xpHr, goldHr: goldHr,
      weaknessBonus: weaknessBonus,
    };
  }

  function getMonsterIcon(id){
    var path = window._monsterIcon && window._monsterIcon[id];
    var m = window.MONSTERS && window.MONSTERS[id];
    if(path) return '<img src="'+path+'" alt="" />';
    return '<span style="font-size:96px">'+(m && m.icon || '👾')+'</span>';
  }

  function lootRowHtml(d){
    var id = typeof d === 'string' ? d : d.id;
    var item = window.ITEMS && window.ITEMS[id];
    var name = item ? (item.n||id) : id;
    var icon = item && item.icon ? item.icon : '📦';
    var iconPath = window._itemPath && window._itemPath[id];
    var iconHtml = iconPath ? '<img src="'+iconPath+'" />' : '<span>'+icon+'</span>';
    var chance = (typeof d === 'object' && d.chance) ? Math.round(d.chance*100)+'%' : 'common';
    var qty = (typeof d === 'object' && d.qty) ? d.qty.join('-') : '1';
    return '<div class="mp-loot-row">'+
      '<div class="mp-loot-icon">'+iconHtml+'</div>'+
      '<div class="mp-loot-name">'+name+'</div>'+
      '<div class="mp-loot-meta">'+qty+'× · '+chance+'</div>'+
    '</div>';
  }

  function renderPreview(monsterId){
    ensureModal();
    var m = window.MONSTERS && window.MONSTERS[monsterId];
    if(!m) return;
    var ov = document.getElementById('mob-preview');
    var modal = document.getElementById('mp-modal');
    var est = estimateCombat(m);
    var weaknessLabel = m.weaponWeak ? m.weaponWeak.charAt(0).toUpperCase()+m.weaponWeak.slice(1) : 'None';
    var weaknessTag = est.weaknessBonus > 1 ? '<span class="mp-tag good">+20% dmg</span>' : '<span class="mp-tag muted">no bonus</span>';
    var atkLv = (typeof getLevel === 'function') ? getLevel('attack') : 1;
    var strLv = (typeof getLevel === 'function') ? getLevel('strength') : 1;
    var defLv = (typeof getLevel === 'function') ? getLevel('defense') : 1;
    var hpLv = (typeof getLevel === 'function') ? getLevel('hitpoints') : 1;
    var rngLv = (typeof getLevel === 'function') ? getLevel('ranged') : 1;
    var magLv = (typeof getLevel === 'function') ? getLevel('magic') : 1;
    var foodId = G && G.foodSlot;
    var foodCount = foodId ? (G.inventory[foodId]||0) : 0;
    var foodIcon = foodId && window.ITEMS[foodId] ? window.ITEMS[foodId].icon : '🍖';
    var foodName = foodId && window.ITEMS[foodId] ? window.ITEMS[foodId].n : 'No food';

    modal.innerHTML = `
      <button class="mp-close" aria-label="Close">✕</button>
      <div class="mp-header">
        <div class="mp-portrait">${getMonsterIcon(monsterId)}</div>
        <div class="mp-title">
          <h2>${m.name}</h2>
          <div class="mp-sub">${m.family||'monster'} · Tier ${m.tier||1}</div>
        </div>
      </div>

      <div class="mp-stats-row">
        <div class="mp-stat-card">
          <div class="mp-stat-label">HP</div>
          <div class="mp-stat-val">${m.hp}</div>
        </div>
        <div class="mp-stat-card">
          <div class="mp-stat-label">Attack</div>
          <div class="mp-stat-val">${m.atk||0}</div>
        </div>
        <div class="mp-stat-card">
          <div class="mp-stat-label">Defense</div>
          <div class="mp-stat-val">${m.def||0}</div>
        </div>
        <div class="mp-stat-card">
          <div class="mp-stat-label">XP / Kill</div>
          <div class="mp-stat-val">${m.xp||0}</div>
        </div>
      </div>

      <div class="mp-info-row">
        <div><span class="mp-info-label">Weakness</span><span class="mp-info-val">${weaknessLabel} ${weaknessTag}</span></div>
        <div><span class="mp-info-label">Attack speed</span><span class="mp-info-val">${((window.COMBAT_BALANCE && window.COMBAT_BALANCE.tickMs) || 2400)/1000}s</span></div>
      </div>

      <div class="mp-grid">
        <div class="mp-pane">
          <h4>Your Combat</h4>
          <div class="mp-mystats">
            <div><span>⚔️</span><b>Lv ${atkLv}</b><small>Attack</small></div>
            <div><span>💪</span><b>Lv ${strLv}</b><small>Strength</small></div>
            <div><span>🛡️</span><b>Lv ${defLv}</b><small>Defense</small></div>
            <div><span>❤️</span><b>Lv ${hpLv}</b><small>HP</small></div>
            <div><span>🏹</span><b>Lv ${rngLv}</b><small>Ranged</small></div>
            <div><span>🧙</span><b>Lv ${magLv}</b><small>Magic</small></div>
          </div>
        </div>
        <div class="mp-pane">
          <h4>Forecast</h4>
          <div class="mp-forecast">
            <div><span>DPS</span><b>${est.dps.toFixed(1)}</b></div>
            <div><span>Hit chance</span><b>${Math.round(est.hitChance*100)}%</b></div>
            <div><span>Damage</span><b>${est.minHit}–${est.maxHit}</b></div>
            <div><span>Time to kill</span><b>${est.killTimeS.toFixed(1)}s</b></div>
            <div><span>Kills / hr</span><b>${fmtNum(est.killsHr)}</b></div>
            <div><span>XP / hr</span><b>${fmtNum(est.xpHr)}</b></div>
          </div>
        </div>
      </div>

      <div class="mp-pane mp-loot-pane">
        <h4>Loot Table (${(m.drops||[]).length})</h4>
        <div class="mp-loot-grid">${(m.drops||[]).map(lootRowHtml).join('') || '<div class="mp-empty">No drops.</div>'}</div>
      </div>

      <div class="mp-footer">
        <div class="mp-food">
          <div class="mp-food-icon">${foodIcon}</div>
          <div class="mp-food-info">
            <div class="mp-food-name">${foodName}</div>
            <div class="mp-food-qty">${foodCount} in pack</div>
          </div>
        </div>
        <div class="mp-actions">
          <button class="mp-btn mp-btn-secondary" data-act="close">Leave</button>
          <button class="mp-btn mp-btn-primary" data-act="fight" data-monster="${monsterId}">⚔️  Fight</button>
        </div>
      </div>
    `;

    modal.querySelector('.mp-close').addEventListener('click', closePreview);
    modal.querySelectorAll('[data-act=close]').forEach(function(b){ b.addEventListener('click', closePreview); });
    modal.querySelector('[data-act=fight]').addEventListener('click', function(){
      var id = this.dataset.monster;
      closePreview();
      if(typeof window.startCombat === 'function') window.startCombat(id);
    });

    ov.classList.add('open');
  }
  window.openMobPreview = renderPreview;

  // ── Wire monster row clicks to open the preview instead of starting
  //    combat directly. Walks .monster-row in #panel-combat after every
  //    render and replaces the inline onclick. ──
  function rewireRows(){
    var rows = document.querySelectorAll('#panel-combat .monster-row');
    rows.forEach(function(row){
      if(row.__previewWired) return;
      var oc = row.getAttribute('onclick') || '';
      var m = oc.match(/startCombat\(['"]([^'"]+)['"]\)/);
      if(!m) return;
      var id = m[1];
      row.setAttribute('onclick', '');
      row.addEventListener('click', function(e){
        e.preventDefault(); e.stopPropagation();
        // If currently fighting THIS monster, click stops it. Otherwise preview.
        if(window.G && window.G.activeMonster === id){
          if(typeof window.stopCombat === 'function') window.stopCombat();
          return;
        }
        renderPreview(id);
      });
      row.__previewWired = true;
    });
  }
  // Re-wire whenever renderMonsterList runs
  var origRender = window.renderMonsterList;
  if(typeof origRender === 'function'){
    window.renderMonsterList = function(){
      var r = origRender.apply(this, arguments);
      setTimeout(rewireRows, 0);
      return r;
    };
  }
  // Also re-wire on tab change to combat
  var origShowTab = window.showTab;
  if(typeof origShowTab === 'function'){
    window.showTab = function(tab){
      var r = origShowTab.apply(this, arguments);
      if(tab === 'combat') setTimeout(rewireRows, 60);
      return r;
    };
  }
  // Initial wire after a short delay
  setTimeout(rewireRows, 1000);

  // Esc to close
  document.addEventListener('keydown', function(e){
    if(e.key === 'Escape') closePreview();
  });

  console.log('Combat preview: loaded');
})();

// ===== block 8: script-8 =====
"use strict";
/* ════════════════════════════════════════════════════════════
   ACTIVE EFFECTS panel — Profile
   Inserted as a new card after the existing Profile panel content.
   Renders live: food buffs (with mm:ss countdown), house bonuses
   (read from getBonus if present), Phase B placeholders for clan.
   ════════════════════════════════════════════════════════════ */

(function injectActiveEffectsCard(){
  if(document.getElementById('active-effects-card')) return;
  const profile = document.getElementById('panel-profile');
  if(!profile) return;
  const card = document.createElement('div');
  card.className = 'card';
  card.id = 'active-effects-card';
  card.style.gridArea = 'auto';
  card.innerHTML = `
    <div class="card-head">
      <div class="card-title">Active Effects</div>
      <span class="card-sub" id="aef-sub">Live</span>
    </div>
    <div class="card-body eff-panel" id="aef-body"></div>`;
  /* Append at the end of the profile grid so it flows alongside the existing cards */
  profile.appendChild(card);

  /* Sprinkle a sensible grid placement: ensure existing 5-card layout still works
     by adding aef as a 6th cell — let CSS auto-flow handle it on smaller widths. */
})();

function _formatBuffKindLabel(kind){
  const map = {
    'allXP':'all XP','combatXP':'combat XP','hearthXP':'hearth XP',
    'cookSpeed':'cook speed','smithSpeed':'smith speed','gatherSpeed':'gather speed',
    'kitDrop':'kit drop','craftSave':'craft save','farmYield':'farm yield',
    'farmYieldPct':'bumper crops','noBurn':'no-burn','storage':'storage',
  };
  return map[kind] || kind.replace(/([A-Z])/g,' $1').toLowerCase();
}

function renderActiveEffects(){
  const el = document.getElementById('aef-body');
  if(!el) return;
  const out = [];

  /* 1. Food buffs — always emit the heading + a host div that the
     buff-queue feature (Phase A.2) populates. If that feature isn't
     loaded, we fall back to rendering legacy {id,expiresAt} buffs here. */
  out.push('<div class="eff-section-h">Food Buffs</div>');
  const hasNewBuffSystem = typeof window.__renderBuffsSection === 'function';
  if(hasNewBuffSystem){
    out.push('<div id="food-buffs-host" data-managed-by="buff-queue"></div>');
  } else {
    const foods = (Array.isArray(G.buffs) ? G.buffs : []).slice();
    if(typeof pruneBuffs === 'function') pruneBuffs();
    if(foods.length){
      foods.forEach(b=>{
        const def = (typeof BUFFS_DEF !== 'undefined') ? BUFFS_DEF[b.id] : null;
        if(!def) return;
        const remain = Math.max(0, Math.ceil((b.expiresAt - Date.now())/1000));
        const m = Math.floor(remain/60), s = remain%60;
        out.push(`<div class="eff-row">
          <div class="eicon">${def.icon}</div>
          <div><b>${def.name}</b><div class="eff-effect">+${Math.round(def.value*100)}% ${_formatBuffKindLabel(def.kind)}</div></div>
          <div class="eff-time">${m}:${s.toString().padStart(2,'0')}</div>
        </div>`);
      });
    } else {
      out.push('<div class="eff-empty">No food buffs active. Cook buff foods to add bonuses.</div>');
    }
  }

  /* 2. House buffs (if getBonus exists) */
  out.push('<div class="eff-section-h">House Buffs</div>');
  if(typeof getBonus === 'function'){
    const keys = ['cookSpeed','smithSpeed','allXP','combatXP','hearthXP','kitDrop','craftSave','gatherSpeed','farmYield','farmYieldPct','noBurn','storage'];
    // Use the same icons as BUFFS_DEF where they overlap, so food and
    // house bonuses display consistent symbols. Avoid 📚/📊/📦 — they
    // render as low-contrast multicolor blocks in Segoe UI Emoji.
    const houseIcons = {cookSpeed:'🍳',smithSpeed:'🔨',allXP:'⭐',combatXP:'⚔️',hearthXP:'🕯️',kitDrop:'🍀',craftSave:'🧵',gatherSpeed:'🌿',farmYield:'🌾',farmYieldPct:'🎃',noBurn:'🔥',storage:'🧰'};
    let any = false;
    keys.forEach(k=>{
      const v = getBonus(k);
      if(!v) return;
      any = true;
      const isFlat = (k === 'farmYield' || k === 'storage');
      const display = isFlat ? `+${v}` : `+${Math.round(v*100)}%`;
      out.push(`<div class="eff-row house">
        <div class="eicon">${houseIcons[k]||'⭐'}</div>
        <div><b>${_formatBuffKindLabel(k).replace(/^./,c=>c.toUpperCase())}</b><div class="eff-effect">${display}</div></div>
        <div class="eff-time">House</div>
      </div>`);
    });
    if(!any){
      out.push('<div class="eff-empty">No house buffs yet. Build rooms to unlock account-wide bonuses.</div>');
    }
  } else {
    out.push('<div class="eff-empty">No house buffs yet.</div>');
  }

  /* 3. Clan placeholder — only show this section once clans actually ship.
     Until then, the row was just exposing work-in-progress to players. */
  if(window.__clansEnabled){
    out.push('<div class="eff-section-h">Clan Buffs</div>');
    const cb = window.getClanBlessing && window.getClanBlessing();
    if(cb){
      out.push(`<div class="eff-row">
        <div class="eicon">🛡️</div>
        <div><b>${cb.name}</b><div class="eff-effect">${cb.effect}</div></div>
        <div class="eff-time">${cb.expiresLabel || 'Active'}</div>
      </div>`);
    } else {
      out.push('<div class="eff-empty">Join a clan to receive blessings.</div>');
    }
  }

  el.innerHTML = out.join('');
}

/* Re-render on a tick so buff timers count down live.
   IMPORTANT: don't wipe innerHTML every second — that causes the entire
   Active Effects panel to flicker. Instead, find the existing timer
   elements and just update their text. Full re-render only fires when
   buffs are added/removed/expired (handled by applyBuff/pruneBuffs). */
setInterval(()=>{
  if(!document.getElementById('panel-profile')?.classList.contains('active')) return;
  // Update food-buff timers (managed by buff-queue feature)
  if(typeof window.refreshBuffTimers === 'function'){
    window.refreshBuffTimers();
  }
  // Legacy fallback: update .eff-time spans if any pre-buff-queue rows exist
  const rows = document.querySelectorAll('#aef-body .eff-row:not(.house) .eff-time');
  rows.forEach(function(t){
    // Only touch rows that have a mm:ss countdown — leave "House"/"—" alone
    if(/^\d+:\d{2}$/.test(t.textContent)){
      // find the parent row; we don't have an idx mapping here so just
      // decrement by 1s. If something resets this we'll re-render full panel.
      const m = t.textContent.match(/^(\d+):(\d{2})$/);
      if(m){
        let total = parseInt(m[1],10)*60 + parseInt(m[2],10) - 1;
        if(total < 0) total = 0;
        const mm = Math.floor(total/60);
        const ss = total%60;
        t.textContent = mm+':'+String(ss).padStart(2,'0');
      }
    }
  });
}, 1000);

