/* ─── DOM walkers — replace emoji with <img> after each render ─── */
function paintSkillIcons(){
  document.querySelectorAll('.skill-tile, .skill-card').forEach(function(el){
    var oc = el.getAttribute('onclick') || '';
    var m = oc.match(/openSkillDetail\('([^']+)'\)/) || oc.match(/showSkill\('([^']+)'\)/);
    if(!m) return;
    var sk = m[1];
    var path = window._skillIcon[sk];
    if(!path) return;
    var iconEl = el.querySelector('.sicon, .icon');
    if(!iconEl) return;
    if(iconEl.querySelector('.poneti-skill-img')) return;
    iconEl.innerHTML = '<img src="' + path + '" class="poneti-skill-img" alt="" loading="lazy" />';
  });
}
function paintMonsterIcons(){
  document.querySelectorAll('.monster-row').forEach(function(el){
    var oc = el.getAttribute('onclick') || '';
    var m = oc.match(/startCombat\('([^']+)'\)/) || oc.match(/openMonster\('([^']+)'\)/);
    if(!m) return;
    var id = m[1];
    var path = window._monsterIcon[id];
    if(!path) return;
    var iconEl = el.querySelector('.mi');
    if(!iconEl) return;
    if(iconEl.querySelector('.poneti-mon-img')) return;
    iconEl.innerHTML = '<img src="' + path + '" class="poneti-mon-img" alt="" loading="lazy" />';
  });
}
function paintAll(){ paintSkillIcons(); paintMonsterIcons(); }

/* Hook common renderers */
['renderSkills','renderMonsterList','renderProfile','showTab','renderInvNew','renderCombat','renderLoadout'].forEach(function(name){
  var orig = window[name];
  if(typeof orig !== 'function') return;
  window[name] = function(){
    var r = orig.apply(this, arguments);
    setTimeout(paintAll, 0);
    return r;
  };
});
setTimeout(paintAll, 200);
setTimeout(paintAll, 800);
document.addEventListener('click', function(){ setTimeout(paintAll, 50); });

/* ─── Empty-state acquisition popover ─── */
function buildOverlay(){
  if(document.getElementById('acq-overlay')) return;
  var ov = document.createElement('div');
  ov.id = 'acq-overlay';
  ov.className = 'acq-overlay';
  ov.innerHTML = '<div class="acq-modal" onclick="event.stopPropagation()">' +
    '<h3 id="acq-title">How to get this</h3>' +
    '<p id="acq-desc"></p>' +
    '<div class="acq-paths" id="acq-paths"></div>' +
    '<button class="acq-close" onclick="hideAcquisitionTip()">Close</button>' +
    '</div>';
  ov.addEventListener('click', hideAcquisitionTip);
  document.body.appendChild(ov);
}
window.hideAcquisitionTip = function(){
  var ov = document.getElementById('acq-overlay');
  if(ov) ov.classList.remove('show');
};
window.showAcquisitionTip = function(itemId){
  buildOverlay();
  var def = (window.ITEMS && ITEMS[itemId]) || {};
  var name = def.n || itemId;
  document.getElementById('acq-title').textContent = 'How to get ' + name;
  document.getElementById('acq-desc').textContent = 'You don\'t have any. Here\'s how to acquire some:';
  var paths = [];

  /* Shop check */
  if(typeof SEED_SHOP !== 'undefined'){
    var sh = SEED_SHOP.find(function(x){return x.id===itemId;});
    if(sh){
      paths.push({e:'🛒', t:'Buy from Seed Shop', s:'×' + sh.qty + ' for ' + sh.cost + 'g', a:"showTab('store')"});
    }
  }
  if(typeof EQUIP_SHOP !== 'undefined'){
    var eq = EQUIP_SHOP.find(function(x){return x.id===itemId;});
    if(eq){
      paths.push({e:'🛒', t:'Buy from Equipment Shop', s:eq.cost + 'g', a:"showTab('store')"});
    }
  }

  /* Crop / farming */
  if(def.seed && typeof CROPS !== 'undefined'){
    var crop = CROPS[def.seed];
    if(crop){ paths.push({e:'🌾', t:'Plant on a farm plot', s:'Yields ' + crop.prod, a:"showTab('farming')"}); }
  }
  /* Crops are produced by a seed */
  Object.keys((typeof CROPS!=='undefined' ? CROPS : {})).forEach(function(cId){
    if(CROPS[cId].prod === itemId){
      paths.push({e:'🌾', t:'Plant ' + (CROPS[cId].name||cId) + ' seeds', s:'Harvest after ' + CROPS[cId].hours + 'h', a:"showTab('farming')"});
    }
  });

  /* Gathering: woodcutting / mining / fishing */
  [['TREES','woodcutting'],['ROCKS','mining'],['FISH_SPOTS','fishing']].forEach(function(pair){
    var arr = window[pair[0]] || [];
    arr.forEach(function(node){
      if(node.prod === itemId){
        paths.push({e:'⛏️', t:node.name + ' (' + pair[1] + ')', s:'Lv ' + node.req + ' required', a:"showTab('" + pair[1] + "')"});
      }
    });
  });

  /* Mob drop */
  if(typeof MONSTERS !== 'undefined'){
    Object.entries(MONSTERS).forEach(function(kv){
      var mid = kv[0], m = kv[1];
      if((m.drops||[]).some(function(d){return d.id===itemId;})){
        paths.push({e:'⚔️', t:'Drops from ' + m.name, s:'Tier ' + m.tier + ' monster', a:"showTab('combat');startCombat('" + mid + "')"});
      }
    });
  }

  if(paths.length === 0){
    paths.push({e:'❓', t:'No known sources', s:'This item may be quest-locked or removed', a:''});
  }

  document.getElementById('acq-paths').innerHTML = paths.slice(0,6).map(function(p){
    return '<div class="acq-path" onclick="hideAcquisitionTip();' + p.a + '">' +
      '<span class="acq-emoji">' + p.e + '</span>' +
      '<div class="acq-text"><b>' + p.t + '</b><span>' + p.s + '</span></div>' +
    '</div>';
  }).join('');

  document.getElementById('acq-overlay').classList.add('show');
};

/* Wire popover for empty inventory items via click delegation */
document.addEventListener('click', function(e){
  var el = e.target.closest('[data-empty-acq]');
  if(!el) return;
  e.preventDefault(); e.stopPropagation();
  window.showAcquisitionTip(el.getAttribute('data-empty-acq'));
}, true);

/* Wrap invItemTap so a click on a 0-qty item shows the acquisition tip */
(function(){
  var orig = window.invItemTap;
  if(typeof orig !== 'function') return;
  window.invItemTap = function(id){
    var qty = (G && G.inventory && G.inventory[id]) || 0;
    if(qty <= 0){ window.showAcquisitionTip(id); return; }
    return orig.apply(this, arguments);
  };
})();

console.log('Poneti v2 loaded:', Object.keys(window._skillIcon).length, 'skills,', Object.keys(window._monsterIcon).length, 'monsters,', Object.keys(window._itemPath).length, 'items total');
