/* ─── Artisan render: replaces 'Train by fighting' empty state ─── */
window.renderArtisanActivities = function(skillId){
  var recipes = window.ARTISAN_RECIPES[skillId];
  if(!recipes || typeof getLevel !== 'function') return '';
  var lv = getLevel(skillId);
  return recipes.map(function(r){
    var have = (G.inventory && G.inventory[r.input]) || 0;
    var unlocked = lv >= r.req;
    var canDo = unlocked && have > 0;
    var active = G.activeSkill===skillId && G.skillTargetId===r.id;
    var inputName = (typeof ITEMS!=='undefined' && ITEMS[r.input]) ? ITEMS[r.input].n : r.input;
    var outputLabel = r.output && typeof ITEMS!=='undefined' && ITEMS[r.output] ? ITEMS[r.output].n : (r.output||'XP only');
    var status = '';
    if(!unlocked) status = '<span class="muted tiny">🔒 Lv '+r.req+'</span>';
    else if(!have) status = '<span class="muted tiny">Need '+inputName+'</span>';
    else if(active) status = '<span style="color:var(--green);font-weight:700;font-size:11px">●ACTIVE</span>';
    var secondaryText = '';
    if(r.secondary){
      secondaryText = ' + ' + Object.entries(r.secondary).map(function(kv){
        var nm = (ITEMS[kv[0]]&&ITEMS[kv[0]].n)||kv[0];
        return kv[1]+'×'+nm;
      }).join(', ');
    }
    return '<button class="monster-row '+(active?'fighting':'')+'" '+(canDo?'':'disabled')+' onclick="'+(active?'stopSkill()':"window.startArtisan('"+skillId+"','"+r.id+"')")+'">'+
      '<span class="mi">'+r.icon+'</span>'+
      '<div style="flex:1;min-width:0"><span class="mn">'+r.name+'</span><span class="ms">Lv '+r.req+' · '+r.xp+' XP · ('+inputName+secondaryText+(r.output?' → '+outputLabel:'')+') · Have: '+have+'</span></div>'+
      status+
    '</button>';
  }).join('');
};

/* ─── Artisan action loop (mirrors startSkill but consumes inputs) ─── */
window.startArtisan = function(skillId, recipeId){
  var recipes = window.ARTISAN_RECIPES[skillId];
  if(!recipes) return;
  var r = recipes.find(function(x){return x.id===recipeId;});
  if(!r) return;
  if(getLevel(skillId) < r.req){ if(typeof notify==='function') notify('Need Lv '+r.req+' '+skillId,'kill'); return; }
  if(!(G.inventory[r.input] > 0)){ if(typeof notify==='function') notify('No '+(ITEMS[r.input]?.n||r.input),'kill'); return; }
  if(typeof stopSkill === 'function') stopSkill();
  G.activeSkill = skillId; G.skillTargetId = recipeId; G.skillProgress = 0; G.skillMs = r.ms;
  var bonusKey = (skillId==='cooking') ? 'cookSpeed' : (skillId==='smithing' ? 'smithSpeed' : 'gatherSpeed');
  var speed = (typeof getBonus==='function') ? getBonus(bonusKey) : 0;
  var actualMs = Math.max(500, Math.floor(r.ms * (1 - speed)));
  window._artisanInterval = setInterval(function(){ doArtisanAction(skillId, recipeId); }, actualMs);
  window._artisanProgress = setInterval(function(){
    G.skillProgress = Math.min(1, G.skillProgress + (100/actualMs));
    if(typeof activeTab !== 'undefined' && activeTab==='skills' && typeof renderSkillDetail==='function') renderSkillDetail(skillId);
  }, 100);
  if(typeof renderSkillsList==='function') renderSkillsList();
  if(typeof renderSkillDetail==='function') renderSkillDetail(skillId);
};

window.doArtisanAction = function(skillId, recipeId){
  var recipes = window.ARTISAN_RECIPES[skillId];
  var r = recipes && recipes.find(function(x){return x.id===recipeId;});
  if(!r) return;
  /* Out of input or secondary? Stop. */
  if(!(G.inventory[r.input] > 0)){ window._stopArtisan(); return; }
  if(r.secondary){
    var oot = false;
    Object.entries(r.secondary).forEach(function(kv){ if((G.inventory[kv[0]]||0) < kv[1]) oot = true; });
    if(oot){ window._stopArtisan(); if(typeof notify==='function') notify('Out of secondary materials','kill'); return; }
  }
  /* Consume */
  if(typeof removeItem==='function') removeItem(r.input, 1);
  if(r.secondary) Object.entries(r.secondary).forEach(function(kv){ removeItem(kv[0], kv[1]); });
  /* Produce */
  if(r.output && typeof addItem==='function') addItem(r.output, 1);
  /* XP */
  if(typeof addXp==='function') addXp(skillId, r.xp);
  /* Counters */
  if(skillId==='cooking'){
    G.stats.cooked = (G.stats.cooked||0) + 1;
    if(typeof updateDaily==='function') updateDaily('cooked', 1);
  }
  if(skillId==='smithing'){
    G.stats.refined = (G.stats.refined||0) + 1;
    G.stats.smithed = (G.stats.smithed||0) + 1;
    if(typeof updateDaily==='function') updateDaily('smithed', 1);
  }
  if(skillId==='crafting'){
    G.stats.refined = (G.stats.refined||0) + 1;
    G.stats.crafted = (G.stats.crafted||0) + 1;
    if(typeof updateDaily==='function') updateDaily('crafted', 1);
  }
  if(typeof renderSkillDetail==='function') renderSkillDetail(skillId);
  if(typeof updateTopbar==='function') updateTopbar();
};

/* Hook into existing stopSkill so we also clear artisan intervals */
window._stopArtisan = function(){
  if(window._artisanInterval){ clearInterval(window._artisanInterval); window._artisanInterval=null; }
  if(window._artisanProgress){ clearInterval(window._artisanProgress); window._artisanProgress=null; }
};
(function(){
  var origStop = window.stopSkill;
  if(typeof origStop !== 'function') return;
  window.stopSkill = function(){
    window._stopArtisan();
    return origStop.apply(this, arguments);
  };
})();

/* ─── Daily gold-today tracking ─── */
(function(){
  if(typeof G !== 'object' || !G) return;
  function todayKey(){ var d=new Date(); return d.getUTCFullYear()*10000+(d.getUTCMonth()+1)*100+d.getUTCDate(); }
  function checkDailyGold(){
    if(typeof G !== 'object') return;
    var today = todayKey();
    if(!G.dailyGoldStart || G.dailyGoldStart.day !== today){
      G.dailyGoldStart = {day: today, gold: G.gold||0};
    }
  }
  setTimeout(checkDailyGold, 200);
  setInterval(checkDailyGold, 60000);
})();

