function applyCharExtensions(){
  var host = document.getElementById('panel-character');
  if(!host) return;

  /* 1. Current Activity card — pin at top */
  var existing = host.querySelector('.char-active-card');
  if(existing) existing.remove();
  var activity = buildActivityCard();
  if(activity){
    host.insertBefore(activity, host.firstChild);
  }

  /* 2. Paper-doll loadout — replace the old eq-strip if present, or add fresh */
  var oldStrip = host.querySelector('.eq-strip');
  if(oldStrip){
    var newDoll = buildLoadoutDoll();
    oldStrip.parentNode.replaceChild(newDoll, oldStrip);
  } else if(!host.querySelector('.char-loadout')){
    var doll = buildLoadoutDoll();
    /* Find the Combat Stats card and insert after */
    var statsCards = host.querySelectorAll('.char-section');
    if(statsCards.length){
      var card = document.createElement('div');
      card.className = 'card char-section';
      card.innerHTML = '<h3>Equipped Loadout</h3>';
      card.appendChild(doll);
      statsCards[0].parentNode.insertBefore(card, statsCards[0].nextSibling);
    }
  }

  /* 3. Patch existing skill cards to use new calc (fixing Magic bug) */
  host.querySelectorAll('.char-skill-card').forEach(function(card){
    var onclick = card.getAttribute('onclick') || '';
    var m = onclick.match(/openSkillDetail\('([^']+)'\)|showTab\('combat'\)/);
    /* extract skill from name text */
    var nameEl = card.querySelector('.csk-name');
    if(!nameEl) return;
    var skText = nameEl.textContent;
    /* Find skill by name match */
    var skill = null;
    if(typeof SKILLS_DEF !== 'undefined'){
      Object.keys(SKILLS_DEF).forEach(function(s){
        if(skText.indexOf(SKILLS_DEF[s].name) >= 0) skill = s;
      });
    }
    if(!skill) return;
    var calc = window._calcForSkill(skill);
    var rateEl = card.querySelector('.csk-rate');
    if(!rateEl || !calc) return;
    if(calc.kind === 'gather'){
      rateEl.classList.remove('idle');
      rateEl.innerHTML = '<span><b>'+calc.xpHr.toLocaleString()+'</b> XP/hr</span>'+
                         '<span><b>'+calc.itemHr+'</b> '+calc.prodName+'/hr</span>';
    } else if(calc.kind === 'combat'){
      rateEl.classList.remove('idle');
      rateEl.innerHTML = '<span><b>'+calc.xpHr.toLocaleString()+'</b> XP/hr</span>'+
                         '<span>vs '+calc.monsterName+' · '+calc.killsHr+' kills/hr</span>';
    }
  });
}

function buildActivityCard(){
  var card = document.createElement('div');
  /* Combat */
  if(G.activeMonster && typeof MONSTERS !== 'undefined'){
    var m = MONSTERS[G.activeMonster];
    var path = window._monsterIcon && window._monsterIcon[G.activeMonster];
    var icon = path ? '<img src="'+path+'" />' : (m.icon||'⚔️');
    card.className = 'char-active-card';
    card.innerHTML = '<div class="ca-icon">'+icon+'</div>'+
      '<div class="ca-info"><b>Fighting '+m.name+'</b><span>HP: '+G.monsterHp+' / '+m.hp+' · '+m.xp+' XP per kill</span></div>'+
      '<button class="ca-stop" onclick="stopCombat()">Stop</button>';
    return card;
  }
  /* Active gathering / artisan */
  if(G.activeSkill && G.skillTargetId){
    var nodeName = '';
    var iconHtml = '⏳';
    if(typeof TREES!=='undefined'){
      var n = TREES.find(function(a){return a.id===G.skillTargetId;});
      if(n){ nodeName = n.name; iconHtml = n.icon; }
    }
    if(!nodeName && typeof ROCKS!=='undefined'){
      var n = ROCKS.find(function(a){return a.id===G.skillTargetId;});
      if(n){ nodeName = n.name; iconHtml = n.icon; }
    }
    if(!nodeName && typeof FISH_SPOTS!=='undefined'){
      var n = FISH_SPOTS.find(function(a){return a.id===G.skillTargetId;});
      if(n){ nodeName = n.name; iconHtml = n.icon; }
    }
    if(!nodeName && typeof window.ARTISAN_RECIPES !== 'undefined'){
      Object.keys(window.ARTISAN_RECIPES).forEach(function(s){
        var r = window.ARTISAN_RECIPES[s].find(function(x){return x.id===G.skillTargetId;});
        if(r){ nodeName = r.name; iconHtml = r.icon; }
      });
    }
    var skName = (typeof SKILLS_DEF!=='undefined' && SKILLS_DEF[G.activeSkill]) ? SKILLS_DEF[G.activeSkill].name : G.activeSkill;
    card.className = 'char-active-card';
    card.innerHTML = '<div class="ca-icon">'+iconHtml+'</div>'+
      '<div class="ca-info"><b>'+skName+': '+nodeName+'</b><span>Auto-progresses · click stop to switch</span></div>'+
      '<button class="ca-stop" onclick="stopSkill()">Stop</button>';
    return card;
  }
  /* Idle */
  card.className = 'char-active-card idle';
  card.innerHTML = '<div class="ca-icon">😴</div>'+
    '<div class="ca-info"><b>Idle</b><span>Pick a skill or monster to begin training</span></div>';
  return card;
}

function buildLoadoutDoll(){
  var div = document.createElement('div');
  div.className = 'char-loadout';
  var slots = (typeof EQUIP_SLOTS !== 'undefined') ? EQUIP_SLOTS : [];
  var meta = (typeof EQUIP_SLOT_META !== 'undefined') ? EQUIP_SLOT_META : {};
  slots.forEach(function(s){
    var id = G.equipment ? G.equipment[s] : null;
    var def = id && (typeof ITEMS!=='undefined') ? ITEMS[id] : null;
    var path = id && window._itemPath && window._itemPath[id];
    var slotEl = document.createElement('div');
    slotEl.className = 'eq-slot' + (def?'':' empty');
    slotEl.title = def ? def.n+' (click to unequip)' : (meta[s]?.label||s);
    slotEl.onclick = function(){ if(def && typeof unequip==='function') unequip(s); };
    if(def && path){
      slotEl.innerHTML = '<img src="'+path+'" alt="" /><small>'+(meta[s]?.label||s).slice(0,3)+'</small>';
    } else {
      slotEl.innerHTML = (meta[s]?.icon||'·')+'<small>'+(meta[s]?.label||s).slice(0,3)+'</small>';
    }
    div.appendChild(slotEl);
  });
  return div;
}

