// ===== block 26: dragdrop-js =====
(function(){
"use strict";

/* ─── Helpers ─── */
function getPreferredSlotFromItem(def){
  if(!def) return null;
  if(typeof getPreferredSlot === 'function') return getPreferredSlot(def);
  /* Fallback */
  if(def.slot === 'ring') return G.equipment.ring1 ? 'ring2' : 'ring1';
  return def.slot || (def.type === 'weapon' ? 'weapon' : null);
}
function isSlotCompatible(def, targetSlot){
  if(!def || !targetSlot) return false;
  if(def.slot === targetSlot) return true;
  if(def.slot === 'ring' && (targetSlot === 'ring1' || targetSlot === 'ring2')) return true;
  if(def.type === 'weapon' && targetSlot === 'weapon') return true;
  return false;
}
function equipToSlot(id, targetSlot){
  if(typeof migrateEquipmentSlots === 'function') migrateEquipmentSlots();
  var def = ITEMS[id];
  if(!def) return;
  if(!isSlotCompatible(def, targetSlot)){
    if(typeof notify === 'function') notify('Not compatible with that slot','kill');
    return;
  }
  /* Move existing item back to inventory */
  var old = G.equipment[targetSlot];
  if(old){ G.inventory[old] = (G.inventory[old]||0) + 1; }
  G.equipment[targetSlot] = id;
  if(typeof removeItem === 'function') removeItem(id, 1);
  if(typeof notify === 'function') notify('Equipped '+def.n,'info');
  if(typeof renderInventory === 'function') renderInventory();
  if(typeof renderLoadout === 'function') renderLoadout();
  if(typeof window._renderInvFancy === 'function') window._renderInvFancy();
}
window._equipToSlot = equipToSlot;

/* ─── Wire bag tiles as drag sources ─── */
function makeTileDraggable(tile){
  if(tile.dataset.dragWired === '1') return;
  /* Only wire if explicitly draggable */
  if(tile.getAttribute('draggable') !== 'true') return;
  tile.dataset.dragWired = '1';
  var id = tile.dataset.itemId;
  if(!id) return;
  var def = (typeof ITEMS!=='undefined') ? ITEMS[id] : null;
  if(!def) return;
  tile.addEventListener('dragstart', function(e){
    e.dataTransfer.setData('text/plain', id);
    e.dataTransfer.effectAllowed = 'move';
    tile.classList.add('dragging');
    /* Highlight valid drop targets */
    document.querySelectorAll('.td-slot').forEach(function(slot){
      var slotName = slot.className.match(/td-([a-z0-9]+)/i);
      if(!slotName) return;
      var t = slotName[1];
      /* Skip the doll classname stem itself */
      if(t === 'doll' || t === 'slot') return;
      /* Find specific slot via class list */
      var slotKey = null;
      ['helmet','necklace','earrings','cape','weapon','ammo','ring1','body','ring2','gloves','belt','pants','boots','companion'].forEach(function(s){
        if(slot.classList.contains('td-'+s)) slotKey = s;
      });
      if(slotKey && isSlotCompatible(def, slotKey)){
        slot.classList.add('drop-target');
      } else if(slotKey){
        slot.classList.add('drop-invalid');
      }
    });
  });
  tile.addEventListener('dragend', function(){
    tile.classList.remove('dragging');
    document.querySelectorAll('.td-slot').forEach(function(slot){
      slot.classList.remove('drop-target','drop-invalid','drop-hover');
    });
    document.querySelectorAll('.invc-bag-col').forEach(function(c){
      c.classList.remove('drop-target');
    });
  });
}

/* ─── Wire equipment slots as drop targets ─── */
function makeSlotDroppable(slot){
  if(slot.dataset.dropWired === '1') return;
  slot.dataset.dropWired = '1';
  /* Find slot key from class list */
  var slotKey = null;
  ['helmet','necklace','earrings','cape','weapon','ammo','ring1','body','ring2','gloves','belt','pants','boots','companion'].forEach(function(s){
    if(slot.classList.contains('td-'+s)) slotKey = s;
  });
  if(!slotKey) return;

  slot.addEventListener('dragover', function(e){
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    if(slot.classList.contains('drop-target')) slot.classList.add('drop-hover');
  });
  slot.addEventListener('dragleave', function(){
    slot.classList.remove('drop-hover');
  });
  slot.addEventListener('drop', function(e){
    e.preventDefault();
    var id = e.dataTransfer.getData('text/plain');
    if(!id) return;
    equipToSlot(id, slotKey);
  });

  /* Also make the slot itself a drag SOURCE if it has an item — drag to bag = unequip */
  var equippedId = G.equipment ? G.equipment[slotKey] : null;
  if(equippedId){
    slot.setAttribute('draggable','true');
    slot.addEventListener('dragstart', function(e){
      e.dataTransfer.setData('text/unequip', slotKey);
      e.dataTransfer.effectAllowed = 'move';
      /* Highlight bag as valid drop */
      document.querySelectorAll('.invc-bag-col').forEach(function(c){
        c.classList.add('drop-target');
      });
    });
  }
}

/* ─── Wire bag column as drop target for unequip ─── */
function makeBagDroppable(bagCol){
  if(bagCol.dataset.dropWired === '1') return;
  bagCol.dataset.dropWired = '1';
  bagCol.addEventListener('dragover', function(e){
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  });
  bagCol.addEventListener('drop', function(e){
    e.preventDefault();
    var slotKey = e.dataTransfer.getData('text/unequip');
    if(slotKey && typeof unequip === 'function'){
      unequip(slotKey);
      if(typeof window._renderInvFancy === 'function') window._renderInvFancy();
    }
  });
}

/* ─── Apply wiring after every inventory render ─── */
function wireDragDrop(){
  document.querySelectorAll('.invc-tile').forEach(makeTileDraggable);
  document.querySelectorAll('.td-slot').forEach(makeSlotDroppable);
  document.querySelectorAll('.invc-bag-col').forEach(makeBagDroppable);
}
window._wireDragDrop = wireDragDrop;

/* Hook into the render */
(function(){
  var orig = window._renderInvFancy;
  if(typeof orig === 'function'){
    window._renderInvFancy = function(){
      var r = orig.apply(this, arguments);
      setTimeout(wireDragDrop, 30);
      return r;
    };
  }
})();

setTimeout(wireDragDrop, 600);

/* Also re-wire on any tab switch back to inventory */
(function(){
  var origST = window.showTab;
  if(typeof origST === 'function'){
    window.showTab = function(t){
      var r = origST.apply(this, arguments);
      if(t === 'inventory') setTimeout(wireDragDrop, 150);
      return r;
    };
  }
})();

})(); // ← close outer IIFE for drag-drop block

// ===== block 27: activities-grid-js =====
(function(){
"use strict";

function fmtSec(ms){return (ms/1000).toFixed(1)+'s';}
function fmtQty(n){
  n = n || 0;
  if(n>=1000000) return (n/1000000).toFixed(1).replace('.0','')+'M';
  if(n>=1000) return (n/1000).toFixed(1).replace('.0','')+'K';
  return String(n);
}

function actIconHtml(prod, fallbackEmoji){
  var path = prod && window._itemPath && window._itemPath[prod];
  if(path) return '<img src="'+path+'" alt="" loading="lazy" draggable="false" />';
  return '<span class="at-emoji">'+(fallbackEmoji||'❓')+'</span>';
}

/* ── Patch the Skills list (left card) to filter out combat ── */
function patchSkillsList(){
  if(typeof renderSkillsList !== 'function') return;
  window.renderSkillsList = function(){
    var el = document.getElementById('skills-list');
    if(!el) return;
    var cats = {gather:'Gathering', artisan:'Artisan'};
    var html = Object.entries(cats).map(function(pair){
      var cat = pair[0], label = pair[1];
      var skills = Object.entries(SKILLS_DEF).filter(function(kv){return kv[1].cat===cat;});
      var rows = skills.map(function(kv){
        var id = kv[0], s = kv[1];
        var xp = G.skills[id]||0, lv = getLevel(id), pct = Math.floor(xpPct(xp)*100);
        var active = G.activeSkill===id ? 'active' : '';
        var iconHtml = (window._skillIcon && window._skillIcon[id])
          ? '<img src="'+window._skillIcon[id]+'" alt="" loading="lazy" />'
          : '<span class="sicon">'+s.icon+'</span>';
        return '<button class="skill-tile '+active+'" onclick="openSkillDetail(\''+id+'\')">'
          +iconHtml
          +'<span class="slv">Lv '+lv+'</span>'
          +'<div class="bar xp"><i style="width:'+pct+'%"></i></div>'
          +'<span class="snm">'+s.name+'</span>'
          +'</button>';
      }).join('');
      return '<div class="muted tiny" style="text-transform:uppercase;letter-spacing:.08em;margin:8px 0 5px;font-weight:700">'+label+'</div>'
        +'<div class="skill-board">'+rows+'</div>';
    }).join('');
    el.innerHTML = html;

    var card = el.closest('.card');
    if(card){
      var title = card.querySelector('.card-title');
      if(title) title.textContent = 'Activities';
    }
  };
}

/* ── Build a gather tile ── */
function tileForGather(action, skillId){
  var lv = getLevel(skillId);
  var unlocked = lv >= action.req;
  var active = G.activeSkill===skillId && G.skillTargetId===action.id;
  var qty = (G.inventory && G.inventory[action.prod]) || 0;
  var speed = (typeof getBonus==='function') ? getBonus('gatherSpeed') : 0;
  var ms = Math.max(500, Math.floor(action.ms*(1-speed)));
  var click = active
    ? "stopSkill()"
    : (unlocked ? "startSkill('"+skillId+"','"+action.id+"',"+action.ms+")" : "");
  var qtyClass = qty>0 ? 'at-qty' : 'at-qty muted';
  return '<div class="act-tile '+(unlocked?'':'locked')+' '+(active?'active':'')+'" '
    +'data-prod="'+action.prod+'" '
    +'onclick="'+click+'" '
    +'title="'+(action.name||'').replace(/"/g,'&quot;')+'">'
    +(active ? '<span class="at-stop">Active · click to stop</span>' : '')
    +'<div class="at-name">'+(action.name||action.id)+'</div>'
    +'<div class="at-meta">Level requirement: <b>'+action.req+'</b></div>'
    +'<div class="at-meta">'+action.xp+' XP / '+fmtSec(ms)+'</div>'
    +'<div class="at-icon">'+actIconHtml(action.prod, action.icon)+'</div>'
    +'<div class="'+qtyClass+'">Qty: '+fmtQty(qty)+'</div>'
    +(unlocked ? '<div class="at-prog"><div class="at-prog-fill"></div></div>' : '')
    +'</div>';
}

/* ── Build an artisan tile ── */
function tileForArtisan(recipe, skillId){
  var lv = getLevel(skillId);
  var unlocked = lv >= recipe.req;
  var active = G.activeArtisanRecipe === recipe.id;
  var outId = recipe.output;
  var outDef = ITEMS[outId];
  var qty = (G.inventory && G.inventory[outId]) || 0;
  /* stopSkill is wrapped to also clear artisan intervals (line 7382) */
  var click = active
    ? "stopSkill()"
    : (unlocked ? "window.startArtisan('"+skillId+"','"+recipe.id+"')" : "");
  var inputs = recipe.inputs || (recipe.input ? (function(){var o={};o[recipe.input]=recipe.inputQty||1;return o;})() : {});
  var inputsLine = Object.entries(inputs).map(function(kv){
    var d = ITEMS[kv[0]]; return (kv[1]>1?kv[1]+'x ':'')+(d?d.n.split(' ')[0]:kv[0]);
  }).join(' + ');
  var qtyClass = qty>0 ? 'at-qty' : 'at-qty muted';
  return '<div class="act-tile '+(unlocked?'':'locked')+' '+(active?'active':'')+'" '
    +'data-prod="'+outId+'" '
    +'onclick="'+click+'" '
    +'title="'+(recipe.name||'').replace(/"/g,'&quot;')+'">'
    +(active ? '<span class="at-stop">Active · click to stop</span>' : '')
    +'<div class="at-name">'+(recipe.name||recipe.id)+'</div>'
    +'<div class="at-meta">Level requirement: <b>'+recipe.req+'</b></div>'
    +'<div class="at-meta">'+recipe.xp+' XP / '+fmtSec(recipe.ms||3000)+'</div>'
    +'<div class="at-icon">'+actIconHtml(outId, outDef ? outDef.icon : '❓')+'</div>'
    +'<div class="at-meta" style="font-size:10px;opacity:.85">'+inputsLine+'</div>'
    +'<div class="'+qtyClass+'">Qty: '+fmtQty(qty)+'</div>'
    +(unlocked ? '<div class="at-prog"><div class="at-prog-fill"></div></div>' : '')
    +'</div>';
}

function buildHead(skillId){
  var s = SKILLS_DEF[skillId];
  var xp = G.skills[skillId]||0, lv = getLevel(skillId), pct = xpPct(xp)*100, toNext = xpToNext(xp);
  var iconHtml = (window._skillIcon && window._skillIcon[skillId])
    ? '<img src="'+window._skillIcon[skillId]+'" alt="" style="width:36px;height:36px;object-fit:contain;image-rendering:pixelated" />'
    : '<span class="ah-icon">'+s.icon+'</span>';
  return '<div class="act-head">'
    +iconHtml
    +'<div class="ah-meta">'
      +'<div class="ah-row1">'
        +'<span class="ah-name">'+s.name+'</span>'
        +'<span class="ah-lvl">Level: '+lv+'</span>'
      +'</div>'
      +'<div class="ah-xp">Experience: '+xp.toLocaleString()+(lv<99?' / '+(xp+toNext).toLocaleString():' MAX')+'</div>'
      +'<div class="ah-bar"><i style="width:'+pct.toFixed(1)+'%"></i></div>'
    +'</div>'
  +'</div>';
}

window._actLastRender = window._actLastRender || {skillId:null, activeKey:null};

/* Light update: only touches progress bar + qty + xp header; no DOM rebuild. */
function lightUpdate(skillId){
  var detail = document.getElementById('skill-detail');
  if(!detail) return;
  var prog = (typeof G !== 'undefined' && typeof G.skillProgress === 'number') ? G.skillProgress : 0;
  var pctStr = (Math.min(1, Math.max(0, prog)) * 100).toFixed(1) + '%';
  var activeTile = detail.querySelector('.act-tile.active');
  if(activeTile){
    var fill = activeTile.querySelector('.at-prog-fill');
    if(fill) fill.style.width = pctStr;
  }
  var xp = G.skills[skillId]||0, lv = getLevel(skillId), pct = xpPct(xp)*100, toNext = xpToNext(xp);
  var ahLvl = detail.querySelector('.ah-lvl'); if(ahLvl) ahLvl.textContent = 'Level: '+lv;
  var ahXp = detail.querySelector('.ah-xp'); if(ahXp) ahXp.textContent = 'Experience: '+xp.toLocaleString()+(lv<99?' / '+(xp+toNext).toLocaleString():' MAX');
  var ahBar = detail.querySelector('.ah-bar i'); if(ahBar) ahBar.style.width = pct.toFixed(1)+'%';
  detail.querySelectorAll('.act-tile').forEach(function(tile){
    var qe = tile.querySelector('.at-qty');
    var prodId = tile.getAttribute('data-prod');
    if(qe && prodId && G.inventory){
      var q = G.inventory[prodId] || 0;
      qe.textContent = 'Qty: ' + fmtQty(q);
      if(q===0) qe.classList.add('muted'); else qe.classList.remove('muted');
    }
  });
}

function patchSkillDetail(){
  window.renderSkillDetail = function(id){
    if(!id) return;
    var s = SKILLS_DEF[id];
    if(!s) return;
    if(s.cat==='combat'){
      if(typeof showTab==='function') showTab('combat');
      return;
    }

    var activeKey = (G.activeSkill||'')+'|'+(G.skillTargetId||'')+'|'+(G.activeArtisanRecipe||'');
    var detailEl = document.getElementById('skill-detail');
    var alreadyRendered = detailEl && detailEl.querySelector('.act-grid');
    if(alreadyRendered && window._actLastRender.skillId===id && window._actLastRender.activeKey===activeKey){
      lightUpdate(id);
      return;
    }
    window._actLastRender = {skillId:id, activeKey:activeKey};

    var titleEl = document.getElementById('skill-detail-title');
    if(titleEl) titleEl.textContent = s.icon+' '+s.name;

    var head = buildHead(id);
    var tiles = '';
    var count = 0;

    if(id==='woodcutting'){
      tiles = TREES.map(function(a){return tileForGather(a, id);}).join('');
      count = TREES.length;
    } else if(id==='mining'){
      tiles = ROCKS.map(function(a){return tileForGather(a, id);}).join('');
      count = ROCKS.length;
    } else if(id==='fishing'){
      tiles = FISH_SPOTS.map(function(a){return tileForGather(a, id);}).join('');
      count = FISH_SPOTS.length;
    } else if(id==='farming'){
      tiles = '<div class="act-tile" onclick="showTab(\'farming\')" style="grid-column:1/-1">'
        +'<div class="at-name">Open the Farm tab</div>'
        +'<div class="at-meta">Plant and harvest crops on your plots.</div>'
        +'<div class="at-icon"><span class="at-emoji">🌾</span></div>'
        +'</div>';
      count = 1;
    } else if(window.ARTISAN_RECIPES && window.ARTISAN_RECIPES[id]){
      var recipes = window.ARTISAN_RECIPES[id];
      tiles = recipes.map(function(r){return tileForArtisan(r, id);}).join('');
      count = recipes.length;
    } else {
      tiles = '<div class="act-tile" style="grid-column:1/-1"><div class="at-name">No activities</div><div class="at-meta">This skill has no available activities.</div></div>';
      count = 1;
    }

    var cols = 4;
    if(count <= 3) cols = count;
    else if(count <= 4) cols = 4;
    else if(count <= 6) cols = 3;
    else if(count <= 8) cols = 4;
    else if(count <= 10) cols = 5;
    else if(count <= 12) cols = 6;
    else if(count <= 15) cols = 5;
    else cols = 6;

    var grid = '<div class="act-grid" style="grid-template-columns:repeat('+cols+',minmax(0,1fr))">'+tiles+'</div>';

    if(detailEl) detailEl.innerHTML = head + grid;
  };
}

/* Auto-open first non-combat skill when entering Activities tab */
function autoOpenActivity(){
  if(typeof showTab !== 'function') return;
  var origShowTab = showTab;
  window.showTab = function(name){
    var r = origShowTab.apply(this, arguments);
    if(name === 'skills'){
      /* Detect if a skill is already rendered by checking the DOM, not window.openSkill
         (the original `openSkill` is a let-binding and not exposed to window — reading it
         here always returned undefined, causing an infinite re-open loop). */
      var detailEl = document.getElementById('skill-detail');
      var alreadyHasGrid = detailEl && detailEl.querySelector('.act-grid');
      if(!alreadyHasGrid){
        var firstId = Object.keys(SKILLS_DEF).find(function(k){
          return SKILLS_DEF[k].cat==='gather' || SKILLS_DEF[k].cat==='artisan';
        });
        if(firstId && typeof openSkillDetail==='function'){
          setTimeout(function(){openSkillDetail(firstId);}, 30);
        }
      }
    }
    return r;
  };
}

function applyAll(){
  patchSkillsList();
  patchSkillDetail();
  autoOpenActivity();
  if(typeof renderSkillsList==='function') renderSkillsList();
  var card = document.querySelector('#panel-skills .layout-2col-a .card-title');
  if(card) card.textContent = 'Activities';
}

if(document.readyState==='loading'){
  document.addEventListener('DOMContentLoaded', function(){setTimeout(applyAll, 100);});
} else {
  setTimeout(applyAll, 100);
}

console.log('[Activities Grid v1] loaded');
})();

