// ── Runner ──
window.__smokeTest = function(opts){
  opts = opts || {};
  var verbose = opts.verbose !== false;
  var startTab = (typeof activeTab !== 'undefined') ? activeTab : 'profile';
  var results = [];
  var pre = window.__errorLog ? window.__errorLog.length : 0;

  TESTS.forEach(function(test){
    var r = test();
    results.push(r);
    if(verbose){
      var line = r.status==='PASS' ? '✓ ' : (r.status==='WARN' ? '⚠ ' : '✗ ');
      console.log(line + r.name + (r.why ? ' — ' + r.why : ''));
    }
  });

  // Restore tab state
  try { showTab(startTab); } catch(e){}

  var summary = {
    total: results.length,
    passed: results.filter(function(r){return r.status==='PASS';}).length,
    failed: results.filter(function(r){return r.status==='FAIL';}).length,
    warned: results.filter(function(r){return r.status==='WARN';}).length,
    runtimeErrors: (window.__errorLog||[]).length - pre,
    results: results,
    timestamp: new Date().toISOString()
  };
  console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  console.log('SMOKE TEST: ' + summary.passed + '/' + summary.total +
              ' passed, ' + summary.failed + ' failed, ' +
              summary.runtimeErrors + ' runtime errors');
  console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  return summary;
};

// ── Floating button + keyboard shortcut ──
function addButton(){
  if(document.getElementById('smoke-test-btn')) return;
  var b = document.createElement('button');
  b.id = 'smoke-test-btn';
  b.textContent = '🧪 Test';
  b.title = 'Run smoke test (Ctrl+Shift+T)';
  b.style.cssText = 'position:fixed;bottom:8px;left:8px;z-index:99999;'+
    'background:#3a4154;color:#dfe9ee;border:1px solid #5fcc7c;border-radius:4px;'+
    'padding:4px 10px;font-size:11px;cursor:pointer;opacity:.6;font-weight:700';
  b.onmouseenter = function(){b.style.opacity='1';};
  b.onmouseleave = function(){b.style.opacity='.6';};
  b.onclick = function(){
    var r = window.__smokeTest();
    var msg = 'Smoke test:\n' + r.passed + '/' + r.total + ' passed\n' +
              r.failed + ' failed, ' + r.runtimeErrors + ' runtime errors\n\n';
    if(r.failed > 0){
      msg += 'Failures:\n' + r.results.filter(function(x){return x.status==='FAIL';})
              .map(function(x){return '• '+x.name+': '+x.why;}).join('\n');
    } else {
      msg += '✓ All clear';
    }
    alert(msg);
  };
  document.body.appendChild(b);
}

