// Companion XP curve. Level 1..30. Cumulative XP needed to REACH level L:
//   xpToLevel(1) = 0;  xpToLevel(L) = round(50 * 1.18^(L-1) * (L-1))   ~roughly 50K at lv 30
window.companionXpToReach = function(L){
  if(L <= 1) return 0;
  var total = 0;
  for(var i=1; i<L; i++){
    total += Math.floor(50 * Math.pow(1.18, i-1) * i);
  }
  return total;
};
window.companionLevelFromXp = function(xp){
  for(var L=30; L>=1; L--){
    if(xp >= window.companionXpToReach(L)) return L;
  }
  return 1;
};

// State migration
function ensureCompanionState(){
  if(typeof G === 'undefined') return;
  if(!G.companions){
    G.companions = {
      ownedIds: ['fox'],          // start with fox
      xp: { fox: 0 },
      equipped: G.equipment && G.equipment.companion === 'fox_companion' ? 'fox' : null
    };
  }
  // Migrate any existing fox_companion equip state
  if(G.equipment && G.equipment.companion === 'fox_companion' && !G.companions.equipped){
    G.companions.equipped = 'fox';
  }
}

// Bonus helper — scaled by level
window.getCompanionBonus = function(){
  ensureCompanionState();
  var b = {strB:0, atkB:0, defB:0, crit:0, xpB:0, gatherSpeed:0, farmYield:0,
           cookSpeed:0, prayerXp:0, rareDrop:0, goldBonus:0, hpRegen:0};
  var eq = G.companions && G.companions.equipped;
  if(!eq) return b;
  var def = window.COMPANIONS[eq];
  if(!def) return b;
  var xp = (G.companions.xp && G.companions.xp[eq]) || 0;
  var lv = window.companionLevelFromXp(xp);
  var scale = 1 + (lv - 1) * 0.05; // +5% per level above 1; lv30 = +145% bonus magnitude
  Object.entries(def.bonus || {}).forEach(function(kv){
    b[kv[0]] = (b[kv[0]] || 0) + (kv[1] * scale);
  });
  return b;
};

// Hook into existing getBonus() if present
(function(){
  if(typeof window.getBonus !== 'function') return;
  var orig = window.getBonus;
  window.getBonus = function(key){
    var v = orig.apply(this, arguments) || 0;
    var cb = window.getCompanionBonus();
    if(cb && typeof cb[key] === 'number') v += cb[key];
    return v;
  };
})();

// Hook into getEquipmentStats() if it exists, so combat/character pages see companion stat bonuses
(function(){
  if(typeof window.getEquipmentStats !== 'function') return;
  var orig = window.getEquipmentStats;
  window.getEquipmentStats = function(){
    var s = orig.apply(this, arguments) || {};
    var cb = window.getCompanionBonus();
    ['strB','atkB','defB','rangeStrB','rangeAtkB','magicStrB','magicAtkB'].forEach(function(k){
      if(typeof cb[k] === 'number') s[k] = (s[k]||0) + cb[k];
    });
    if(typeof cb.crit === 'number') s.critB = (s.critB||0) + cb.crit;
    return s;
  };
})();

// Award XP to the equipped companion (capped to 50k cumulative)
window.awardCompanionXp = function(amount){
  ensureCompanionState();
  var eq = G.companions && G.companions.equipped;
  if(!eq) return;
  G.companions.xp[eq] = Math.min(50000, (G.companions.xp[eq]||0) + amount);
};

// Add a companion to the player's stable
window.unlockCompanion = function(id){
  ensureCompanionState();
  if(!window.COMPANIONS[id]) return false;
  if(G.companions.ownedIds.indexOf(id) >= 0) return false;
  G.companions.ownedIds.push(id);
  G.companions.xp[id] = 0;
  if(typeof notify === 'function') notify('Companion unlocked: '+window.COMPANIONS[id].n+' '+window.COMPANIONS[id].icon, 'loot');
  return true;
};

// Equip a companion (sync to G.equipment slot for legacy systems)
window.equipCompanion = function(id){
  ensureCompanionState();
  if(!G.companions.ownedIds.includes(id)){ if(typeof notify==='function') notify('You don\'t own that companion','kill'); return; }
  G.companions.equipped = id;
  // sync legacy equipment slot
  if(G.equipment) G.equipment.companion = id === 'fox' ? 'fox_companion' : id;
  if(typeof renderProfile==='function') renderProfile();
  if(typeof renderInvFancy==='function') renderInvFancy();
};

window.unequipCompanion = function(){
  ensureCompanionState();
  G.companions.equipped = null;
  if(G.equipment) G.equipment.companion = null;
  if(typeof renderProfile==='function') renderProfile();
  if(typeof renderInvFancy==='function') renderInvFancy();
};

