function renderStable(){
  if(typeof G==='undefined' || !G.companions) return;
  var body = document.getElementById('stable-body');
  if(!body) return;
  var sub = document.getElementById('stable-sub');
  if(sub) sub.textContent = G.companions.ownedIds.length+'/'+Object.keys(window.COMPANIONS).length+' companions owned';

  var html = '<div class="stable-grid">';
  Object.entries(window.COMPANIONS).forEach(function(kv){
    var id = kv[0], def = kv[1];
    var owned = G.companions.ownedIds.indexOf(id) >= 0;
    var equipped = G.companions.equipped === id;
    var xp = (G.companions.xp && G.companions.xp[id]) || 0;
    var lv = window.companionLevelFromXp(xp);
    var nextXp = window.companionXpToReach(lv+1);
    var thisLvXp = window.companionXpToReach(lv);
    var pct = nextXp > thisLvXp ? Math.min(100, ((xp - thisLvXp) / (nextXp - thisLvXp)) * 100) : 100;
    var bonuses = Object.entries(def.bonus||{}).map(function(b){
      var key = b[0], val = b[1];
      var label = ({strB:'STR',atkB:'ATK',defB:'DEF',crit:'Crit',xpB:'XP',gatherSpeed:'Gather',
                    farmYield:'Farm yield',cookSpeed:'Cook speed',rareDrop:'Rare drop',
                    goldBonus:'Gold',hpRegen:'HP/sec'})[key] || key;
      var v = (key === 'crit' || key === 'xpB' || key === 'gatherSpeed' || key === 'farmYield' ||
               key === 'cookSpeed' || key === 'rareDrop' || key === 'goldBonus')
              ? '+'+(val*100).toFixed(0)+'%'
              : '+'+val;
      return '<span><b>'+v+'</b> '+label+'</span>';
    }).join(' &nbsp;·&nbsp; ');

    var roleColor = ({combat:'#e88a8a', gather:'#7de6d4', artisan:'#f3d181', utility:'#d4a8e8', hybrid:'#9aa3b0'})[def.role] || '#9aa3b0';
    html += '<div class="stable-card '+(equipped?'equipped':'')+' '+(owned?'':'locked')+'">'
      + '<span class="sc-lvl">Lv '+lv+'</span>'
      + '<div class="sc-row"><span class="sc-icon">'+def.icon+'</span><div>'
        + '<div class="sc-name">'+def.n+'</div>'
        + '<div class="sc-role" style="color:'+roleColor+'">'+def.role+'</div>'
      + '</div></div>'
      + '<div class="sc-bonuses">'+bonuses+'</div>';
    if(owned){
      html += '<div class="sc-bar"><i style="width:'+pct.toFixed(1)+'%"></i></div>'
            + '<div style="font-size:10px;color:var(--ink-3)">'+xp.toLocaleString()+' / '+nextXp.toLocaleString()+' XP</div>';
      if(def.proc){
        html += '<div class="sc-bonuses" style="font-size:10px;font-style:italic">⚡ '+def.proc.label
              + ' ('+(def.proc.chance*100).toFixed(0)+'% on '+def.proc.trigger+')</div>';
      }
      html += '<button class="sc-equip" onclick="'+(equipped ? "window.unequipCompanion()" : "window.equipCompanion('"+id+"')")+'">'
            + (equipped ? 'Unequip' : 'Equip') + '</button>';
    } else {
      html += '<div class="sc-source">🔒 '+def.source+'</div>';
    }
    html += '</div>';
  });
  html += '</div>';
  body.innerHTML = html;
}

