(function(){
  /**
   * Quests system — promotes Daily Goals to a global pill strip, plus a full modal
   * with Daily/Weekly tabs, rewards, claim flow, and summary stats.
   *
   * Data sources:
   *   - Daily: existing getGoalsForToday() + DAILY_GOAL_POOL (+ rewards table here)
   *   - Weekly: WEEKLY_GOAL_POOL (defined here, similar shape)
   *   - State: G.dailyGoals.claimed{id:true}, G.weeklyGoals (mirror of dailyGoals)
   *
   * When the multi-character system arrives (#83), each character gets its own
   * dailyGoals/weeklyGoals slot. The data shape doesn't need to change.
   */

  // ── Reward attachments (extends DAILY_GOAL_POOL semantically without mutating data) ──
  var DAILY_REWARDS = {
    kill_any:    {gold: 200, xp:{combat:50}},
    kill_more:   {gold: 600, xp:{combat:200}, gems: 1},
    gather_logs: {gold: 250, xp:{woodcutting:100}},
    mine_ore:    {gold: 250, xp:{mining:100}},
    cook:        {gold: 200, xp:{cooking:80}},
    fish:        {gold: 250, xp:{fishing:100}},
    gold_500:    {gold: 0, xp:{}, item:'starter_bundle_token', items:{small_bones:5}},
    plant:       {gold: 200, xp:{farming:80}},
    level_up:    {gold: 500, xp:{}, gems: 1},
  };

  // Weekly pool — bigger targets, bigger rewards. Phase B will let players claim
  // these on the same flow.
  window.WEEKLY_GOAL_POOL = window.WEEKLY_GOAL_POOL || [
    {id:'wk_kills',    emoji:'⚔️', name:'Slay 100 monsters', target:100, source:'stats.kills',           reward:{gold:2500, gems:3, xp:{combat:1000}}},
    {id:'wk_gather',   emoji:'⛏️', name:'Gather 250 ores',  target:250, source:'collection.copper_ore', reward:{gold:2000, xp:{mining:500}}},
    {id:'wk_logs',     emoji:'🪵', name:'Cut 250 logs',     target:250, source:'collection.normal_log', reward:{gold:2000, xp:{woodcutting:500}}},
    {id:'wk_cook',     emoji:'🍳', name:'Cook 50 dishes',    target:50,  source:'stats.cooked',         reward:{gold:1500, xp:{cooking:400}}},
    {id:'wk_levels',   emoji:'📈', name:'Gain 5 skill levels', target:5, source:'stats.levelups',       reward:{gold:5000, gems:5}},
  ];
  function thisWeekKey(){
    var d = new Date();
    var ms = Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate());
    var weekIdx = Math.floor(ms / (7*86400000));
    return weekIdx;
  }
  window.getWeeklyGoals = function(){
    var key = thisWeekKey();
    if(!G.weeklyGoals || G.weeklyGoals.weekKey !== key){
      // Pick 3 deterministic weekly goals
      var seed = key;
      var picks = []; var used = {};
      for(var i = 0; i < 3 && i < WEEKLY_GOAL_POOL.length; i++){
        seed = (seed * 9301 + 49297) % 233280;
        var idx = Math.floor((seed/233280) * WEEKLY_GOAL_POOL.length);
        while(used[idx]) idx = (idx+1) % WEEKLY_GOAL_POOL.length;
        used[idx] = true; picks.push(WEEKLY_GOAL_POOL[idx]);
      }
      G.weeklyGoals = {weekKey: key, picks: picks.map(function(g){return g.id;}), startValues: {}, claimed:{}};
      picks.forEach(function(g){ G.weeklyGoals.startValues[g.id] = (typeof readSource === 'function') ? readSource(g.source) : 0; });
    }
    return G.weeklyGoals.picks.map(function(id){
      return WEEKLY_GOAL_POOL.find(function(p){return p.id===id;});
    }).filter(Boolean);
  };

  // ── Helpers to compute progress ──
  function getProgress(goal, isWeekly){
    if(typeof readSource !== 'function') return 0;
    var stateObj = isWeekly ? G.weeklyGoals : G.dailyGoals;
    var startVal = (stateObj && stateObj.startValues && stateObj.startValues[goal.id]) || 0;
    return Math.max(0, readSource(goal.source) - startVal);
  }
  function isClaimed(goal, isWeekly){
    var stateObj = isWeekly ? G.weeklyGoals : G.dailyGoals;
    return !!(stateObj && stateObj.claimed && stateObj.claimed[goal.id]);
  }
  function isComplete(goal, isWeekly){
    return getProgress(goal, isWeekly) >= goal.target;
  }
  function rewardFor(goalId, isWeekly){
    if(isWeekly){
      var def = WEEKLY_GOAL_POOL.find(function(p){return p.id===goalId;});
      return def && def.reward;
    }
    return DAILY_REWARDS[goalId] || {gold:100};
  }
  function rewardSummary(reward){
    if(!reward) return '—';
    var parts = [];
    if(reward.gold) parts.push(reward.gold+'g');
    if(reward.gems) parts.push(reward.gems+'💎');
    if(reward.xp){
      Object.entries(reward.xp).forEach(function(kv){
        parts.push(kv[1]+' '+kv[0]+' xp');
      });
    }
    if(reward.items){
      Object.entries(reward.items).forEach(function(kv){
        parts.push(kv[1]+'x '+kv[0]);
      });
    }
    return parts.join(' · ');
  }

  // ── Claim ──
  window.claimQuestReward = function(goalId, isWeekly){
    var goal = isWeekly
      ? WEEKLY_GOAL_POOL.find(function(p){return p.id===goalId;})
      : (typeof DAILY_GOAL_POOL !== 'undefined' ? DAILY_GOAL_POOL.find(function(p){return p.id===goalId;}) : null);
    if(!goal) return;
    if(!isComplete(goal, isWeekly)) return;
    if(isClaimed(goal, isWeekly)) return;
    var reward = rewardFor(goalId, isWeekly);
    if(reward){
      if(reward.gold && typeof G.gold === 'number') G.gold += reward.gold;
      if(reward.gems && typeof G.gems === 'number') G.gems += reward.gems;
      if(reward.xp){
        Object.entries(reward.xp).forEach(function(kv){
          if(typeof window.addXp === 'function') window.addXp(kv[0], kv[1]);
        });
      }
      if(reward.items){
        Object.entries(reward.items).forEach(function(kv){
          if(typeof window.addItem === 'function') window.addItem(kv[0], kv[1]);
        });
      }
    }
    var stateObj = isWeekly ? G.weeklyGoals : G.dailyGoals;
    if(stateObj){
      stateObj.claimed = stateObj.claimed || {};
      stateObj.claimed[goalId] = true;
    }
    if(typeof window.notify === 'function') notify('Reward claimed: '+rewardSummary(reward), 'loot');
    if(typeof window.updateTopbar === 'function') window.updateTopbar();
    if(window.HearthriseEvents) window.HearthriseEvents.emit('questClaim', {goalId, isWeekly, reward});
    renderModal();
    renderStrip();
  };

  // ── Strip render (compact pills along top border) ──
  function ensureStrip(){
    var strip = document.getElementById('global-quests-strip');
    if(strip) return strip;
    var main = document.querySelector('main.main') || document.querySelector('main');
    if(!main) return null;
    strip = document.createElement('div');
    strip.id = 'global-quests-strip';
    strip.className = 'global-quests-strip';
    strip.innerHTML = '<span class="gq-label">🎯 Quests</span><div class="gq-list"></div><span class="gq-meta" id="gq-reset"></span><span class="gq-open-hint">Click to open ▸</span>';
    strip.addEventListener('click', openQuestsModal);
    var topbar = main.querySelector('.topbar');
    var activity = main.querySelector('.activity-bar, [class*=activity-bar]');
    if(topbar && topbar.nextSibling) main.insertBefore(strip, topbar.nextSibling);
    else if(activity) main.insertBefore(strip, activity);
    else main.insertBefore(strip, main.firstChild);
    return strip;
  }
  function renderStrip(){
    var strip = ensureStrip();
    if(!strip) return;
    var list = strip.querySelector('.gq-list');
    var meta = strip.querySelector('#gq-reset');
    var goals = (typeof window.getGoalsForToday === 'function') ? window.getGoalsForToday() : [];
    if(!goals.length){
      if(list) list.innerHTML = '<span style="color:var(--ink-3);font-style:italic;font-size:11px">No active quests.</span>';
      if(meta) meta.textContent = '';
      return;
    }
    list.innerHTML = goals.map(function(g){
      var prog = getProgress(g, false);
      var done = prog >= g.target;
      var claimed = isClaimed(g, false);
      var prefix = claimed ? '✓ ' : (done ? '🎁 ' : '');
      return '<span class="gq-quest '+(done?'done':'')+'">'
        +'<span class="gq-icon">'+(g.emoji||'🎯')+'</span>'
        +'<span class="gq-name">'+prefix+g.name+'</span>'
        +'<span class="gq-prog">'+Math.min(prog,g.target)+' / '+g.target+'</span>'
      +'</span>';
    }).join('');
    if(meta) meta.textContent = (typeof window.hoursTillUTCMidnight === 'function') ? ('Resets in '+window.hoursTillUTCMidnight()+'h') : '';
  }

  // ── Modal ──
  var currentTab = 'daily';
  function openQuestsModal(){
    closeQuestsModal();
    var overlay = document.createElement('div');
    overlay.className = 'qm-overlay';
    overlay.id = 'quests-modal-overlay';
    overlay.innerHTML =
      '<div class="qm-modal" style="position:relative">'
      + '<button class="qm-close" aria-label="Close">✕</button>'
      + '<div class="qm-tabs">'
        + '<button class="qm-tab '+(currentTab==='daily'?'active':'')+'" data-tab="daily">Daily Quests <span class="qm-tab-count" data-count="daily"></span></button>'
        + '<button class="qm-tab '+(currentTab==='weekly'?'active':'')+'" data-tab="weekly">Weekly Quests <span class="qm-tab-count" data-count="weekly"></span></button>'
      + '</div>'
      + '<div class="qm-body">'
        + '<div class="qm-list" id="qm-list"></div>'
        + '<aside class="qm-aside">'
          + '<div><h4>📊 Quest Info</h4>'
          + '<div class="qm-summary" id="qm-summary"></div></div>'
          + '<div><h4 style="font-size:11px">About Quests</h4>'
          + '<p class="qm-info-text">Daily quests refresh every 24 hours at UTC midnight. Weekly quests refresh every Monday. Complete them to claim gold, XP, gems, and rare items.</p></div>'
          + '<div class="qm-reset" id="qm-reset"></div>'
        + '</aside>'
      + '</div></div>';
    overlay.querySelector('.qm-close').addEventListener('click', closeQuestsModal);
    overlay.addEventListener('click', function(e){ if(e.target === overlay) closeQuestsModal(); });
    overlay.querySelectorAll('.qm-tab').forEach(function(b){
      b.addEventListener('click', function(){ currentTab = b.dataset.tab; renderModal(); });
    });
    // Delegated claim handler — buttons render via innerHTML on each renderModal()
    overlay.addEventListener('click', function(e){
      var btn = e.target.closest && e.target.closest('.qm-q-claim');
      if(!btn) return;
      var qid = btn.dataset.qid;
      var isWeekly = btn.dataset.weekly === '1';
      if(qid && typeof window.claimQuestReward === 'function') window.claimQuestReward(qid, isWeekly);
    });
    document.body.appendChild(overlay);
    renderModal();
  }
  function closeQuestsModal(){
    var existing = document.getElementById('quests-modal-overlay');
    if(existing) existing.remove();
  }
  window.openQuestsModal = openQuestsModal;
  window.closeQuestsModal = closeQuestsModal;

  function renderModal(){
    var overlay = document.getElementById('quests-modal-overlay');
    if(!overlay) return;
    // Refresh tab states + counts
    overlay.querySelectorAll('.qm-tab').forEach(function(b){
      b.classList.toggle('active', b.dataset.tab === currentTab);
    });
    var dailyGoals = (typeof window.getGoalsForToday === 'function') ? window.getGoalsForToday() : [];
    var weeklyGoals = (typeof window.getWeeklyGoals === 'function') ? window.getWeeklyGoals() : [];
    var dCount = dailyGoals.filter(function(g){return isComplete(g,false) && !isClaimed(g,false);}).length;
    var wCount = weeklyGoals.filter(function(g){return isComplete(g,true) && !isClaimed(g,true);}).length;
    var dailyCountEl = overlay.querySelector('[data-count="daily"]');
    var weeklyCountEl = overlay.querySelector('[data-count="weekly"]');
    if(dailyCountEl) dailyCountEl.textContent = dCount > 0 ? dCount : '';
    if(weeklyCountEl) weeklyCountEl.textContent = wCount > 0 ? wCount : '';

    // Render list
    var goals = currentTab === 'weekly' ? weeklyGoals : dailyGoals;
    var isWeekly = currentTab === 'weekly';
    var list = overlay.querySelector('#qm-list');
    if(!goals.length){
      list.innerHTML = '<div style="color:var(--ink-3);font-style:italic;text-align:center;padding:40px">No '+(isWeekly?'weekly':'daily')+' quests.</div>';
    } else {
      list.innerHTML = goals.map(function(g){
        var prog = getProgress(g, isWeekly);
        var done = prog >= g.target;
        var claimed = isClaimed(g, isWeekly);
        var pct = Math.min(100, (prog/g.target)*100);
        var reward = rewardFor(g.id, isWeekly);
        var rewardHtml = '<div class="qm-q-reward"><div class="qm-r-label">Reward</div><div class="qm-r-val">'+rewardSummary(reward)+'</div></div>';
        var claimBtn = '';
        if(claimed) claimBtn = '<span class="qm-q-claimed">✓ Claimed</span>';
        else if(done) claimBtn = '<button class="qm-q-claim" data-qid="'+g.id+'" data-weekly="'+(isWeekly?1:0)+'">Claim</button>';
        return '<div class="qm-quest '+(done&&!claimed?'claimable':done?'done':'')+'">'
          +'<div class="qm-q-icon">'+(g.emoji||'🎯')+'</div>'
          +'<div class="qm-q-info">'
            +'<div class="qm-q-name">'+g.name+'</div>'
            +'<div class="qm-q-desc">'+(g.desc||'Complete this objective to claim your reward.')+'</div>'
            +'<div class="qm-q-progbar"><i style="width:'+pct.toFixed(1)+'%"></i></div>'
            +'<div class="qm-q-progtext">'+Math.min(prog,g.target)+' / '+g.target+' ('+pct.toFixed(0)+'%)</div>'
          +'</div>'
          +rewardHtml
          +claimBtn
        +'</div>';
      }).join('');
    }

    // Summary aside
    var totalQ = goals.length;
    var inProgress = goals.filter(function(g){return getProgress(g,isWeekly) > 0 && !isComplete(g,isWeekly);}).length;
    var completed = goals.filter(function(g){return isComplete(g,isWeekly);}).length;
    var claimable = goals.filter(function(g){return isComplete(g,isWeekly) && !isClaimed(g,isWeekly);}).length;
    var summary = overlay.querySelector('#qm-summary');
    if(summary){
      summary.innerHTML =
        '<div class="qm-sum-row"><span>Total quests</span><b>'+totalQ+'</b></div>'
        +'<div class="qm-sum-row"><span>In progress</span><b>'+inProgress+'</b></div>'
        +'<div class="qm-sum-row claimable"><span>Claimable</span><b>'+claimable+'</b></div>'
        +'<div class="qm-sum-row"><span>Completed</span><b>'+completed+'</b></div>';
    }
    var reset = overlay.querySelector('#qm-reset');
    if(reset){
      if(isWeekly){
        var d = new Date();
        var dayOfWeek = d.getUTCDay() || 7;
        var daysUntilMonday = (7 - dayOfWeek + 1) % 7 || 7;
        reset.textContent = 'Resets in '+daysUntilMonday+'d (Monday UTC)';
      } else {
        var hrs = (typeof window.hoursTillUTCMidnight === 'function') ? window.hoursTillUTCMidnight() : '?';
        reset.textContent = 'Resets in '+hrs+'h';
      }
    }
  }

  // ── Tick + boot ──
  setInterval(function(){ renderStrip(); var m=document.getElementById('quests-modal-overlay'); if(m) renderModal(); }, 2000);
  if(document.readyState === 'loading'){
    document.addEventListener('DOMContentLoaded', function(){ setTimeout(renderStrip, 600); });
  } else {
    setTimeout(renderStrip, 600);
  }
  if(window.HearthriseEvents && typeof window.HearthriseEvents.on === 'function'){
    window.HearthriseEvents.on('*', function(){ renderStrip(); var m=document.getElementById('quests-modal-overlay'); if(m) renderModal(); });
  }
  // Esc to close
  document.addEventListener('keydown', function(e){
    if(e.key === 'Escape') closeQuestsModal();
  });
  console.log('[Quests modal] ready — Daily + Weekly tabs with rewards & claim flow');
})();

// ===== block 41: script-41 =====
(function(){
  window.openHearthHallStore = function(){
    if(typeof showTab === 'function') showTab('shop');
    setTimeout(function(){
      var btn = document.querySelector('button[onclick*="hearth_hall_premium"]');
      if(btn){
        btn.scrollIntoView({behavior:'smooth', block:'center'});
        var card = btn.closest('.shop-card, .shop-row, .iap-card') || btn.parentElement;
        if(card){
          card.style.transition = 'box-shadow .3s';
          card.style.boxShadow = '0 0 0 3px var(--gold-2), 0 0 30px rgba(243,209,129,.6)';
          setTimeout(function(){card.style.boxShadow = '';}, 2000);
        }
      } else if(typeof notify === 'function') notify('Hearth Hall Premium is in the Store','info');
    }, 100);
  };
})();
